-- ============================================================================
-- Rebalansuje odpowiedzi w pytaniach Prawda/Fałsz (wcześniej ~85% odpowiedzi to
-- „Prawda"). Część zdań przepisano tak, by były faktycznie fałszywe, a pole
-- explain wyjaśnia błąd — docelowo ~50/50. Wygenerowane z app/content/topics.ts.
-- Tylko wiki + questions — pozostałe pola tematów bez zmian. Idempotentne.
-- ============================================================================

update public.topics as t set
  wiki = x.wiki,
  questions = x.questions
from jsonb_to_recordset($awfjson$[{"id":"funkcje-czasu-wolnego","wiki":[{"body":"Czas wolny pełni szereg funkcji, które razem wspierają regenerację, rozwój i relacje człowieka. Dobrze zorganizowany czas wolny ma także silny potencjał wychowawczy."},{"heading":"Funkcje czasu wolnego","bullets":["Regeneracyjna — odpoczynek fizyczny i psychiczny po wysiłku, stresie i obowiązkach.","Rekreacyjna — rozrywka, relaks i miłe spędzanie czasu.","Rozwojowa — poszerzanie wiedzy, rozwijanie zainteresowań, nowe umiejętności (kursy, książki, warsztaty).","Kompensacyjna — wyrównuje braki z innych sfer życia (aktywność, kontakt społeczny, kreatywność).","Kreacyjna — twórcza realizacja przez sztukę, muzykę, pisanie, rękodzieło.","Katartyczna — oczyszcza emocje, rozładowuje stres i napięcie.","Społeczna — budowanie relacji, współpraca i integracja z grupą."]},{"heading":"Potencjał wychowawczy","body":"Polega na wykorzystaniu czasu wolnego do wspierania rozwoju osobistego, społecznego i moralnego dzieci i młodzieży — to nie tylko odpoczynek, ale i szansa na wychowanie.","bullets":["Rozwija zainteresowania i pasje — dziecko odkrywa, co lubi i w czym jest dobre.","Buduje relacje społeczne oraz więzi rodzinne i rówieśnicze.","Kształtuje wartości: empatię, współpracę, szacunek, zasady fair play.","Chroni przed zachowaniami ryzykownymi — zorganizowany czas wolny ogranicza nudę i negatywne wpływy."]}],"questions":[{"type":"abcd","q":"Która funkcja czasu wolnego pełni rolę oczyszczającą emocje i rozładowującą napięcie?","options":["Kompensacyjna","Regeneracyjna","Kreacyjna","Katartyczna"],"correct":3,"explain":"Funkcja katartyczna oczyszcza emocje oraz rozładowuje stres i napięcie."},{"type":"abcd","q":"Funkcja kompensacyjna czasu wolnego polega na:","options":["wyrównywaniu braków i niedostatków z innych sfer życia","twórczej realizacji przez sztukę i rękodzieło","odpoczynku po wysiłku fizycznym","budowaniu relacji w grupie"],"correct":0,"explain":"Funkcja kompensacyjna uzupełnia braki z innych stref życia (np. aktywność fizyczna, kontakt społeczny)."},{"type":"tf","q":"Dobrze zorganizowany czas wolny zmniejsza podatność na nudę i chroni przed zachowaniami ryzykownymi.","correct":true,"explain":"To jeden z elementów potencjału wychowawczego czasu wolnego."},{"type":"flash","front":"Wymień 7 funkcji czasu wolnego.","back":"Regeneracyjna, rekreacyjna, rozwojowa, kompensacyjna, kreacyjna, katartyczna, społeczna."}]},{"id":"koncepcje-motywacyjne","wiki":[{"body":"Motywacja to wewnętrzny stan pobudzający jednostkę do działania; kieruje zachowaniem oraz wpływa na to, jak długo i jak intensywnie coś wykonujemy. Powstaje z różnych potrzeb i może mieć charakter rodzinny, poznawczy, historyczny, zdrowotny, społeczny, estetyczny lub duchowy."},{"heading":"Piramida potrzeb Maslowa","bullets":["Fizjologiczne — odpoczynek, sen, jedzenie (wakacje zaspokajają te potrzeby).","Bezpieczeństwa — podróże w spokojne miejsca, oderwanie od stresu.","Przynależności — wyjazdy z rodziną i przyjaciółmi, budowanie relacji.","Uznania — zdobywanie i dzielenie się nowymi doświadczeniami.","Samorealizacji — poznawanie świata, rozwój osobisty, duchowy, edukacyjny."]},{"heading":"Teoria autodeterminacji (Ryan i Deci)","body":"Wskazuje 3 kluczowe potrzeby psychologiczne: autonomię (decydowanie o sobie), kompetencję (poczucie sprawności) oraz relacje z innymi. Rekreacja pomaga je zaspokoić, dając poczucie spełnienia."},{"heading":"Motywacja wewnętrzna i zewnętrzna","bullets":["Wewnętrzna — wynika z osobistych potrzeb i przyjemności (bieganie dla satysfakcji, podróże dla poznawania świata).","Zewnętrzna — związana z nagrodą lub uniknięciem kary (udział w zawodach dla medalu)."]}],"questions":[{"type":"abcd","q":"Które trzy potrzeby psychologiczne wskazuje teoria autodeterminacji Ryana i Deciego?","options":["Fizjologiczne, bezpieczeństwa, uznania","Regeneracja, kompensacja, kreacja","Poznawcza, estetyczna, duchowa","Autonomia, kompetencja, relacje z innymi"],"correct":3,"explain":"Teoria autodeterminacji opiera się na autonomii, kompetencji i relacjach z innymi."},{"type":"abcd","q":"Bieganie dla własnej satysfakcji to przykład motywacji:","options":["zewnętrznej","wewnętrznej","kontrolnej","formalnej"],"correct":1,"explain":"Motywacja wewnętrzna wynika z osobistych potrzeb i przyjemności z działania."},{"type":"tf","q":"W piramidzie Maslowa potrzeby fizjologiczne znajdują się na najwyższym poziomie.","correct":false,"explain":"Na szczycie piramidy jest samorealizacja, a potrzeby fizjologiczne stanowią jej podstawę (najniższy poziom)."},{"type":"flash","front":"Czym różni się motywacja wewnętrzna od zewnętrznej?","back":"Wewnętrzna wynika z osobistych potrzeb i przyjemności; zewnętrzna z oczekiwania nagrody lub uniknięcia kary."}]},{"id":"witaminy-antyoksydacyjne","wiki":[{"body":"Witaminy antyoksydacyjne pomagają chronić komórki przed uszkodzeniem przez wolne rodniki — cząsteczki, które mogą sprzyjać chorobom (nowotwory, choroby serca i mózgu). Organizm broni się sam, a witaminy dodatkowo go wspierają."},{"heading":"Witamina A (retinol, beta-karoten)","body":"Źródła: marchew, dynia, bataty, szpinak, jarmuż.","bullets":["Neutralizuje wolne rodniki, chroni błony komórkowe.","Wspiera zdrowie skóry i błon śluzowych.","Niezbędna do prawidłowego widzenia i odporności."]},{"heading":"Witamina C (kwas askorbinowy)","body":"Źródła: cytrusy, papryka, pietruszka, truskawki, kiwi.","bullets":["Silny antyoksydant działający w środowisku wodnym.","Wspomaga syntezę kolagenu i gojenie ran.","Zwiększa przyswajanie żelaza niehemowego, wzmacnia odporność."]},{"heading":"Witamina E (tokoferole)","body":"Źródła: oleje roślinne, orzechy, nasiona, zielone warzywa.","bullets":["Chroni błony komórkowe przed uszkodzeniami oksydacyjnymi.","Wspomaga układ krwionośny, zmniejsza ryzyko miażdżycy.","Poprawia stan skóry i wspiera układ nerwowy."]},{"heading":"Koenzym Q10","body":"Nie jest witaminą, ale ma silne działanie antyoksydacyjne. Źródła: ryby, mięso, orzechy, oleje roślinne. Bierze udział w produkcji energii w mitochondriach."}],"questions":[{"type":"abcd","q":"Która witamina antyoksydacyjna działa głównie w środowisku wodnym organizmu?","options":["Witamina A","Koenzym Q10","Witamina E","Witamina C"],"correct":3,"explain":"Witamina C jest silnym antyoksydantem neutralizującym wolne rodniki w środowisku wodnym."},{"type":"abcd","q":"Dobrym źródłem witaminy A (beta-karotenu) jest:","options":["cytryna","marchew","olej słonecznikowy","ryba"],"correct":1,"explain":"Witamina A / beta-karoten występuje m.in. w marchwi, dyni, batatach i jarmużu."},{"type":"tf","q":"Koenzym Q10 jest witaminą antyoksydacyjną.","correct":false,"explain":"Koenzym Q10 nie jest witaminą, choć ma silne działanie antyoksydacyjne i uczestniczy w produkcji energii w mitochondriach."},{"type":"flash","front":"Czym są wolne rodniki i dlaczego są groźne?","back":"To cząsteczki uszkadzające komórki; mogą sprzyjać chorobom (nowotwory, choroby serca i mózgu). Witaminy antyoksydacyjne pomagają je neutralizować."}]},{"id":"blonnik-pokarmowy","wiki":[{"body":"Błonnik pokarmowy to część roślin, która nie ulega strawieniu i wchłonięciu w przewodzie pokarmowym. Choć nie dostarcza energii, usprawnia pracę jelit, wspiera odchudzanie i pomaga regulować poziom cukru we krwi."},{"heading":"Błonnik rozpuszczalny","body":"W kontakcie z wodą pęcznieje i tworzy żel. Spowalnia wchłanianie węglowodanów (stabilizuje glukozę) i obniża poziom cholesterolu.","bullets":["Źródła: płatki owsiane, rośliny strączkowe, siemię lniane, jabłka, cytrusy."]},{"heading":"Błonnik nierozpuszczalny","body":"Działa jak „szczotka” w jelitach — zwiększa objętość stolca i przyspiesza pasaż jelitowy, zapobiegając zaparciom.","bullets":["Źródła: produkty pełnoziarniste, otręby, orzechy, skórki warzyw i owoców."]},{"heading":"Zalecenia i nadmiar","bullets":["Dorośli: 25–40 g błonnika dziennie.","Nadmiar może powodować biegunkę i zaburzać wchłanianie składników mineralnych (żelaza, wapnia, cynku)."]}],"questions":[{"type":"abcd","q":"Który rodzaj błonnika w kontakcie z wodą tworzy żel i obniża poziom cholesterolu?","options":["Nierozpuszczalny","Żaden","Oba tak samo","Rozpuszczalny"],"correct":3,"explain":"Błonnik rozpuszczalny pęcznieje, tworzy żel, stabilizuje glukozę i obniża cholesterol."},{"type":"abcd","q":"Jakie jest zalecane dzienne spożycie błonnika u dorosłych?","options":["5–10 g","25–40 g","10–20 g","50–70 g"],"correct":1,"explain":"Zalecenie dla dorosłych to 25–40 g błonnika dziennie."},{"type":"tf","q":"Błonnik rozpuszczalny przyspiesza pasaż jelitowy i zapobiega zaparciom.","correct":false,"explain":"Pasaż przyspiesza błonnik nierozpuszczalny (działa jak „szczotka”); rozpuszczalny pęcznieje, spowalnia trawienie i obniża cholesterol."},{"type":"flash","front":"Jakie są skutki nadmiaru błonnika?","back":"Biegunka oraz zaburzenia wchłaniania składników mineralnych (żelaza, wapnia, cynku)."}]},{"id":"przystosowania-do-wysilku","wiki":[{"body":"Adaptacje organizmu zależą od rodzaju, intensywności, czasu trwania i częstotliwości treningu. Regularny wysiłek prowadzi do zmian czynnościowych zwiększających wydolność i sprawność."},{"heading":"Trening wytrzymałościowy (bieganie, kolarstwo)","bullets":["Wzrost pojemności minutowej serca i objętości wyrzutowej.","Więcej i wydolniejsze mitochondria, wzrost VO₂ max.","Lepsze ukrwienie tkanek, obniżenie tętna spoczynkowego."]},{"heading":"Trening siłowy (ciężary, masa ciała)","bullets":["Hipertrofia mięśni — wzrost przekroju poprzecznego włókien.","Wzrost siły i gęstości mięśniowej oraz gęstości mineralnej kości.","Lepsza rekrutacja jednostek motorycznych i kontrola mięśni."]},{"heading":"Trening gibkości i równowagi (joga, rozciąganie)","bullets":["Większy zakres ruchu w stawach, mniejsze ryzyko kontuzji.","Relaks mięśni, lepsza koordynacja i równowaga."]},{"heading":"Niska intensywność oraz trening interwałowy","bullets":["Niska intensywność: wzrost wydolności tlenowej, obniżenie kortyzolu, kontrola masy ciała.","Interwały / sporty zespołowe: szybka adaptacja układu krążenia do zmiennego obciążenia, poprawa systemu tlenowego i beztlenowego."]}],"questions":[{"type":"abcd","q":"Hipertrofia mięśni jest charakterystyczną adaptacją dla treningu:","options":["wytrzymałościowego","gibkościowego","siłowego","o niskiej intensywności"],"correct":2,"explain":"Hipertrofia (wzrost przekroju włókien) to typowa adaptacja do treningu siłowego."},{"type":"abcd","q":"Wzrost liczby i wydolności mitochondriów oraz VO₂ max to efekt treningu:","options":["siłowego","oporowego","gibkościowego","wytrzymałościowego"],"correct":3,"explain":"Adaptacje tlenowe (mitochondria, VO₂ max) są typowe dla treningu wytrzymałościowego."},{"type":"tf","q":"Regularny trening wytrzymałościowy obniża tętno spoczynkowe.","correct":true,"explain":"Serce pracuje efektywniej, pompując więcej krwi przy każdym skurczu, więc tętno spoczynkowe spada."},{"type":"flash","front":"Wymień trzy systemy energetyczne pracującego mięśnia.","back":"System fosfagenowy (ATP), glikoliza beztlenowa (mleczan) i metabolizm tlenowy (mitochondria)."}]},{"id":"style-kierowania","wiki":[{"body":"Styl kierowania to sposób, w jaki kierownik zarządza zespołem: jak podejmuje decyzje, komunikuje się i wpływa na pracę. Wyróżnia się trzy główne style."},{"heading":"Styl autokratyczny","body":"Kierownik sam podejmuje wszystkie decyzje i ma pełną kontrolę. Sprawdza się przy dużej wiedzy kierownika i konieczności szybkich decyzji, ale z czasem obniża zaangażowanie i motywację pracowników."},{"heading":"Styl demokratyczny","body":"Kierownik konsultuje decyzje z pracownikami, którzy mogą wyrażać opinie. Działa dobrze przy kompetentnym i zaangażowanym zespole, ale podejmowanie decyzji bywa wolniejsze."},{"heading":"Styl liberalny","body":"Kierownik daje dużą swobodę — pracownicy sami decydują i wykonują zadania. Dobre przy kompetentnym, zmotywowanym zespole, ale może prowadzić do chaosu i braku kontroli. W praktyce kierownicy łączą style zależnie od sytuacji."}],"questions":[{"type":"abcd","q":"Który styl kierowania zakłada konsultowanie decyzji z pracownikami?","options":["Autokratyczny","Liberalny","Demokratyczny","Dyrektywny"],"correct":2,"explain":"W stylu demokratycznym kierownik konsultuje się z zespołem przed podjęciem decyzji."},{"type":"abcd","q":"Główną wadą stylu liberalnego może być:","options":["spadek motywacji wynikający z nadmiernej kontroli","chaos i brak kontroli","zbyt wolne podejmowanie decyzji przez konsultacje","traktowanie pracowników jak narzędzia"],"correct":1,"explain":"Duża swoboda w stylu liberalnym może z czasem prowadzić do chaosu i braku kontroli."},{"type":"tf","q":"Styl autokratyczny może być skuteczny, gdy decyzje muszą być podejmowane szybko.","correct":true,"explain":"Sprawdza się, gdy kierownik ma dużą wiedzę i potrzebne są szybkie decyzje."},{"type":"flash","front":"Wymień trzy główne style kierowania.","back":"Autokratyczny, demokratyczny i liberalny."}]},{"id":"produkt-turystyczny","wiki":[{"body":"Produkt turystyczny to zestaw dóbr i usług zaspokajających potrzeby turysty związane z podróżą i pobytem. Z perspektywy przedsiębiorstwa to zestaw usług i dóbr do sprzedaży; z perspektywy turysty — zestaw przeżyć, doświadczeń i korzyści."},{"heading":"Elementy materialne","bullets":["Infrastruktura turystyczna.","Baza noclegowa (hotele, pensjonaty).","Gastronomia (restauracje, bary).","Transport (loty, pociągi, autobusy), sprzęt, pamiątki."]},{"heading":"Elementy niematerialne","bullets":["Usługi przewodnickie i informacyjne.","Przeżycia emocjonalne i duchowe.","Wizerunek miejsca, atmosfera, klimat i pogoda.","Nowe kontakty i relacje społeczne."]},{"heading":"Rodzaje produktów","bullets":["Produkty proste — pojedyncze dobra/usługi (bilet, nocleg, przewodnik).","Produkty złożone (pakiety) — kombinacje usług i atrakcji (imprezy turystyczne)."]}],"questions":[{"type":"abcd","q":"Z perspektywy turysty (konsumenta) produkt turystyczny to przede wszystkim:","options":["zestaw przeżyć, doświadczeń i korzyści","zestaw usług i dóbr oferowanych do sprzedaży","wyłącznie baza noclegowa","tylko transport i gastronomia"],"correct":0,"explain":"Dla turysty produkt to zestaw przeżyć, doświadczeń i korzyści; perspektywa firmy to zestaw usług/dóbr do sprzedaży."},{"type":"abcd","q":"Który z elementów jest niematerialnym składnikiem produktu turystycznego?","options":["Baza noclegowa","Transport","Atmosfera i wizerunek miejsca","Sprzęt turystyczny"],"correct":2,"explain":"Elementy niematerialne to m.in. atmosfera, wizerunek miejsca, przeżycia i relacje społeczne."},{"type":"tf","q":"Impreza turystyczna (pakiet) jest przykładem złożonego produktu turystycznego.","correct":true,"explain":"Produkty złożone to kombinacje usług i atrakcji, np. imprezy turystyczne."},{"type":"flash","front":"Podaj dwie definicje produktu turystycznego (firma vs turysta).","back":"Firma: zestaw usług i dóbr oferowanych do sprzedaży. Turysta: zestaw przeżyć, doświadczeń i korzyści."}]},{"id":"formy-ochrony-przyrody","wiki":[{"heading":"Główne formy ochrony","bullets":["Parki narodowe — najwyższa forma ochrony; duże obszary, surowe zakazy (np. Białowieski, Tatrzański).","Parki krajobrazowe — chronią krajobraz i przyrodę z mniejszymi ograniczeniami; dopuszczalna działalność gospodarcza nieszkodliwa dla środowiska.","Rezerwaty przyrody — mniejsze obszary; ścisłe (zakaz ingerencji) lub częściowe (ograniczone działania ochronne).","Natura 2000 — sieć europejskich terenów chroniących zagrożone gatunki i siedliska.","Pomnik przyrody — pojedyncze obiekty (drzewa, głazy, jaskinie), np. Dąb Bartek."]},{"heading":"Pozostałe formy","bullets":["Użytki ekologiczne — niewielkie cenne tereny (oczka wodne, bagna, torfowiska).","Zespoły przyrodniczo-krajobrazowe — obszary cenne krajobrazowo i kulturowo.","Stanowiska dokumentacyjne — miejsca ważne geologicznie.","Ochrona gatunkowa — roślin, zwierząt i grzybów.","UNESCO — lista światowego dziedzictwa (np. Wieliczka, stare miasto w Krakowie)."]}],"questions":[{"type":"abcd","q":"Która forma ochrony przyrody w Polsce jest uznawana za najwyższą?","options":["Park krajobrazowy","Pomnik przyrody","Użytek ekologiczny","Park narodowy"],"correct":3,"explain":"Park narodowy to najwyższa forma ochrony — duże obszary i surowe zakazy."},{"type":"abcd","q":"Dąb Bartek to przykład:","options":["parku narodowego","rezerwatu ścisłego","pomnika przyrody","użytku ekologicznego"],"correct":2,"explain":"Pojedyncze obiekty przyrodnicze (drzewa, głazy) to pomniki przyrody — np. Dąb Bartek."},{"type":"tf","q":"Natura 2000 to sieć europejskich terenów chroniących zagrożone gatunki i siedliska.","correct":true,"explain":"Natura 2000 to europejska sieć obszarów chroniących zagrożone gatunki i siedliska."},{"type":"flash","front":"Czym różni się rezerwat ścisły od częściowego?","back":"Ścisły — całkowity zakaz ingerencji człowieka; częściowy — możliwe ograniczone działania ochronne."}]},{"id":"check-in-check-out","wiki":[{"heading":"Check-in (zameldowanie)","body":"Proces rejestracji gościa w hotelu.","bullets":["Powitanie gościa — uprzejmie i profesjonalnie.","Weryfikacja rezerwacji w systemie (imię, nazwisko, data).","Prośba o dokument tożsamości (paszport / dowód).","Wypełnienie karty rejestracyjnej.","Autoryzacja płatności — depozyt lub preautoryzacja karty.","Przekazanie klucza/karty, informacja o numerze pokoju i godzinach wymeldowania.","Dodatkowe informacje (śniadanie, wifi, siłownia) i ewentualna pomoc bagażowa."]},{"heading":"Check-out (wymeldowanie)","body":"Proces zakończenia pobytu i rozliczenia gościa.","bullets":["Sprawdzenie tożsamości gościa (nazwisko / numer pokoju).","Weryfikacja opłat — czy usługi dodatkowe (minibar, restauracja) doliczono.","Rozliczenie płatności (gotówka, karta, inna metoda).","Wystawienie faktury/paragonu na życzenie gościa.","Zwrot depozytu i klucza/karty do pokoju.","Zapytanie o opinię oraz uprzejme pożegnanie i zaproszenie ponownie."]}],"questions":[{"type":"abcd","q":"Który krok należy do procedury check-in?","options":["Autoryzacja płatności / preautoryzacja karty","Zwrot depozytu","Wystawienie faktury końcowej","Zwrot klucza do pokoju"],"correct":0,"explain":"Autoryzacja płatności (depozyt lub preautoryzacja karty) to element zameldowania (check-in)."},{"type":"tf","q":"Weryfikacja, czy usługi z minibaru zostały doliczone do rachunku, należy do check-in.","correct":false,"explain":"To krok wymeldowania (check-out), a nie zameldowania — przy check-out rozlicza się opłaty za usługi dodatkowe."},{"type":"flash","front":"Wymień pierwsze trzy kroki procedury check-in.","back":"Powitanie gościa, weryfikacja rezerwacji, prośba o dokument tożsamości."}]},{"id":"obiekty-hotelarskie","wiki":[{"heading":"Obiekty kategoryzowane","bullets":["Hotel — min. 10 pokoi, szeroki zakres usług (nocleg, wyżywienie, sprzątanie).","Motel — przy trasach, parking i udogodnienia dla zmotoryzowanych, min. 10 pokoi.","Pensjonat — nocleg i pełne wyżywienie, mniejszy zakres usług, min. 7 pokoi.","Dom wycieczkowy, schronisko młodzieżowe, schronisko górskie, pola namiotowe/kempingi."]},{"heading":"Obiekty nieskategoryzowane","body":"Nie muszą mieć gwiazdek, ale muszą spełniać wymagania sanitarne i techniczne.","bullets":["Pola biwakowe, kwatery prywatne.","Ośrodki wczasowe/wypoczynkowe/szkoleniowe, agroturystyka."]},{"heading":"System gwiazdek (1–5)","bullets":["Hotele, motele, pensjonaty: gwiazdki 1–5; campingi 1–4.","1* minimalne wyposażenie; 3* własna łazienka, TV, gastronomia; 5* luksus, recepcja 24h.","Kategorię przyznaje marszałek województwa po kontroli (ustawa z 19 sierpnia 2004 r.)."]}],"questions":[{"type":"abcd","q":"Kto przyznaje kategorię (gwiazdki) obiektowi hotelarskiemu w Polsce?","options":["Minister sportu","Burmistrz gminy","Marszałek województwa","Polska Izba Hotelarstwa"],"correct":2,"explain":"Kategorię nadaje marszałek województwa na wniosek właściciela po kontroli zgodności z wymaganiami."},{"type":"abcd","q":"Ile minimum pokoi musi mieć hotel?","options":["5","10","7","15"],"correct":1,"explain":"Hotel to obiekt z minimum 10 pokojami; pensjonat — min. 7."},{"type":"tf","q":"Agroturystyka jest obiektem kategoryzowanym gwiazdkowo.","correct":false,"explain":"Agroturystyka należy do obiektów nieskategoryzowanych (bez gwiazdek, ale ze spełnieniem wymagań sanitarnych i technicznych)."},{"type":"flash","front":"Czym różni się pensjonat od hotelu?","back":"Pensjonat oferuje nocleg i pełne wyżywienie, ma mniejszy zakres usług i min. 7 pokoi; hotel min. 10 pokoi i szerszy zakres usług."}]},{"id":"obsluga-klienta-biuro-podrozy","wiki":[{"heading":"Etapy rozmowy sprzedażowej","bullets":["Powitanie — uśmiech, profesjonalny wygląd, aktywne słuchanie.","Badanie potrzeb — pytania otwarte o miejsce, termin, budżet, liczbę osób, standard.","Prezentacja oferty — kilka opcji, kluczowe informacje (cena, program, ubezpieczenia), korzyści.","Obsługa obiekcji — słuchanie wątpliwości, jasne odpowiedzi, alternatywy.","Finalizacja — szczegóły rezerwacji i płatności, umowa, potwierdzenie.","Pożegnanie i opieka posprzedażowa — podziękowanie, kontakt, opinia po powrocie."]}],"questions":[{"type":"abcd","q":"Na którym etapie obsługi klienta zadajemy pytania otwarte o budżet i preferencje?","options":["Badanie potrzeb","Finalizacja sprzedaży","Obsługa obiekcji","Pożegnanie"],"correct":0,"explain":"Pytania otwarte o miejsce, termin, budżet i standard zadaje się na etapie badania potrzeb."},{"type":"tf","q":"Opieka posprzedażowa obejmuje zapytanie klienta o opinię po powrocie z wyjazdu.","correct":true,"explain":"Pożegnanie i opieka posprzedażowa obejmują kontakt oraz zapytanie o opinię i sugestie po powrocie."},{"type":"flash","front":"Wymień sześć etapów obsługi klienta w biurze podróży.","back":"Powitanie, badanie potrzeb, prezentacja oferty, obsługa obiekcji, finalizacja sprzedaży, pożegnanie i opieka posprzedażowa."}]},{"id":"cechy-projektu-outdoorowego","wiki":[{"body":"Projekty outdoorowe nie muszą skupiać się na silnych emocjach ani ryzyku uszczerbku na zdrowiu. Outdoor to szerszy obszar niż turystyka — wyróżnia się outdoor recreation, education i activities. Często łączy się z turystyką miejską (np. spływ tratwami, jazda konna, narciarstwo, trekking, birdwatching)."},{"heading":"Czynniki kształtujące outdoor","bullets":["Otwarta przestrzeń — miejska lub wiejska, przystosowana i bezpieczna.","Integracja z otoczeniem — przestrzeń zagospodarowana, interakcja ze środowiskiem.","Integracja i interakcja z uczestnikami — wycieczki, warsztaty, gry, wspólne oglądanie.","Warunki atmosferyczne — pogoda jako przeszkoda lub zaleta.","Element edukacji — zamierzony lub jako efekt działania."]},{"heading":"Główne aspekty projektów outdoorowych","bullets":["Promocja dziedzictwa kulturowego i naturalnego.","Podniesienie znaczenia lokalnej ludności i jej tożsamości.","Budowanie kompetencji międzykulturowych.","Budowanie obustronnego szacunku do miejsca.","Tworzenie sztuki w przestrzeni i innych wytworów."]}],"questions":[{"type":"abcd","q":"Który czynnik NIE jest typowym wyróżnikiem projektu outdoorowego?","options":["Otwarta przestrzeń przystosowana i bezpieczna","Integracja z otoczeniem","Wysokie ryzyko uszczerbku na zdrowiu jako cel","Interakcja z uczestnikami"],"correct":2,"explain":"Outdoor nie skupia się na dużym ryzyku — kładzie nacisk na wątki kulturowe i interakcję z otoczeniem."},{"type":"tf","q":"Outdoor zawęża się wyłącznie do turystyki.","correct":false,"explain":"Outdoor to szerszy obszar; wyróżnia się outdoor recreation, education i activities."},{"type":"flash","front":"Wymień trzy rodzaje outdooru.","back":"Outdoor recreation, outdoor education i outdoor activities."}]},{"id":"edukacja-przygodowa","wiki":[{"body":"Edukacja przygodowa opiera się na uczeniu przez doświadczenie i relacji człowieka z naturą. Pojęcie outdoor education jest szerokie — obejmuje ekstremalne wyprawy, lekcje w terenie i percepcyjne obcowanie z przyrodą (pol. edukacja plenerowa)."},{"heading":"Trzy komponenty outdoor education","bullets":["Ekologia.","Rozwój umiejętności fizycznych.","Relacje interpersonalne."]},{"heading":"Adventure education wg Priesta i Gassa","bullets":["Cel — uświadomienie uczestnikowi możliwości zmiany na lepsze (samoocena, relacje społeczne).","Proces — aktywności grupowe/indywidualne wymagające decyzyjności, rozwiązywania problemów, komunikacji, współpracy, zaufania i ryzyka (emocjonalnego, społecznego, fizycznego).","Wynik — samodoskonalenie; zmierzenie się z ograniczeniami i rozwój potencjału, poprawa relacji z innymi i sobą."]},{"body":"Adventure education i environmental education zawierają się w szerszym ujęciu outdoor education. Na zachodzie rozwinęły się dwa nurty: pedagogika przygody (kraje anglosaskie) oraz pedagogika przeżyć (m.in. Niemcy, Czechy)."}],"questions":[{"type":"abcd","q":"Które trzy komponenty łączą działania outdoor education?","options":["Ekonomia, marketing, logistyka","Historia, kultura, sztuka","Ryzyko, rywalizacja, nagroda","Ekologia, rozwój umiejętności fizycznych, relacje interpersonalne"],"correct":3,"explain":"Outdoor education łączy ekologię, rozwój umiejętności fizycznych oraz relacje interpersonalne."},{"type":"abcd","q":"Według Priesta i Gassa wynikiem adventure education jest:","options":["samodoskonalenie","zysk finansowy","zdobycie certyfikatu","wygrana w rywalizacji"],"correct":0,"explain":"Wynik to samodoskonalenie — rozwój potencjału i poprawa relacji z innymi i sobą."},{"type":"tf","q":"Pedagogika przeżyć rozwinęła się głównie w krajach anglosaskich.","correct":false,"explain":"W krajach anglosaskich rozwinęła się pedagogika przygody; pedagogika przeżyć — m.in. w Niemczech i Czechach."},{"type":"flash","front":"Opisz model adventure education wg Priesta i Gassa.","back":"Cel (zmiana na lepsze), proces (aktywności wymagające decyzyjności, współpracy i ryzyka) oraz wynik (samodoskonalenie)."}]},{"id":"obowiazki-pracownika-pracodawcy","wiki":[{"heading":"Obowiązki pracownika","bullets":["Sumienne wykonywanie pracy - rzetelnie, zgodnie z zaleceniami przełożonych, instrukcją i harmonogramem","Przestrzeganie przepisów BHP oraz regulaminu pracy, utrzymywanie porządku i higieny dla bezpieczeństwa swojego i innych","Dbanie o mienie pracodawcy - szanowanie sprzętu, narzędzi i materiałów, używanie ich zgodnie z przeznaczeniem","Zachowanie tajemnicy - danych firmy, klientów i informacji chronionych","Zachowanie kultury osobistej - unikanie konfliktów, poszanowanie innych, współpraca i komunikacja"]},{"heading":"Obowiązki pracodawcy","bullets":["Zapewnienie bezpiecznych i higienicznych warunków pracy (sprawny sprzęt, szkolenia BHP)","Terminowe i uczciwe wynagrodzenie","Szacunek dla godności pracownika - zakaz dyskryminacji i mobbingu","Dbanie o rozwój zawodowy pracownika","Przestrzeganie przepisów prawa pracy (czas pracy, urlopy)"]},{"body":"Podstawą wzajemnych obowiązków są umowa o pracę oraz przepisy prawa pracy, które określają normy i regulacje związane z zatrudnieniem."}],"questions":[{"type":"abcd","q":"Który z poniższych jest obowiązkiem pracodawcy, a nie pracownika?","options":["Dbanie o mienie pracodawcy","Zachowanie tajemnicy firmy","Zapewnienie bezpiecznych i higienicznych warunków pracy","Przestrzeganie regulaminu pracy"],"correct":2,"explain":"Zapewnienie bezpiecznych i higienicznych warunków pracy spoczywa na pracodawcy; pozostałe to obowiązki pracownika."},{"type":"tf","q":"Zakaz dyskryminacji i mobbingu należy do obowiązków pracownika.","correct":false,"explain":"To obowiązek pracodawcy — musi on szanować godność pracownika oraz przeciwdziałać dyskryminacji i mobbingowi."},{"type":"flash","front":"Wymień podstawowe obowiązki pracownika.","back":"Sumienne wykonywanie pracy, przestrzeganie BHP i regulaminu, dbanie o mienie pracodawcy, zachowanie tajemnicy oraz kultury osobistej."}]},{"id":"teorie-potrzeb-rekreacja","wiki":[{"body":"Rekreacja pełni funkcję zaspokajania potrzeb rekreacyjnych, zdrowotnych, poznawczych, kulturowych i społecznych. Uczestnik angażuje się nie tylko dla ruchu, ale też dla poprawy kondycji, poznawania nowych treści, integracji i relaksu."},{"heading":"Piramida potrzeb Maslowa","body":"Maslow uporządkował potrzeby od najbardziej podstawowych do najwyższych:","bullets":["Fizjologiczne - ruch, odpoczynek, regeneracja (gimnastyka, spacery)","Bezpieczeństwa - bezpieczne warunki zajęć, nadzór trenera, struktura treningu","Przynależności i akceptacji - zajęcia grupowe, integracja, gry zespołowe","Uznania - pochwały, osiągnięcia, testy sprawnościowe","Samorealizacji - nowe wyzwania, rozwój kompetencji, kreatywność"]},{"heading":"Teoria autodeterminacji (Ryan i Deci)","body":"Wskazuje 3 kluczowe potrzeby psychologiczne, których zaspokojenie daje poczucie spełnienia i radości:","bullets":["Autonomia - decydowanie samemu o sobie","Kompetencja - poczucie sprawności i rozwijanie umiejętności","Relacje - posiadanie dobrych więzi z innymi"]}],"questions":[{"type":"abcd","q":"Które trzy potrzeby psychologiczne wyróżnia teoria autodeterminacji Ryana i Deciego?","options":["Poznawcze, kulturowe, zdrowotne","Fizjologiczne, bezpieczeństwa, uznania","Ruch, odpoczynek, regeneracja","Autonomia, kompetencja, relacje"],"correct":3,"explain":"Teoria autodeterminacji opiera się na potrzebie autonomii, kompetencji i relacji z innymi."},{"type":"tf","q":"Według piramidy Maslowa potrzeba samorealizacji znajduje się na najwyższym poziomie.","correct":true,"explain":"Maslow uporządkował potrzeby od fizjologicznych (najniższe) do samorealizacji (najwyższe)."},{"type":"flash","front":"Jak rekreacja realizuje potrzebę przynależności wg Maslowa?","back":"Poprzez zajęcia grupowe, integrację, gry zespołowe i wspólne wyprawy."}]},{"id":"komunikowanie-w-organizacji","wiki":[{"body":"Komunikacja w organizacji to proces wymiany informacji, idei, opinii i instrukcji między członkami organizacji, odgrywający kluczową rolę w jej efektywnym funkcjonowaniu."},{"heading":"Funkcje komunikacji","bullets":["Informacyjna - przekazywanie danych, instrukcji, celów","Motywacyjna - zachęcanie pracowników do działania","Kontrolna - monitorowanie zadań i przestrzeganie zasad","Emocjonalno-społeczna - budowanie zaufania, atmosfery i relacji"]},{"heading":"Rodzaje komunikacji","bullets":["Formalna - oficjalne komunikaty, maile, spotkania, dokumenty","Nieformalna - codzienne rozmowy","Pionowa - polecenia przełożonych, raporty pracowników","Pozioma - między pracownikami tego samego szczebla"]},{"heading":"Rola lidera i bariery","body":"Lider przekazuje jasne informacje, udziela informacji zwrotnej, rozwiązuje konflikty, słucha, motywuje i prowadzi dialog. Bariery komunikacyjne to m.in. różnice międzykulturowe i wiekowe, brak jasnych kanałów oraz nieefektywne przekazywanie informacji."}],"questions":[{"type":"abcd","q":"Komunikacja między pracownikami tego samego szczebla to komunikacja:","options":["Pionowa","Pozioma","Formalna","Kontrolna"],"correct":1,"explain":"Komunikacja pozioma zachodzi między pracownikami na tym samym szczeblu, w odróżnieniu od pionowej (przełożony-podwładny)."},{"type":"tf","q":"Funkcja motywacyjna komunikacji polega na monitorowaniu zadań i przestrzegania zasad.","correct":false,"explain":"Monitorowanie zadań to funkcja kontrolna; funkcja motywacyjna polega na zachęcaniu pracowników do działania."},{"type":"flash","front":"Za co odpowiada lider w komunikacji w organizacji?","back":"Za przekazywanie jasnych informacji, udzielanie informacji zwrotnej, rozwiązywanie konfliktów, słuchanie, motywowanie i prowadzenie otwartego dialogu."}]},{"id":"rodzina-jako-mala-grupa","wiki":[{"body":"Rodzina to grupa społeczna składająca się z bliskich osób - najczęściej rodziców i dzieci, czasem dziadków. Jej członkowie dobrze się znają i spędzają razem dużo czasu, a grupa - choć niewielka - ma swoje zasady i role."},{"heading":"Motywy uczestnictwa rodziny w turystyce i rekreacji","bullets":["Integracyjny - wspólne spędzanie czasu, oderwanie od codzienności, wzmacnianie więzi","Wychowawczy - dzieci uczą się przez obserwację zasad społecznych, współpracy i kultury","Edukacyjny - poznawanie nowych miejsc, kultury i historii","Zdrowotny - aktywność fizyczna (spacery, rower, pływanie) wspiera zdrowie całej rodziny"]},{"heading":"Planowanie wyjazdu","body":"Wyjazd to często wspólna decyzja - rodzice wybierają miejsce, ale uwzględniają sugestie dzieci. Wybór zależy od możliwości finansowych, zainteresowań i potrzeb. Trudności mogą wynikać z różnic pokoleniowych, ograniczeń finansowych oraz zmieniających się potrzeb rodziny."}],"questions":[{"type":"abcd","q":"Który motyw uczestnictwa rodziny w turystyce wiąże się z uczeniem dzieci zasad społecznych przez obserwację?","options":["Wychowawczy","Zdrowotny","Integracyjny","Edukacyjny"],"correct":0,"explain":"Motyw wychowawczy polega na tym, że dzieci uczą się zasad społecznych, współpracy i kultury przez obserwację i uczestnictwo."},{"type":"tf","q":"Planowanie wyjazdu rodzinnego nigdy nie napotyka problemów wynikających z różnic pokoleniowych.","correct":false,"explain":"Różnice pokoleniowe (inne zainteresowania), ograniczenia finansowe i zmiany potrzeb mogą utrudniać planowanie wyjazdu."},{"type":"flash","front":"Wymień motywy uczestnictwa rodziny w turystyce i rekreacji.","back":"Integracyjny, wychowawczy, edukacyjny i zdrowotny."}]},{"id":"zabawa-rozrywka-grupy-wiekowe","wiki":[{"body":"Czas wolny to czas bez obowiązków zawodowych, szkolnych czy domowych, przeznaczony na odpoczynek, regenerację i samorealizację. Zabawa to spontaniczna aktywność dająca radość i rozwijająca umiejętności, a rozrywka to szeroko pojęte formy spędzania czasu wolnego (fizyczne, kulturowe, rekreacyjne)."},{"heading":"Dzieci (wiek przedszkolny i wczesnoszkolny)","bullets":["Zabawy ruchowe - rozwijają sprawność fizyczną (bieganie, plac zabaw)","Zabawy konstrukcyjne - wspierają logiczne myślenie (klocki, układanki)","Zabawy fabularne i tematyczne - rozwijają wyobraźnię (dom, sklep)","Gry planszowe - ćwiczą pamięć i koncentrację"]},{"heading":"Młodzież","bullets":["Sport - kondycja i zdrowie (siłownia, sporty drużynowe, taniec)","Kultura - muzyka, kino, teatr","Internet i gry komputerowe, media społecznościowe","Podróże oraz wolontariat (poczucie sensu, odpowiedzialność)"]},{"heading":"Dorośli","bullets":["Relaks - redukcja stresu (książki, film)","Aktywność fizyczna (siłownia, joga, fitness)","Spotkania towarzyskie i hobby/pasje","Rozwój zawodowy i nauka"]}],"questions":[{"type":"abcd","q":"Który rodzaj zabawy dzieci szczególnie wspiera logiczne myślenie?","options":["Zabawy ruchowe","Zabawy tematyczne","Zabawy fabularne","Zabawy konstrukcyjne"],"correct":3,"explain":"Zabawy konstrukcyjne (klocki, układanki) wspierają logiczne myślenie."},{"type":"tf","q":"Czas wolny dorosłych jest zazwyczaj mocno ograniczony przez dużą ilość obowiązków.","correct":true,"explain":"Według materiału czas wolny dorosłych jest dość mocno ograniczony przez liczne obowiązki."},{"type":"flash","front":"Czym różni się zabawa od rozrywki?","back":"Zabawa to spontaniczna aktywność dająca radość i rozwijająca umiejętności; rozrywka to szeroko pojęte formy spędzania czasu wolnego - fizyczne, kulturowe i rekreacyjne."}]},{"id":"zasady-prezentacji-powerpoint","wiki":[{"heading":"Pięć zasad","bullets":["Logiczna struktura i płynność - jasny podział na wstęp, rozwinięcie i zakończenie, start od tytułu i spisu treści, logiczna kolejność slajdów","Przejrzystość i minimalizm - jeden slajd to jedna myśl, hasła i punkty zamiast długich zdań, czytelna czcionka (Arial, Calibri)","Styl graficzny - jedna kolorystyka i czcionka, maksymalnie 2-3 kolory, unikanie nadmiaru efektów specjalnych","Grafika i wspierające treści - każdy element graficzny coś tłumaczy, obrazy dobrej jakości i czytelne","Interakcja i dopasowanie do słuchaczy - mówienie swobodne zamiast czytania slajdów, angażowanie pytaniami i przykładami, dostosowanie języka do odbiorców"]}],"questions":[{"type":"abcd","q":"Ile kolorów zaleca się stosować w spójnym stylu graficznym prezentacji?","options":["Dowolnie wiele","Co najmniej 5","Maksymalnie 2-3","Tylko czarny i biały"],"correct":2,"explain":"Zasada stylu graficznego zaleca używanie maksymalnie 2-3 kolorów dla zachowania spójności."},{"type":"tf","q":"Zgodnie z dobrymi zasadami prezentacji należy odczytywać tekst ze slajdów słowo w słowo.","correct":false,"explain":"Zasada interakcji mówi, by nie czytać slajdów, lecz mówić swobodnie i rozwijać hasła."},{"type":"flash","front":"Na czym polega zasada przejrzystości i minimalizmu?","back":"Każdy slajd to jedna myśl - krótko i konkretnie; zamiast długich zdań stosuje się hasła i punkty oraz czytelną czcionkę odpowiedniej wielkości."}]},{"id":"fizjologiczne-podstawy-treningu","wiki":[{"body":"Trening fizyczny wpływa na organizm poprzez adaptacje fizjologiczne zwiększające wydolność, siłę i sprawność. Jego podstawą jest zdolność organizmu do adaptacji do obciążeń wysiłkowych."},{"heading":"Źródła energii podczas wysiłku","bullets":["System fosfagenowy (ATP) - dostarcza energii bardzo szybko, do krótkich intensywnych wysiłków","Glikoliza beztlenowa - rozkład glukozy bez tlenu, energia od kilkudziesięciu sekund do minut, produktem jest mleczan","Metabolizm tlenowy - zachodzi w mitochondriach, wykorzystuje węglowodany i tłuszcze, do długotrwałych wysiłków"]},{"heading":"Adaptacje układów","bullets":["Mięśniowy - hipertrofia, wzrost wytrzymałości, więcej mitochondriów, lepsza koordynacja nerwowo-mięśniowa","Krążenia - wzrost objętości wyrzutowej i minutowej serca, spadek tętna spoczynkowego, więcej naczyń włosowatych, obniżenie ciśnienia i poziomu LDL","Oddechowy - większa pojemność płuc, lepsza wymiana gazowa, silniejsze mięśnie oddechowe","Nerwowy - lepsza koordynacja i czas reakcji, więcej endorfin","Metaboliczny i hormonalny - lepsze spalanie tłuszczów, większa wrażliwość na insulinę, wzrost testosteronu"]}],"questions":[{"type":"abcd","q":"Który system energetyczny dostarcza energii najszybciej, w krótkich i intensywnych wysiłkach?","options":["Metabolizm tlenowy","System fosfagenowy (ATP)","Glikoliza beztlenowa","Lipoliza"],"correct":1,"explain":"System fosfagenowy (ATP) dostarcza energii bardzo szybko i jest wykorzystywany w krótkich intensywnych wysiłkach."},{"type":"tf","q":"Regularny trening prowadzi do spadku tętna spoczynkowego.","correct":true,"explain":"Adaptacja układu krążenia obejmuje spadek tętna spoczynkowego - serce bije wolniej i bardziej efektywnie."},{"type":"flash","front":"Jakie zmiany w układzie mięśniowym wywołuje trening?","back":"Hipertrofia (wzrost masy i siły), wzrost wytrzymałości, większa liczba mitochondriów oraz lepsza koordynacja nerwowo-mięśniowa."}]},{"id":"segmentacja-rynku-turystycznego","wiki":[{"body":"Segmentacja rynku to podział dużej grupy klientów na mniejsze segmenty o podobnych cechach, potrzebach lub zachowaniach. Dzięki temu firmy turystyczne lepiej dopasowują oferty do konkretnej grupy, zwiększając jej zadowolenie i skuteczność marketingu."},{"heading":"Kryteria segmentacji","bullets":["Demograficzne - wiek, płeć, dochód, stan cywilny, wykształcenie","Geograficzne - miejsce zamieszkania, klimat, odległość od destynacji","Psychograficzne - styl życia, wartości, osobowość, zainteresowania","Behawioralne - motywacje, lojalność, częstotliwość podróżowania"]},{"heading":"Segmentacja wg celu podróży i aktywności","bullets":["Cel podróży: wypoczynkowa, biznesowa, zdrowotna (spa, wellness), kulturowa","Rodzaj aktywności: sportowa, ekoturystyka, rozrywkowa"]},{"heading":"Przykładowe segmenty","bullets":["Rodziny z dziećmi - atrakcje dla najmłodszych","Młodzi dorośli - przygody, życie nocne, aktywny odpoczynek","Seniorzy - spokój i dostęp do opieki medycznej","Turyści biznesowi - szybki transport i dogodności do pracy","Miłośnicy przygód - ekoturystyka, natura"]}],"questions":[{"type":"abcd","q":"Styl życia, wartości i zainteresowania to kryterium segmentacji:","options":["Psychograficzne","Geograficzne","Demograficzne","Behawioralne"],"correct":0,"explain":"Kryterium psychograficzne obejmuje styl życia, wartości, osobowość i zainteresowania."},{"type":"tf","q":"Segmentacja rynku pozwala firmom turystycznym lepiej dopasować ofertę do konkretnej grupy klientów.","correct":true,"explain":"To główny cel segmentacji - dopasowanie oferty zwiększa zadowolenie klientów i skuteczność działań marketingowych."},{"type":"flash","front":"Wymień cztery kryteria segmentacji rynku turystycznego.","back":"Demograficzne, geograficzne, psychograficzne i behawioralne."}]},{"id":"czynniki-zachowania-wolnoczasowe","wiki":[{"body":"Zachowanie wolnoczasowe to sposoby, w jakie ludzie spędzają swój czas wolny. Wybór aktywności zależy od wielu czynników."},{"heading":"Czynniki demograficzne","bullets":["Wiek - dzieci preferują zabawy ruchowe, młodzież gry i sport, dorośli rekreację i turystykę, seniorzy spokojne formy (spacery)","Płeć - mężczyźni częściej sport i rywalizację, kobiety częściej zajęcia relaksacyjne, kulturowe i społeczne","Stan cywilny i sytuacja rodzinna - osoby samotne wybierają podróże i spotkania, rodziny z dziećmi rekreację dla najmłodszych"]},{"heading":"Pozostałe czynniki","bullets":["Ekonomiczne - dochód i dostępność urlopu wpływają na wybór (droższe vs darmowe formy)","Społeczne - wpływ rodziny i znajomych, trendy i moda na zdrowy styl życia","Psychologiczne - motywacje, osobowość (introwertyk vs ekstrawertyk), stan zdrowia","Kulturowe i technologiczne - internet, gry online, urbanizacja i infrastruktura miast","Środowiskowe - infrastruktura, walory naturalne (góry, jeziora, lasy), dostępność komunikacyjna i bezpieczeństwo"]}],"questions":[{"type":"abcd","q":"Różnica między introwertykami a ekstrawertykami w wyborze form czasu wolnego należy do czynników:","options":["Ekonomicznych","Demograficznych","Psychologicznych","Środowiskowych"],"correct":2,"explain":"Osobowość (introwertyk vs ekstrawertyk) to czynnik psychologiczny."},{"type":"tf","q":"Bliskość gór, jezior i lasów to przykład czynnika ekonomicznego determinującego zachowanie wolnoczasowe.","correct":false,"explain":"Walory naturalne to czynniki środowiskowe, a nie ekonomiczne; do ekonomicznych zalicza się np. dochód czy ceny usług."},{"type":"flash","front":"Wymień główne grupy czynników determinujących zachowanie wolnoczasowe.","back":"Demograficzne, ekonomiczne, społeczne, psychologiczne, kulturowo-technologiczne oraz środowiskowe."}]},{"id":"ladowe-ekosystemy-swiata","wiki":[{"heading":"Bioróżnorodność","body":"Bioróżnorodność (różnorodność biologiczna) to całe bogactwo form życia na Ziemi: gatunki zwierząt, roślin i mikroorganizmów, ich zróżnicowanie genetyczne oraz ekosystemy, w których funkcjonują.","bullets":["Genetyczna - np. rasy psów, różne odmiany jabłoni","Gatunkowa - liczba i rodzaje gatunków (ptaki, ssaki, rośliny) w danym ekosystemie","Ekosystemowa - lasy, łąki, bagna, pustynie"]},{"heading":"Główne ekosystemy lądowe","bullets":["Lasy równikowe (deszczowe, tropikalne) - najbogatszy ekosystem Ziemi, liczne gatunki endemiczne; zagrożenia: wycinka, rolnictwo (soja, palma olejowa), zmiany klimatu","Lasy liściaste strefy umiarkowanej - różnorodne drzewa liściaste, bogata fauna; zagrożenia: zanieczyszczenia powietrza, intensywna gospodarka leśna, fragmentacja siedlisk","Tajga - dominują drzewa iglaste, fauna chłodnego klimatu (łosie, wilki, niedźwiedzie); zagrożenia: wycinka przemysłowa, topnienie wiecznej zmarzliny, pożary","Pustynie - sukulenty, gady, drobne ssaki; zagrożenia: zmiany klimatu, nadużywanie wód podziemnych","Tundra - niska roślinność (mchy, porosty), lisy polarne, sowy śnieżne, renifery; zagrożenia: eksploatacja surowców, ocieplenie klimatu","Sawanna - obszary trawiaste z rozproszonymi drzewami, dużo ssaków; zagrożenia: nadmierny wypas, kłusownictwo, wypalanie traw","Stepy i prerie - trawiaste równiny (trawy, gryzonie, sokoły, dzikie konie); zagrożenia: przekształcanie w tereny rolnicze, erozja gleby"]}],"questions":[{"type":"abcd","q":"Który ekosystem lądowy jest uznawany za najbogatszy pod względem bioróżnorodności?","options":["Tundra","Lasy równikowe (deszczowe)","Pustynie","Stepy i prerie"],"correct":1,"explain":"Lasy równikowe (tropikalne) to najbogatszy ekosystem Ziemi z ogromną liczbą gatunków, w tym licznymi endemitami."},{"type":"abcd","q":"Ile rodzajów bioróżnorodności wyróżniono w materiale?","options":["3 - genetyczna, gatunkowa, ekosystemowa","2 - genetyczna i gatunkowa","4 - z dodatkiem krajobrazowej","5"],"correct":0,"explain":"Wyróżniono trzy rodzaje: genetyczną, gatunkową i ekosystemową."},{"type":"tf","q":"Topnienie wiecznej zmarzliny jest jednym z problemów środowiskowych tajgi.","correct":true,"explain":"W tajdze zagrożeniem są wycinka przemysłowa, zmiany klimatyczne (topnienie wiecznej zmarzliny) oraz pożary."},{"type":"flash","front":"Wymień przykładowe problemy środowiskowe lasów równikowych.","back":"Wycinka lasów, rolnictwo (uprawa soi, palmy olejowej) prowadzące do utraty siedlisk i spadku bioróżnorodności, oraz zmiany klimatyczne przesuszające lasy."}]},{"id":"wodne-ekosystemy-swiata","wiki":[{"heading":"Rodzaje wodnych ekosystemów","body":"Ekosystemy wodne są kluczowe dla życia na Ziemi - stanowią siedliska milionów gatunków oraz pełnią funkcję filtracyjną i klimatyczną.","bullets":["Słodkowodne - rzeki, jeziora, bagna, mokradła; ryby (pstrągi, sumy), płazy (żaby, salamandry), gady (żółwie, krokodyle), rośliny wodne, ptaki wodne","Morskie - oceany, morza, rafy koralowe; od planktonu i koralowców po drapieżniki jak rekiny","Rafy koralowe - zajmują niewielką powierzchnię, ale są siedliskiem dla około 25% wszystkich gatunków morskich"]},{"heading":"Problemy środowiskowe","bullets":["Zanieczyszczenia wód - ścieki przemysłowe i rolnicze, pestycydy; eutrofizacja (namnażanie glonów przez nadmiar azotu, deficyt tlenu); plastik w oceanach","Zmiany klimatu i globalne ocieplenie - zakwaszenie oceanu, wzrost poziomu wody, zmiany zasolenia przez topnienie lodowców","Nadmierna eksploatacja - budowa i regulacja rzek ograniczająca migrację ryb","Zanieczyszczenie siedlisk - osuszanie bagien i mokradeł, utrata siedlisk ptaków wodnych i płazów"]},{"heading":"Ochrona wodnych ekosystemów","bullets":["Zrównoważone rybołówstwo","Ochrona siedlisk i gatunków","Działania na rzecz klimatu","Redukcja zanieczyszczeń"]}],"questions":[{"type":"abcd","q":"Jaki odsetek wszystkich gatunków morskich znajduje siedlisko w rafach koralowych?","options":["Około 5%","Około 10%","Około 25%","Około 50%"],"correct":2,"explain":"Rafy koralowe zajmują niewielką powierzchnię, lecz są siedliskiem dla około 25% wszystkich gatunków morskich."},{"type":"abcd","q":"Czym jest eutrofizacja?","options":["Zakwaszeniem oceanu przez wzrost temperatury","Przyspieszonym namnażaniem glonów spowodowanym nadmiarem azotu, prowadzącym do deficytu tlenu","Topnieniem lodowców i wzrostem poziomu wód","Migracją ryb między rzekami"],"correct":1,"explain":"Eutrofizacja to przyspieszone namnażanie glonów wskutek nadmiaru azotu, co prowadzi do deficytu tlenu i śmierci organizmów wodnych."},{"type":"tf","q":"Osuszanie bagien i mokradeł przyczynia się do utraty siedlisk ptaków wodnych i płazów.","correct":true,"explain":"Osuszanie bagien i mokradeł to zanieczyszczenie/niszczenie siedlisk skutkujące utratą siedlisk ptaków wodnych i płazów."},{"type":"flash","front":"Wymień sposoby ochrony wodnych ekosystemów.","back":"Zrównoważone rybołówstwo, ochrona siedlisk i gatunków, działania na rzecz klimatu oraz redukcja zanieczyszczeń."}]},{"id":"zalety-statystyki-w-turystyce","wiki":[{"heading":"Lepsze planowanie i zarządzanie turystyką","body":"Statystyka dostarcza danych o tym, ilu turystów przyjeżdża, skąd pochodzą, jak długo zostają i z jakich usług korzystają.","bullets":["Efektywne planowanie rozwoju infrastruktury (noclegi, drogi, atrakcje)","Dostosowanie oferty usługowej i zarządzanie zasobami","Np. dane o szczycie w lipcu i sierpniu pozwalają z wyprzedzeniem zwiększyć liczbę pracowników i rozbudować bazę","Zmniejszenie ryzyka przeciążenia miejsc i niezadowolenia turystów"]},{"heading":"Monitorowanie wpływu gospodarczego","body":"Statystyka pozwala ocenić, jak turystyka wpływa na gospodarkę: ile pieniędzy wydają turyści, które branże zyskują (hotele, restauracje, transport), ile miejsc pracy tworzy turystyka. Pomaga to władzom lokalnym podejmować świadome decyzje rozwojowe."},{"heading":"Trafne decyzje biznesowe i prognozowanie trendów","body":"Analiza statystyczna pomaga przewidzieć przyszłe zachowania turystów, co jest istotne przy planowaniu reklam, inwestycji i planów rozwoju. Branża może szybciej reagować na problemy, takie jak spadek liczby odwiedzających lub zmiana zainteresowań."}],"questions":[{"type":"abcd","q":"Która z poniższych jest zaletą stosowania statystyki w turystyce wymienioną w materiale?","options":["Lepsze planowanie i zarządzanie turystyką","Eliminacja sezonowości ruchu turystycznego","Likwidacja kosztów infrastruktury","Gwarancja stałej liczby turystów"],"correct":0,"explain":"Pierwszą wymienioną zaletą jest lepsze planowanie i zarządzanie turystyką dzięki danym o ruchu turystycznym."},{"type":"tf","q":"Statystyka pozwala ocenić wpływ turystyki na gospodarkę, np. ile pieniędzy wydają turyści i ile miejsc pracy tworzy turystyka.","correct":true,"explain":"Monitorowanie wpływu gospodarczego to jedna z głównych zalet - statystyka ujawnia wydatki turystów, zyski branż i liczbę miejsc pracy."},{"type":"flash","front":"Podaj trzy zalety stosowania statystyki w turystyce.","back":"Lepsze planowanie i zarządzanie turystyką, monitorowanie wpływu gospodarczego oraz podejmowanie trafnych decyzji biznesowych i prognozowanie trendów."}]},{"id":"pojecie-i-funkcje-zarzadzania","wiki":[{"heading":"Pojęcie zarządzania","body":"Zarządzanie to proces planowania, organizowania, przewodzenia i kontrolowania zasobów organizacji w celu osiągnięcia określonych celów. Jest kluczowym elementem funkcjonowania każdej organizacji, niezależnie od jej wielkości czy branży."},{"heading":"Podstawowe funkcje zarządzania","bullets":["Planowanie - określanie celów i sposobów ich realizacji; analiza sytuacji, prognozowanie i opracowanie strategii","Organizowanie - przydzielanie zadań, zasobów i odpowiedzialności; tworzenie struktur organizacyjnych","Przewodzenie - motywowanie i prowadzenie zespołu, komunikacja, rozwiązywanie problemów i podejmowanie decyzji","Kontrolowanie - monitorowanie postępów i porównywanie z celami; wprowadzanie korekt"]},{"body":"W modelu Henriego Fayola wyróżnia się 5. funkcję: koordynowanie."}],"questions":[{"type":"abcd","q":"Która funkcja zarządzania polega na monitorowaniu postępów i porównywaniu ich z założonymi celami?","options":["Planowanie","Kontrolowanie","Przewodzenie","Organizowanie"],"correct":1,"explain":"Kontrolowanie to monitorowanie postępów i porównywanie ich z celami oraz wprowadzanie korekt."},{"type":"abcd","q":"Jaką piątą funkcję zarządzania dodał Henri Fayol?","options":["Koordynowanie","Delegowanie","Negocjowanie","Raportowanie"],"correct":0,"explain":"W modelu Henriego Fayola piątą funkcją jest koordynowanie."},{"type":"tf","q":"Motywowanie zespołu, komunikacja i podejmowanie decyzji należą do funkcji planowania.","correct":false,"explain":"To elementy przewodzenia, a nie planowania; planowanie dotyczy wyznaczania celów i sposobów ich osiągnięcia."},{"type":"flash","front":"Wymień cztery podstawowe funkcje zarządzania.","back":"Planowanie, organizowanie, przewodzenie i kontrolowanie (w modelu Fayola dodatkowo koordynowanie)."}]},{"id":"determinizm-i-wolna-wola","wiki":[{"heading":"Pojęcia","bullets":["Determinizm - pogląd, że wszystko, co się dzieje, ma swoją przyczynę; znając prawa natury i warunki początkowe można przewidzieć każde zdarzenie, także ludzkie decyzje","Wolna wola - przekonanie, że człowiek może samodzielnie wybierać, co oznacza odpowiedzialność za swoje decyzje"]},{"heading":"Problem","body":"Jeśli wszystko jest z góry zdeterminowane, to być może nasze decyzje są jedynie skutkiem genów, wychowania i innych wpływów. Powstaje pytanie, czy mamy wtedy wolną wolę i czy jesteśmy za coś odpowiedzialni."},{"heading":"Trzy główne podejścia filozoficzne","bullets":["Twardy determinizm - nie ma wolnej woli; wolność to tylko nasze wrażenie, a nie prawda","Libertarianizm - wolna wola istnieje, świat nie jest całkowicie zdeterminowany; człowiek może działać inaczej i ponosi odpowiedzialność","Kompatybilizm - wolna wola i determinizm mogą współistnieć; człowiek jest wolny, jeśli działa zgodnie ze swoimi przekonaniami, a nie pod przymusem"]}],"questions":[{"type":"abcd","q":"Które stanowisko głosi, że wolna wola i determinizm mogą działać razem?","options":["Twardy determinizm","Kompatybilizm","Libertarianizm","Indeterminizm"],"correct":1,"explain":"Kompatybilizm zakłada, że wolna wola i determinizm mogą współistnieć - człowiek jest wolny, jeśli działa zgodnie ze swoimi przekonaniami, a nie pod przymusem."},{"type":"abcd","q":"Co głosi twardy determinizm w kwestii wolności człowieka?","options":["Wolność to iluzja, wolnej woli nie ma","Człowiek jest w pełni wolny","Wolność zależy od wychowania","Wolna wola istnieje obok determinizmu"],"correct":0,"explain":"Według twardego determinizmu wolności nie ma - jest ona tylko iluzją, a wszystko dzieje się, bo musiało się tak stać."},{"type":"tf","q":"Determinizm to pogląd, że wszystko, co się dzieje, ma swoją przyczynę.","correct":true,"explain":"Tak brzmi definicja determinizmu - każde zdarzenie ma swoją przyczynę, a znając prawa natury i warunki początkowe można je przewidzieć."},{"type":"flash","front":"Wymień trzy główne podejścia filozoficzne do problemu determinizmu i wolnej woli.","back":"Twardy determinizm (brak wolnej woli), libertarianizm (wolna wola istnieje) oraz kompatybilizm (wolna wola i determinizm współistnieją)."}]},{"id":"e-marketing-w-turystyce-i-rekreacji","wiki":[{"heading":"Pojęcie","body":"E-marketing to wykorzystywanie cyfrowych kanałów komunikacji do prezentowania oferty turystycznej, interakcji z klientami oraz monitorowania skuteczności działań. Kluczowym celem jest dotarcie do potencjalnych turystów i rekreantów w sposób atrakcyjny, spersonalizowany i mierzalny."},{"heading":"Narzędzia e-marketingu","bullets":["Strony internetowe i blogi - atrakcyjne strony ze zdjęciami i opisami, blogi budujące zaufanie","SEO - optymalizacja treści pod wyszukiwarki, by strona pojawiała się wyżej w wynikach","SEM - płatne reklamy (np. Google Ads) docierające do osób szukających konkretnych usług","Media społecznościowe - Instagram, Facebook itp. do prezentacji oferty i interakcji","E-mail marketing - newslettery i oferty specjalne utrzymujące kontakt z klientami","Content marketing - wartościowe treści: artykuły, filmy, infografiki","Mobile marketing - dostosowanie treści i reklam do urządzeń mobilnych","Reklamy graficzne i wideo - atrakcyjny wizualny sposób prezentacji oferty"]},{"heading":"Znaczenie","bullets":["Globalny zasięg - prezentacja ofert na całym świecie 24/7","Niższe koszty - reklama tańsza i bardziej efektywna","Dostosowanie do klienta - dzięki analizie danych oferta dopasowana indywidualnie","Szybka analiza wyników - bieżące śledzenie skuteczności kampanii"]}],"questions":[{"type":"abcd","q":"Które narzędzie e-marketingu polega na płatnych reklamach docierających do osób szukających konkretnych usług turystycznych?","options":["SEO","SEM (np. Google Ads)","Newsletter","Blog"],"correct":1,"explain":"SEM (marketing w wyszukiwarkach) to płatne reklamy, np. Google Ads, docierające do osób szukających konkretnych usług turystycznych."},{"type":"abcd","q":"Co jest kluczowym celem e-marketingu w turystyce?","options":["Dotarcie do turystów w sposób atrakcyjny, spersonalizowany i mierzalny","Wyłącznie obniżenie kosztów drukowania ulotek","Zastąpienie pracowników biur podróży","Rezygnacja z analizy danych o klientach"],"correct":0,"explain":"Celem e-marketingu jest dotarcie do potencjalnych turystów i rekreantów w sposób atrakcyjny, spersonalizowany oraz mierzalny."},{"type":"tf","q":"Ograniczony, lokalny zasięg oferty to jedna z głównych zalet e-marketingu w turystyce.","correct":false,"explain":"Przeciwnie — atutem e-marketingu jest globalny zasięg i dostępność oferty 24/7, a nie ograniczenie do rynku lokalnego."},{"type":"flash","front":"Wymień co najmniej cztery narzędzia e-marketingu w turystyce.","back":"Strony internetowe i blogi, SEO, SEM (Google Ads), media społecznościowe, e-mail marketing, content marketing, mobile marketing oraz reklamy graficzne i wideo."}]},{"id":"rola-managera-w-turystyce","wiki":[{"heading":"Rola managera","body":"Manager w turystyce odgrywa kluczową rolę w zarządzaniu działalnością firm turystycznych, takich jak biura podróży, hotele i organizatorzy wycieczek. Jego główne zadania obejmują planowanie, organizowanie, kierowanie i kontrolowanie działań związanych z oferowaniem usług turystycznych."},{"heading":"Kluczowe obowiązki","bullets":["Zarządzanie zespołem - rekrutacja, motywowanie, przydzielanie zadań, monitorowanie","Planowanie i rozwój oferty turystycznej - tworzenie atrakcyjnych pakietów, analiza trendów rynkowych, wprowadzanie nowych produktów","Relacje z klientami - wysoka jakość obsługi, rozwiązywanie problemów, reagowanie na opinie","Marketing i promocja - opracowywanie strategii, wykorzystywanie narzędzi e-marketingu","Zarządzanie finansami - budżetowanie, kontrola kosztów, analiza wyników i działania korygujące","Współpraca z partnerami - kontakt z dostawcami usług (hotele, przewodnicy), budowanie relacji biznesowych","Zapewnienie zgodności z przepisami - przestrzeganie regulacji prawnych i monitorowanie ich zmian"]},{"body":"W dynamicznie zmieniającej się branży manager musi być elastyczny i otwarty na innowacje, aby spełniać oczekiwania klientów i sprostać wyzwaniom rynkowym."}],"questions":[{"type":"abcd","q":"Które zadanie należy do kluczowych obowiązków managera w turystyce?","options":["Osobiste oprowadzanie wszystkich wycieczek","Ignorowanie opinii klientów","Zakaz korzystania z e-marketingu","Zarządzanie zespołem: rekrutacja, motywowanie, przydzielanie zadań"],"correct":3,"explain":"Zarządzanie zespołem - rekrutacja, motywowanie, przydzielanie zadań i monitorowanie - to jeden z kluczowych obowiązków managera."},{"type":"tf","q":"W dynamicznie zmieniającej się branży turystycznej manager powinien być elastyczny i otwarty na innowacje.","correct":true,"explain":"Materiał wskazuje, że manager musi być elastyczny i otwarty na innowacje, aby sprostać oczekiwaniom klientów i wyzwaniom rynku."},{"type":"flash","front":"Wymień przykładowe obowiązki managera w turystyce.","back":"Zarządzanie zespołem, planowanie i rozwój oferty, relacje z klientami, marketing i promocja, zarządzanie finansami, współpraca z partnerami oraz zapewnienie zgodności z przepisami."}]},{"id":"badania-pierwotne-a-wtorne-rynku-turystycznego","wiki":[{"heading":"Badania pierwotne","body":"Polegają na zbieraniu nowych, niepublikowanych wcześniej danych bezpośrednio od źródła.","bullets":["Metody: wywiady indywidualne, ankiety i kwestionariusze, grupy fokusowe, obserwacje","Zalety: aktualność danych, dostosowanie do potrzeb badania, kontrola jakości","Wady: kosztowność, czasochłonność, wymagana infrastruktura i zasoby"]},{"heading":"Badania wtórne","body":"Polegają na analizie już istniejących danych, zebranych i opublikowanych wcześniej przez inne podmioty.","bullets":["Źródła: raporty branżowe, dane statystyczne urzędów, artykuły naukowe i publikacje, bazy danych","Zalety: oszczędność czasu i kosztów, szeroki zakres informacji, łatwość porównania danych historycznych","Wady: brak aktualności, ograniczona elastyczność (dane zebrane w innym celu), niepewna jakość"]},{"heading":"Najważniejsze różnice","body":"Oba podejścia różnią się metodologią zbierania danych, źródłami informacji oraz zastosowaniem. Pierwotne dają świeże, dopasowane dane kosztem czasu i pieniędzy; wtórne są tańsze i szybsze, lecz mniej aktualne i mniej elastyczne."}],"questions":[{"type":"abcd","q":"Co jest cechą badań pierwotnych rynku turystycznego?","options":["Zbieranie nowych, niepublikowanych danych bezpośrednio od źródła","Analiza danych opublikowanych wcześniej przez inne podmioty","Korzystanie wyłącznie z raportów branżowych","Brak możliwości dostosowania do potrzeb badania"],"correct":0,"explain":"Badania pierwotne polegają na zbieraniu nowych, niepublikowanych wcześniej danych bezpośrednio od źródła (np. ankiety, wywiady)."},{"type":"abcd","q":"Która z poniższych jest zaletą badań wtórnych?","options":["Pełna aktualność danych","Oszczędność czasu i kosztów","Możliwość bezpośredniej kontroli jakości zbierania danych","Pełne dostosowanie do potrzeb konkretnego badania"],"correct":1,"explain":"Zaletą badań wtórnych jest oszczędność czasu i kosztów, bo dane są już dostępne i nie trzeba zbierać ich od podstaw."},{"type":"tf","q":"Zaletą badań wtórnych jest zawsze pełna aktualność i pewna jakość danych.","correct":false,"explain":"To wada, nie zaleta — dane wtórne bywają nieaktualne i zebrane w innym celu, więc ich jakość jest niepewna."},{"type":"flash","front":"Czym różnią się badania pierwotne od wtórnych rynku turystycznego?","back":"Pierwotne to zbieranie nowych danych bezpośrednio od źródła (aktualne, dopasowane, ale drogie i czasochłonne); wtórne to analiza istniejących, opublikowanych danych (tańsze i szybsze, ale mniej aktualne i elastyczne)."}]},{"id":"znaczenie-kultury-w-turystyce","wiki":[{"body":"Kultura odgrywa kluczową rolę w turystyce - wpływa na motywację podróżnych i rozwój destynacji. Jest jednym z głównych czynników przyciągających turystów oraz kształtującym dla nich doświadczeniem."},{"heading":"Kultura jako atrakcja i doświadczenie","bullets":["Kultura jako atrakcja - wiele osób podróżuje, by poznać dziedzictwo kulturowe; popularne są zabytki, muzea, festiwale, sztuka, muzyka, tradycje","Kultura jako element doświadczenia - turystyka kulturowa pozwala poznawać nowe języki, zwyczaje i style życia; lokalne potrawy, rękodzieło i obyczaje czynią podróż bardziej autentyczną"]},{"heading":"Wpływ turystyki na kulturę lokalną","bullets":["Pozytywny - wspieranie zachowania i promocji dziedzictwa; dochody finansują renowację zabytków i wydarzenia kulturowe","Negatywny - konflikty społeczne, zanikanie autentyczności (kultura na pokaz), komercjalizacja pod turystów"]},{"heading":"Kultura a zrównoważona turystyka","bullets":["Ochrona lokalnych tradycji i dziedzictwa jest kluczowa dla zrównoważonego rozwoju","Edukacja turystów w zakresie poszanowania miejscowej kultury pomaga zachować jej unikalny charakter"]}],"questions":[{"type":"abcd","q":"Który przykład ilustruje kulturę jako atrakcję turystyczną?","options":["Darmowe wi-fi w hotelu","Transfer z lotniska","Zabytki, muzea, festiwale, sztuka i tradycje","Ubezpieczenie podróży"],"correct":2,"explain":"Popularne atrakcje kulturowe to zabytki, muzea, festiwale, sztuka, muzyka i tradycje - to one przyciągają turystów."},{"type":"tf","q":"Rozwój turystyki zawsze wzmacnia autentyczność kultury lokalnej i nie niesie żadnych zagrożeń.","correct":false,"explain":"Turystyka może też komercjalizować kulturę i osłabiać jej autentyczność (kultura „robi się na pokaz”) oraz wywoływać konflikty społeczne."},{"type":"flash","front":"Jakie znaczenie odgrywa kultura w turystyce?","back":"Jest atrakcją przyciągającą turystów (zabytki, festiwale, tradycje) i elementem doświadczenia (języki, potrawy, zwyczaje); turystyka wzajemnie wpływa na kulturę lokalną - wspiera dziedzictwo, ale może je komercjalizować. Ochrona tradycji i edukacja turystów wspierają zrównoważony rozwój."}]},{"id":"ocena-wydolnosci-fizycznej","wiki":[{"heading":"Czym jest wydolność fizyczna","body":"Wydolność fizyczna to zdolność organizmu do wykonywania wysiłku o określonej intensywności i czasie trwania bez nadmiernego zmęczenia oraz z możliwością szybkiej regeneracji. Ocenia się ją metodami laboratoryjnymi i terenowymi."},{"heading":"Metody laboratoryjne (bezpośrednie)","body":"Najdokładniejsze, prowadzone w warunkach kontrolowanych przy użyciu specjalistycznego sprzętu (bieżnia, cykloergometr).","bullets":["Pomiar VO2max - maksymalna ilość tlenu, jaką organizm może pobrać, przetransportować i zużyć; najlepszy wskaźnik wydolności tlenowej","Test progowy (próg mleczanowy) - ocena stężenia mleczanu we krwi przy rosnącej intensywności","Ergometria wysiłkowa - bieżnia, cykloergometr, ergometr wioślarski; ocena tętna, ciśnienia, EKG, poboru tlenu","CPET (sercowo-płucny test wysiłkowy), spirometria, EKG wysiłkowe"]},{"heading":"Testy terenowe i metody pośrednie","body":"Łatwiejsze i tańsze do przeprowadzenia; metody pośrednie szacują VO2max na podstawie reakcji tętna.","bullets":["Test Coopera - bieg przez 12 min, mierzony dystans; im większy, tym lepsza wydolność","Test Ruffiera - tętno przed wysiłkiem, po 30 przysiadach i po minucie odpoczynku","Test Astranda - cykloergometr, obciążenie submaksymalne, ocena na podstawie tętna","Test Harwardzki - wchodzenie i schodzenie ze stopnia, analiza szybkości powrotu tętna"]},{"heading":"Wydolność beztlenowa i ocena subiektywna","bullets":["Test Wingate - 30 s maksymalnego wysiłku na cykloergometrze; ocenia moc maksymalną, pojemność beztlenową i odporność na zmęczenie","Próg przemian beztlenowych - inwazyjnie (pomiar mleczanu), nieinwazyjnie (test Conconiego, próg wentylacji)","Skala Borga - subiektywna ocena odczuwanego zmęczenia podczas wysiłku"]}],"questions":[{"type":"abcd","q":"Który test polega na przebiegnięciu jak najdłuższego dystansu w ciągu 12 minut?","options":["Test Ruffiera","Test Astranda","Test Wingate","Test Coopera"],"correct":3,"explain":"Test Coopera to bieg przez 12 minut, w którym mierzy się pokonany dystans pozwalający oszacować VO2max."},{"type":"tf","q":"VO2max jest uznawany za najlepszy wskaźnik wydolności tlenowej.","correct":true,"explain":"VO2max określa największą ilość tlenu, jaką organizm może pobrać i zużyć, i jest najlepszym wskaźnikiem wydolności aerobowej."},{"type":"tf","q":"Test Wingate służy do oceny wydolności tlenowej (aerobowej).","correct":false,"explain":"Test Wingate (30 s maksymalnego wysiłku) ocenia wydolność beztlenową: moc maksymalną, pojemność beztlenową i odporność na zmęczenie."},{"type":"flash","front":"Wymień i scharakteryzuj sposoby oceny wydolności fizycznej.","back":"Metody laboratoryjne (VO2max, próg mleczanowy, ergometria, CPET); testy terenowe (Cooper, Ruffier, Astrand, Harwardzki); ocena parametrów fizjologicznych (tętno, ciśnienie, czas regeneracji); wydolność beztlenowa (test Wingate); ocena subiektywna (skala Borga)."}]},{"id":"typy-wykresow-dochod-firmy","wiki":[{"heading":"Typy wykresów","bullets":["Wykres kolumnowy (słupkowy) - przedstawia dochód jako pionowe lub poziome słupki, których wysokość odpowiada wartości w danym roku; czytelny, ułatwia porównanie danych","Wykres liniowy - prezentuje zmiany dochodu w czasie linią łączącą punkty z kolejnych lat; przydatny do analizy trendów, wzrostu lub spadku","Wykres kołowy (pierścieniowy) - pokazuje procentowy udział dochodu z każdego roku w dochodzie całkowitym; sprawdza się gdy chcemy zobrazować proporcje zamiast zmian w czasie"]}],"questions":[{"type":"abcd","q":"Który wykres jest najlepszy do analizy trendu wzrostu lub spadku dochodu w czasie?","options":["Wykres kołowy","Wykres liniowy","Wykres pierścieniowy","Wykres bąbelkowy"],"correct":1,"explain":"Wykres liniowy łączy punkty z kolejnych lat, dzięki czemu dobrze obrazuje trendy oraz wzrost i spadek dochodu."},{"type":"tf","q":"Wykres liniowy najlepiej nadaje się do pokazania procentowego udziału dochodów poszczególnych lat w dochodzie całkowitym.","correct":false,"explain":"Do proporcji (udziału w całości) służy wykres kołowy; wykres liniowy obrazuje zmiany wartości w czasie, a nie udziały procentowe."},{"type":"flash","front":"Wymień 3 typy wykresów do prezentacji dochodu firmy w 5 kolejnych latach.","back":"Wykres kolumnowy (słupkowy), wykres liniowy oraz wykres kołowy (pierścieniowy)."}]},{"id":"redukcja-stresu-rekreacja-turystyka","wiki":[{"heading":"Rekreacja i turystyka jako forma redukcji stresu","body":"Stres jest naturalną reakcją organizmu, ale jego nadmiar prowadzi do problemów zdrowotnych i psychicznych. Aktywność rekreacyjno-turystyczna umożliwia odpoczynek, regenerację i oderwanie od codziennych obowiązków.","bullets":["Aktywność fizyczna (spacery, pływanie, jazda na rowerze) obniża poziom kortyzolu i poprawia samopoczucie","Kontakt z naturą (góry, las, morze) działa uspokajająco i zmniejsza napięcie psychiczne","Zmiana otoczenia pozwala oderwać się od stresujących sytuacji","Społeczny aspekt turystyki (wyjazdy z rodziną, znajomymi) wzmacnia relacje międzyludzkie"]},{"heading":"Formy pomagające w redukcji stresu","bullets":["Rekreacja ruchowa - bieganie, joga, fitness, siłownia pobudzają wydzielanie endorfin","Turystyka wypoczynkowa - morze, uzdrowiska, spa - relaks i regeneracja","Turystyka aktywna - wędrówki górskie, kajakarstwo, nurkowanie wymagają skupienia","Turystyka kulturowa - muzea, koncerty, festiwale jako źródło przyjemności"]},{"heading":"Korzyści psychofizyczne","bullets":["Lepsza odporność na stres dzięki regularnej aktywności","Poprawa jakości snu - ruch na świeżym powietrzu wspomaga regenerację","Wzrost poziomu energii i motywacji"]}],"questions":[{"type":"abcd","q":"Jaki efekt fizjologiczny daje aktywność fizyczna w kontekście redukcji stresu?","options":["Podnosi poziom kortyzolu","Pogarsza jakość snu","Zwiększa napięcie psychiczne","Obniża poziom kortyzolu"],"correct":3,"explain":"Aktywność fizyczna obniża poziom kortyzolu (hormonu stresu) i poprawia samopoczucie."},{"type":"tf","q":"Kontakt z naturą podczas turystyki działa uspokajająco i zmniejsza napięcie psychiczne.","correct":true,"explain":"Przebywanie w górach, lesie czy nad morzem działa uspokajająco i redukuje napięcie psychiczne."},{"type":"flash","front":"Jakie korzyści psychofizyczne daje aktywność rekreacyjno-turystyczna?","back":"Lepsza odporność na stres, poprawa jakości snu (ruch na świeżym powietrzu wspomaga regenerację) oraz wzrost poziomu energii i motywacji."}]},{"id":"podzial-pozycji-wyjsciowych","wiki":[{"heading":"Podział podstawowy","bullets":["Pozycje wysokie - pozycje w staniu oraz we wspięciu (np. postawa, wykrok, rozkrok, wypady, pozycje wspięte)","Pozycje półwysokie - półprzysiady, przysiady, klęki (np. przysiad obunóż, klęk prosty, klęk podparty)","Pozycje niskie - siady, podpory, leżenia (np. siad prosty, siad skrzyżny, podpór leżąc, leżenie tyłem)"]},{"heading":"Pozycje specjalne","bullets":["Pozycje izolowane - ruch odbywa się w jednym stawie i angażuje jedną grupę mięśniową przy minimalnym udziale innych mięśni (np. pozycja w siadzie skrzyżnym)","Pozycje równoważne - wymagają współdziałania całego ciała i układu ruchowego w celu zachowania równowagi"]}],"questions":[{"type":"abcd","q":"Do której grupy pozycji wyjściowych zaliczamy siady, podpory i leżenia?","options":["Pozycje wysokie","Pozycje niskie","Pozycje półwysokie","Pozycje równoważne"],"correct":1,"explain":"Pozycje niskie obejmują siady, podpory i leżenia."},{"type":"tf","q":"Pozycje izolowane to takie, w których ruch odbywa się w wielu stawach jednocześnie i angażuje wiele grup mięśniowych.","correct":false,"explain":"Odwrotnie — w pozycjach izolowanych ruch odbywa się w jednym stawie i angażuje jedną grupę mięśniową; praca wielu stawów cechuje ćwiczenia złożone (wielostawowe)."},{"type":"flash","front":"Dokonaj podziału pozycji wyjściowych do ćwiczeń kształtujących.","back":"Pozycje wysokie (stanie, wspięcie), półwysokie (półprzysiady, przysiady, klęki), niskie (siady, podpory, leżenia), izolowane (ruch w jednym stawie) oraz równoważne (współdziałanie całego ciała dla zachowania równowagi)."}]},{"id":"funkcje-dysfunkcje-turystyki","wiki":[{"heading":"Funkcje turystyki","body":"Turystyka jako zjawisko społeczne i gospodarcze przyczynia się do rozwoju społecznego, kulturalnego i ekonomicznego.","bullets":["Wypoczynkowa - odpoczynek od obowiązków i regeneracja","Zdrowotna - poprawa stanu zdrowia turystów","Edukacyjna i kulturowa - poszerzanie wiedzy o kulturach, tradycjach, zwyczajach","Wychowawcza - rozwija odpowiedzialność i umiejętność współpracy w grupie","Ekonomiczna - generuje dochody, tworzy miejsca pracy, stymuluje lokalne gospodarki","Urbanistyczna/miastotwórcza, polityczna, etniczna oraz ekologiczna"]},{"heading":"Dysfunkcje turystyki","body":"Rozwój turystyki niesie również negatywne skutki dla środowiska i społeczeństwa.","bullets":["Przeludnienie popularnych miejsc - tłok, hałas, problemy z infrastrukturą","Wzrost cen towarów, usług i mieszkań uciążliwy dla mieszkańców","Uzależnienie lokalnej gospodarki od turystyki (wrażliwość na kryzysy)","Degradacja kultury - tradycje stają się pokazami dla turystów i tracą autentyczność","Zjawiska patologiczne (alkoholizm, prostytucja) oraz konflikty społeczne"]}],"questions":[{"type":"abcd","q":"Która z poniższych jest dysfunkcją, a nie funkcją turystyki?","options":["Funkcja zdrowotna","Funkcja edukacyjna","Degradacja kultury","Funkcja ekonomiczna"],"correct":2,"explain":"Degradacja kultury (utrata autentyczności tradycji) to dysfunkcja; pozostałe to funkcje turystyki."},{"type":"tf","q":"Uzależnienie lokalnej gospodarki wyłącznie od turystyki czyni ją wrażliwą na kryzysy.","correct":true,"explain":"Gdy gospodarka opiera się głównie na turystyce, kryzys może bardzo negatywnie wpłynąć na region - to dysfunkcja turystyki."},{"type":"flash","front":"Wymień funkcje współczesnej turystyki.","back":"Wypoczynkowa, zdrowotna, edukacyjna i kulturowa, wychowawcza, ekonomiczna, urbanistyczna/miastotwórcza, polityczna, etniczna i ekologiczna."}]},{"id":"trendy-tworzenia-stron-www","wiki":[{"heading":"Najważniejsze trendy","body":"Strony internetowe coraz bardziej skupiają się na wygodzie użytkownika, aby były łatwe, szybkie i przyjemne w obsłudze.","bullets":["Projektowanie z myślą o dostępności - zrozumiałe dla wszystkich, w tym osób z niepełnosprawnościami","Szybkość działania - użytkownicy oczekują szybkiego ładowania strony","Minimalistyczny wygląd z trybem ciemnym - większa czytelność, lepszy dla oczu, oszczędza baterię","Personalizacja i AI - chatboty, spersonalizowane rekomendacje, dynamiczne treści"]},{"heading":"Pozostałe trendy","bullets":["Efekty 3D i animacja - ruchome elementy przyciągające uwagę","Projektowanie mobile-first - najpierw smartfony, potem komputery","Prosta nawigacja i menu rozwijane (np. hamburger, menu pełnoekranowe)","Wysokiej jakości, autorskie materiały graficzne zamiast standardowych zdjęć","Powiadomienia push - z możliwością ich wyłączenia"]}],"questions":[{"type":"abcd","q":"Co oznacza podejście mobile-first przy tworzeniu stron internetowych?","options":["Tworzenie osobnej aplikacji zamiast strony","Strona dostępna tylko na komputerach","Rezygnacja z wersji mobilnej","Strona tworzona najpierw z myślą o smartfonach, a potem dopasowana do komputerów"],"correct":3,"explain":"Mobile-first oznacza projektowanie najpierw pod smartfony, a następnie dopasowanie do komputerów, bo coraz więcej osób przegląda internet przez telefon."},{"type":"tf","q":"Tryb ciemny jest obecnie popularnym trendem, ponieważ jest lepszy dla oczu i oszczędza baterię.","correct":true,"explain":"Minimalistyczny wygląd z trybem ciemnym poprawia czytelność, jest łagodniejszy dla oczu i oszczędza baterię."},{"type":"flash","front":"Wymień obecne trendy przy tworzeniu stron internetowych.","back":"Dostępność, szybkość działania, minimalizm z trybem ciemnym, personalizacja i AI, efekty 3D i animacje, mobile-first, prosta nawigacja (menu rozwijane), autorskie materiały graficzne, powiadomienia push."}]},{"id":"metody-badania-rynku-turystycznego","wiki":[{"heading":"Istota badań","body":"Badanie rynku turystycznego to proces zbierania informacji o konkurencji i turystach, ich potrzebach, zachowaniach i oczekiwaniach."},{"heading":"Badania ilościowe","body":"Celem jest uzyskanie konkretnych, liczbowych danych, które można analizować statystycznie.","bullets":["Ankiety i kwestionariusze (pytania zamknięte, skale ocen; online, telefonicznie, osobiście)","Badania opinii turystów (formularze oceny usług)","Badania popytu turystycznego (liczba turystów, cel podróży, długość pobytu, wydatki)","Zalety: duża próba, możliwość wnioskowania statystycznego. Wady: nie pokazują motywów i emocji turystów"]},{"heading":"Badania jakościowe","body":"Celem jest zrozumienie motywacji, potrzeb, opinii i zachowań turystów; dane opisowe, mniejsza liczba osób.","bullets":["Wywiady pogłębione - indywidualne rozmowy z uczestnikami rynku","Grupy fokusowe - dyskusje w małych grupach o usługach i preferencjach","Obserwacja uczestnicząca - badacz angażuje się w działanie grupy","Zalety: głębokie zrozumienie zachowań. Wady: trudne do uogólnienia, wymagają czasu i zasobów"]},{"heading":"Źródła danych","bullets":["Badania pierwotne - dane zbierane samodzielnie od respondentów (ankieta, wywiad, obserwacja)","Badania wtórne - wykorzystanie istniejących danych, raportów, statystyk i publikacji"]}],"questions":[{"type":"abcd","q":"Która metoda należy do badań jakościowych rynku turystycznego?","options":["Grupa fokusowa","Ankieta zamknięta","Analiza danych liczbowych ze statystyk","Badanie popytu turystycznego"],"correct":0,"explain":"Grupa fokusowa to badanie jakościowe; pozostałe wymienione to metody ilościowe."},{"type":"tf","q":"Badania wtórne polegają na samodzielnym zbieraniu nowych danych w terenie, np. przez ankiety.","correct":false,"explain":"To opis badań pierwotnych; badania wtórne opierają się na już istniejących danych, raportach i statystykach."},{"type":"flash","front":"Omów podstawowe metody i techniki badania rynku turystycznego.","back":"Badania ilościowe (ankiety, badania opinii i popytu - dane liczbowe) oraz jakościowe (wywiady pogłębione, grupy fokusowe, obserwacja uczestnicząca - zrozumienie motywacji). Obie grupy prowadzi się jako badania pierwotne (zbierane samodzielnie) lub wtórne (istniejące dane)."}]},{"id":"zalozenia-metodyczne-rekreacja","wiki":[{"heading":"Formy rekreacji fizycznej","body":"Założenie metodyczne to pomysł na to, jak poprowadzić zajęcia, by osiągnąć cel. Formy to rodzaje zajęć ruchowych poprawiających kondycję, zdrowie, samopoczucie i integrację.","bullets":["Formy organizacyjne: indywidualna (jogging), zespołowe (siatkówka), grupowe (fitness, taniec), masowe (biegi uliczne)","Formy dydaktyczne: zabawowa, naśladowcza, zadaniowa, improwizacyjna, ścisła, programowa, współzawodnictwo"]},{"heading":"Metody działania instruktora","bullets":["Metody nauczania czynności ruchowych: poglądowa (pokaz), słowa (objaśnienia), praktyczna (wykonywanie ćwiczeń)","Metody treningowe ciągłe: jednostajna (stała intensywność), zmienna (zmiana tempa)","Metody treningowe przerywane: interwałowa, powtórzeniowa, ekstensywna, intensywna","Metody socjotechniczne: informacyjna, poradnictwo, animacja, programowanie","Metody wychowawcze: wpływu osobistego, sytuacyjnego, społecznego, kierowania samowychowaniem"]},{"heading":"Środki w rekreacji fizycznej","body":"Narzędzia uatrakcyjniające i ułatwiające zajęcia.","bullets":["Sprzęt sportowy, muzyka, przestrzeń","Przyrządy intensyfikujące - hantle, stepy","Metody intensyfikacji - praca w parach, zmiany tempa, dodatkowe powtórzenia"]},{"heading":"Zasady metodyczne (dydaktyczne)","bullets":["Świadomość i aktywność - uczestnik wie po co ćwiczy i chce to robić","Systematyczność","Dostępność - dostosowanie do wieku i możliwości","Utrwalenie - powtarzanie dla lepszego zapamiętania","Wszechstronność - rozwój siły, wytrzymałości i zręczności"]}],"questions":[{"type":"abcd","q":"Do której grupy zalicza się metoda jednostajna i zmienna?","options":["Metody nauczania czynności ruchowych","Metody wychowawcze","Metody socjotechniczne","Metody treningowe ciągłe"],"correct":3,"explain":"Metoda jednostajna (stała intensywność) i zmienna (zmiana tempa) to metody treningowe ciągłe."},{"type":"tf","q":"Zasada dostępności oznacza dostosowanie zajęć do wieku i możliwości uczestników.","correct":true,"explain":"Zasada dostępności wymaga, by zajęcia były dostosowane do wieku i możliwości ćwiczących."},{"type":"flash","front":"Wymień metody działania instruktora rekreacji.","back":"Metody nauczania czynności ruchowych (poglądowa, słowa, praktyczna), metody treningowe (ciągłe: jednostajna, zmienna; przerywane: interwałowa, powtórzeniowa, ekstensywna, intensywna), metody socjotechniczne (informacyjna, poradnictwo, animacja, programowanie) oraz metody wychowawcze (wpływu osobistego, sytuacyjnego, społecznego, kierowania samowychowaniem)."}]},{"id":"uniwersalne-zasady-sporzadzania-listu","wiki":[{"heading":"Uklad listu","body":"Poprawnie sporzadzony list ma stala, logiczna strukture, ktora porzadkuje przekaz.","bullets":["Naglowek - dane nadawcy oraz data","Adresat - imie, nazwisko lub nazwa firmy i adres","Zwrot grzecznosciowy - formalny (Szanowna Pani) lub nieformalny (Droga Anno, czesc)","Tresc - logiczna, podzielona na akapity, jasna i poprawna","Zakonczenie - podsumowanie, prosba o odpowiedz lub podziekowanie","Zwrot koncowy i podpis - formalny (Z wyrazami szacunku) lub nieformalny (pozdrawiam serdecznie)"]},{"heading":"Styl i jezyk","bullets":["Dostosowanie do odbiorcy - styl formalny lub nieformalny","Jasnosc i zwiezlosc - unikamy dygresji, mowimy konkretnie","Poprawnosc jezykowa - brak bledow ortograficznych i stylistycznych","Uprzejmosc - nawet w skargach zachowujemy uprzejmy i rzeczowy ton"]},{"heading":"Rodzaje listow","bullets":["Formalny - do urzedow i firm, oficjalny styl (list motywacyjny, reklamacje)","Nieformalny - do znajomych i rodziny, swobodny styl","Biznesowy - elementy formalne, ale bardziej elastyczny ton (oferta, podziekowania dla klienta)"]}],"questions":[{"type":"abcd","q":"Ktory element listu zawiera dane nadawcy oraz date?","options":["Adresat","Naglowek","Zwrot koncowy","Tresc"],"correct":1,"explain":"Naglowek listu zawiera dane nadawcy plus date."},{"type":"tf","q":"Nawet w listach ze skarga nalezy zachowac uprzejmy i rzeczowy ton.","correct":true,"explain":"Uprzejmosc to jedna z zasad stylu - obowiazuje takze w skargach."},{"type":"flash","front":"Wymien rodzaje listow.","back":"Formalny (urzedy, firmy), nieformalny (znajomi, rodzina) oraz biznesowy (elementy formalne, lecz bardziej elastyczny ton)."}]},{"id":"bariery-komunikacji-miedzykulturowej","wiki":[{"heading":"Cechy charakteru utrudniajace komunikacje","bullets":["Egocentryzm - skupienie na sobie utrudnia dostrzeganie odmiennych sposobow wyrazania mysli, emocji i wartosci","Brak empatii - niezdolnosc do postawienia sie w sytuacji drugiej osoby ogranicza rozumienie jej perspektywy kulturowej","Niskie umiejetnosci spoleczne - trudnosci w nawiazywaniu relacji i adaptacji do nowych sytuacji kulturowych","Zamkniecie na zmiany - przywiazanie do jedynie slusznych norm utrudnia adaptacje do nowych kontekstow kulturowych"]},{"heading":"Bariery wewnetrzne","bullets":["Lek i niepewnosc - obawa przed niezrozumieniem lub byciem ocenianym prowadzi do wycofania z komunikacji","Stereotypy i uprzedzenia - automatyczne przypisywanie cech osobom z danej kultury prowadzi do bledow i konfliktow","Szok kulturowy - intensywne przezycia w nowej kulturze moga wywolac frustracje, lek i odrzucenie odmiennych norm","Brak samoswiadomosci i tozsamosci kulturowej - nieznajomosc wlasnych uwarunkowan utrudnia zrozumienie roznic","Etnocentryzm - przekonanie, ze wlasna kultura jest lepsza","Nietolerancja oraz brak kompetencji kulturowych"]}],"questions":[{"type":"abcd","q":"Jak nazywa sie przekonanie, ze wlasna kultura jest lepsza od innych?","options":["Etnocentryzm","Egocentryzm","Empatia","Sensualizm"],"correct":0,"explain":"Etnocentryzm to przekonanie o wyzszosci wlasnej kultury - bariera komunikacji miedzykulturowej."},{"type":"tf","q":"Brak empatii ulatwia zrozumienie perspektywy kulturowej drugiej osoby.","correct":false,"explain":"Przeciwnie - brak empatii ogranicza zrozumienie perspektywy kulturowej innej osoby."},{"type":"flash","front":"Czym jest szok kulturowy jako bariera komunikacji?","back":"Intensywne przezycia zwiazane z wejsciem w nowa kulture, ktore moga wywolac frustracje, lek i odrzucenie odmiennych norm."}]},{"id":"pozytywne-skutki-wielkich-odkryc-geograficznych","wiki":[{"heading":"Czym byly Wielkie Odkrycia Geograficzne","body":"Epoka Wielkich Odkryc Geograficznych (XV-XVII wiek) to okres dalekich wypraw morskich Europejczykow w celu poznania nowych ladow i znalezienia nowych szlakow handlowych. Najwazniejsi odkrywcy to m.in. Krzysztof Kolumb, Vasco da Gama oraz Ferdynand Magellan."},{"heading":"Wiedza, nauka i nawigacja","bullets":["Poznanie nowych kontynentow i oceanow oraz dokladniejsze mapowanie swiata","Udowodnienie mozliwosci oplyniecia Ziemi","Rozwoj kartografii, geografii i astronomii","Doskonalenie instrumentow nawigacyjnych (kompas, astrolabium) i budowy statkow"]},{"heading":"Gospodarka i wymiana","bullets":["Powstanie nowych szlakow handlowych laczacych Europe, Afryke, Azje i Ameryke","Rozwoj portow, miast handlowych i transportu morskiego","Wymiana kolumbijska - do Europy trafily ziemniaki, kukurydza, pomidory, kakao i tyton; do Ameryki konie, bydlo, pszenica i trzcina cukrowa","Wzrost produkcji zywnosci, ograniczenie glodu i wzrost liczby ludnosci","Pobudzenie kapitalizmu handlowego, bankowosci i podstaw gospodarki globalnej"]},{"heading":"Kontakty miedzykulturowe","body":"Mimo licznych konfliktow doszlo do poznawania nowych kultur i tradycji, wymiany wiedzy i doswiadczen oraz wzrostu zainteresowania roznorodnoscia swiata. Dzieki odkryciom swiat stal sie bardziej polaczony gospodarczo, kulturowo i komunikacyjnie, co stworzylo podstawy wspolczesnej globalizacji."}],"questions":[{"type":"abcd","q":"Ktore rosliny w ramach tzw. wymiany kolumbijskiej trafily do Europy?","options":["Pszenica i trzcina cukrowa","Len i konopie","Ryz i jeczmien","Ziemniaki i kukurydza"],"correct":3,"explain":"Do Europy trafily m.in. ziemniaki, kukurydza, pomidory, kakao i tyton; pszenice i trzcine cukrowa przywieziono do Ameryki."},{"type":"tf","q":"Wielkie odkrycia geograficzne przyczynily sie do rozwoju kapitalizmu handlowego i podstaw gospodarki globalnej.","correct":true,"explain":"Odkrycia pobudzily kapitalizm handlowy, bankowosc i stworzyly podstawy gospodarki globalnej."},{"type":"flash","front":"Wymien trzech najwazniejszych odkrywcow Epoki Wielkich Odkryc Geograficznych.","back":"Krzysztof Kolumb, Vasco da Gama oraz Ferdynand Magellan."}]},{"id":"zasady-zachowania-zdrowia","wiki":[{"heading":"Czym jest zdrowie","body":"Zdrowie to pelny dobrostan fizyczny, psychiczny i spoleczny, a nie tylko brak choroby lub niepelnosprawnosci. Czlowiek zdrowy nie tylko nie choruje, ale tez dobrze sie czuje, ma energie, sprawnie funkcjonuje w spoleczenstwie i radzi sobie z codziennymi wyzwaniami."},{"heading":"Glowne zasady","bullets":["Zdrowe odzywianie - warzywa i owoce, unikanie fast foodow, slodyczy i nadmiaru soli, picie 1,5-2 l wody dziennie, regularne posilki (3-5 razy dziennie)","Sen i odpoczynek - 7-9 h snu dla doroslych, 8-10 h dla mlodziezy; sen wspomaga regeneracje i zdrowie psychiczne","Aktywnosc fizyczna - co najmniej 30 min dziennie; poprawia krazenie, odpornosc, nastroj i kondycje","Unikanie uzywek - alkohol, papierosy i inne srodki szkodza zdrowiu fizycznemu i psychicznemu","Higiena osobista - mycie rak, codzienna kapiel, czyste ubrania, dbanie o otoczenie","Zdrowie psychiczne - radzenie sobie ze stresem, wspierajace relacje, rozwijanie pasji","Profilaktyka zdrowotna - regularne wizyty u lekarza i stomatologa, badania okresowe, szczepienia ochronne"]}],"questions":[{"type":"abcd","q":"Ile wody dziennie zaleca sie wypijac w ramach zdrowego odzywiania?","options":["okolo 1,5-2 l","okolo 0,5 l","okolo 3-4 l","okolo 5 l"],"correct":0,"explain":"Zaleca sie picie okolo 1,5-2 l wody dziennie."},{"type":"tf","q":"Doroslym zaleca sie 4-5 godzin snu na dobe.","correct":false,"explain":"Zalecane jest 7-9 h snu dla doroslych (a dla mlodziezy 8-10 h); 4-5 h to zbyt malo dla zdrowia."},{"type":"flash","front":"Podaj minimalna dzienna dawke aktywnosci fizycznej wedlug zasad zachowania zdrowia.","back":"Co najmniej 30 minut dziennie (np. spacer, jazda na rowerze, plywanie, taniec)."}]},{"id":"zrodla-informacji-geograficzno-turystycznej-mapy","wiki":[{"heading":"Zrodla informacji geograficzno-turystycznej","bullets":["Mapy i atlasy turystyczne - ukształtowanie terenu, szlaki, obiekty przyrodnicze i kulturowe","Przewodniki turystyczne - opisy atrakcji, szlakow, propozycje tras, informacje praktyczne","Informatory i foldery - krotkie broszury promujace region, wydarzenia i miejsca","Internet - strony, blogi podroznicze, aplikacje (Google Maps, Booking, TripAdvisor)","Lokalne centra informacji turystycznej - aktualne dane i materialy promocyjne","Filmy dokumentalne i programy podroznicze - krajobraz, kultura i przyroda","Dane statystyczne i raporty - ruch turystyczny, liczba turystow, wplyw na srodowisko"]},{"heading":"Znaczenie map w badaniach srodowiska geograficznego","bullets":["Orientacja w terenie - planowanie trasy, polozenie atrakcji, wyznaczenie kierunku","Analiza srodowiska - mapy topograficzne, klimatyczne i hydrograficzne pozwalaja badac cechy srodowiska","Bezpieczenstwo - unikanie trudnych lub niebezpiecznych terenow, szczegolnie w gorach i lasach","Planowanie infrastruktury - projektowanie szlakow pieszych, rowerowych, miejsc wypoczynkowych","Lokalizacja atrakcji i infrastruktury - rozmieszczenie hoteli, restauracji, zabytkow"]},{"heading":"Znaczenie map w dzialalnosci turystyczno-rekreacyjnej","bullets":["Ulatwiaja nawigacje, szczegolnie w gorach, lasach i terenach nieznanych","Pomagaja odkryc nowe, mniej znane atrakcje","Wspieraja rozwoj ekoturystyki - tworzenie tras zgodnych z ochrona przyrody","Pomagaja w promocji regionow - sa uzywane w kampaniach informacyjnych i marketingowych"]}],"questions":[{"type":"abcd","q":"Ktory rodzaj map sluzy do badania cech srodowiska przyrodniczego?","options":["Mapy polityczne","Mapy topograficzne, klimatyczne i hydrograficzne","Mapy administracyjne","Mapy drogowe miast"],"correct":1,"explain":"Mapy tematyczne - topograficzne, klimatyczne i hydrograficzne - pozwalaja badac cechy srodowiska przyrodniczego."},{"type":"tf","q":"Lokalne centra informacji turystycznej sa jednym ze zrodel informacji geograficzno-turystycznej.","correct":true,"explain":"Lokalne centra informacji turystycznej dostarczaja aktualne dane i materialy promocyjne."},{"type":"flash","front":"Wymien co najmniej trzy zrodla informacji geograficzno-turystycznej.","back":"M.in. mapy i atlasy, przewodniki turystyczne, informatory i foldery, Internet, lokalne centra informacji turystycznej, filmy dokumentalne, dane statystyczne i raporty."}]},{"id":"wartosci-zdrowotne-gier-terenowych-bieg-na-orientacje","wiki":[{"heading":"Przyklad: bieg na orientacje","body":"Bieg na orientacje to popularna na calym swiecie gra sportowo-rekreacyjna, polegajaca na odnalezieniu wyznaczonych punktow kontrolnych w terenie przy pomocy mapy i kompasu. Moze byc rozgrywana indywidualnie lub w zespolach - w lesie, parku, gorach czy terenie miejskim."},{"heading":"Wartosci zdrowotne","bullets":["Rozwijanie kondycji fizycznej - bieganie lub szybki marsz w zroznicowanym terenie","Poprawa wydolnosci oddechowo-krazeniowej, sily i koordynacji","Dotlenienie organizmu - aktywnosc na swiezym powietrzu","Zmniejszenie stresu i napiecia psychicznego - kontakt z natura dziala uspokajajaco"]},{"heading":"Wartosci edukacyjne","bullets":["Nauka orientacji w terenie","Myslenie przestrzenne i szybkie podejmowanie decyzji","Poznawanie srodowiska geograficznego i przyrodniczego","Samodzielnosc i odpowiedzialnosc - uczestnik sam planuje trase i tempo"]},{"heading":"Wielostronne oddzialywanie na organizm","bullets":["Fizyczne - poprawa sprawnosci ogolnej, rownowagi i refleksu","Psychiczne - rozwoj koncentracji, logicznego myslenia i odpornosci na stres","Spoleczne - integracja w grupie i zdrowa rywalizacja (w wersjach druzynowych)","Emocjonalne - poczucie przygody, adrenalina, satysfakcja z ukonczenia trasy"]}],"questions":[{"type":"abcd","q":"Za pomoca jakich narzedzi rekreant odnajduje punkty kontrolne w biegu na orientacje?","options":["Telefonu i zegarka","Lornetki i busoli satelitarnej","Mapy i kompasu","Wylacznie znakow szlaku"],"correct":2,"explain":"Bieg na orientacje polega na odnalezieniu punktow kontrolnych przy pomocy mapy i kompasu."},{"type":"tf","q":"Bieg na orientacje moze byc rozgrywany wylacznie indywidualnie.","correct":false,"explain":"Moze byc rozgrywany indywidualnie lub w zespolach, w roznych typach terenu."},{"type":"flash","front":"Wymien obszary wielostronnego oddzialywania biegu na orientacje na organizm.","back":"Fizyczne, psychiczne, spoleczne oraz emocjonalne."}]},{"id":"epoki-historyczne-chronologicznie","wiki":[{"heading":"Od prehistorii do starozytnosci","bullets":["Prehistoria (do ok. 4000-3500 p.n.e.) - rewolucja neolityczna, malarstwo jaskiniowe (Lascaux, Altamira), wenus paleolityczne, architektura megalityczna (Stonehenge)","Starozytnosc (do 476 n.e.) - wynalezienie pisma, demokracja i filozofia w Grecji, prawo rzymskie; piramidy w Gizie, greckie porzadki architektoniczne, rzymski beton (Panteon, Koloseum)"]},{"heading":"Sredniowiecze, renesans, barok","bullets":["Sredniowiecze (476-1453/1492) - teocentryzm, scholastyka, pierwsze uniwersytety; styl romanski i gotycki (sklepienie krzyzowo-zebrowe, witraze)","Renesans (XV-XVI w.) - humanizm i antropocentryzm, druk Gutenberga, heliocentryzm Kopernika; perspektywa linearna, Leonardo da Vinci, Michal Aniol, Rafael","Barok (koniec XVI - polowa XVIII w.) - kontrreformacja, dynamizm i swiatlocien (Caravaggio), opera Monteverdiego, Bernini, Rembrandt, Rubens"]},{"heading":"Oswiecenie, romantyzm, pozytywizm","bullets":["Oswiecenie (XVIII w.) - \"wiek rozumu\", racjonalizm, Wielka Rewolucja Francuska (1789); rokoko i klasycyzm, Mozart, Haydn, bajki Krasickiego","Romantyzm (koniec XVIII - polowa XIX w.) - bunt przeciw racjonalizmowi, kult jednostki, mesjanizm; Mickiewicz, Slowacki, Chopin, neogotyk","Pozytywizm i realizm (2. polowa XIX w.) - scjentyzm, ewolucjonizm, praca u podstaw; powiesc realistyczna (Prus, Sienkiewicz), narodziny impresjonizmu (Monet)"]},{"heading":"Modernizm i wspolczesnosc","bullets":["Przelom wiekow / Mloda Polska (ok. 1890-1918) - dekadentyzm, Nietzsche, psychoanaliza Freuda; symbolizm, secesja (Klimt, Mucha)","Dwudziestolecie miedzywojenne (1918-1939) - awangarda: kubizm, futuryzm, dadaizm, surrealizm, abstrakcjonizm; funkcjonalizm (Bauhaus)","Wspolczesnosc (od 1939) - kryzys humanizmu, rewolucja cyfrowa, postmodernizm; pop-art (Warhol), konceptualizm, happening i performance"]}],"questions":[{"type":"abcd","q":"Ktora epoka nazywana jest \"wiekiem rozumu\" i wiaze sie z Wielka Rewolucja Francuska?","options":["Oswiecenie","Barok","Renesans","Romantyzm"],"correct":0,"explain":"Oswiecenie (XVIII w.) nazywano \"wiekiem rozumu\"; doprowadzilo m.in. do Wielkiej Rewolucji Francuskiej (1789)."},{"type":"tf","q":"Cecha charakterystyczna sredniowiecza byl antropocentryzm.","correct":false,"explain":"Sredniowiecze cechowal teocentryzm (Bog osrodkiem wszystkiego); antropocentryzm — czlowiek w centrum — to cecha renesansu."},{"type":"flash","front":"Wymien chronologicznie epoki od renesansu do dwudziestolecia miedzywojennego.","back":"Renesans, barok, oswiecenie, romantyzm, pozytywizm i realizm, Mloda Polska (modernizm), dwudziestolecie miedzywojenne."}]},{"id":"rekreacyjne-rodzaje-koszykowki","wiki":[{"heading":"Wprowadzenie","body":"Koszykowka to dynamiczna gra zespolowa, ktora doczekala sie wielu rekreacyjnych odmian. Ich celem jest uproszczenie zasad, zwiekszenie dostepnosci oraz umozliwienie gry w mniejszych grupach i na ograniczonej przestrzeni."},{"heading":"Streetball (koszykowka uliczna 3x3)","bullets":["Najbardziej znana rekreacyjna odmiana koszykowki","Gra najczesciej na polowie boiska","Zespoly po 3 zawodnikow na boisku (moga byc rezerwowi)","Gra do 21 punktow lub przez okreslony czas","Rzut z dystansu (zza luku 6,75 m) za 2 punkty, inne rzuty 1 punkt","Po zdobyciu punktu druzyna przeciwna wyprowadza pilke z linii za lukiem","Gra jest bardziej dynamiczna i mniej formalna niz tradycyjna koszykowka"]},{"heading":"Koszykowka 1x1","bullets":["Gra indywidualna - jeden zawodnik przeciwko drugiemu","Skupienie na technice i umiejetnosciach indywidualnych","Gra do okreslonej liczby punktow","Mozliwe zasady: \"kto zdobywa punkt, ten zostaje z pilka\" lub zamiana","Rzuty punktowane wedlug ustalen graczy (1 lub 2 pkt)"]},{"heading":"Horse (gra w konia)","bullets":["Gra polega na nasladowaniu ruchow przeciwnika","Idealna dla dwoch lub wiecej graczy","Pierwszy gracz wykonuje dowolny rzut","Kto nie trafi, dostaje kolejna litere ze slowa HORSE","Przegrywa gracz, ktory pierwszy uzbiera cale slowo"]}],"questions":[{"type":"abcd","q":"Ilu zawodnikow gra na boisku w jednej druzynie w streetballu?","options":["2","4","3","5"],"correct":2,"explain":"Streetball to koszykowka 3x3 - po 3 zawodnikow na boisku w kazdej druzynie."},{"type":"tf","q":"W grze Horse przegrywa gracz, ktory jako pierwszy uzbiera cale slowo HORSE.","correct":true,"explain":"Za kazdy nietrafiony rzut gracz dostaje litere; przegrywa ten, kto pierwszy uzbiera cale slowo HORSE."},{"type":"flash","front":"Wymien trzy podstawowe rekreacyjne rodzaje koszykowki.","back":"Streetball (3x3), koszykowka 1x1 oraz Horse (gra w konia)."}]},{"id":"globalizacja-turystyka","wiki":[{"heading":"Czym jest globalizacja","body":"Globalizacja to proces postępującego zbliżania się społeczeństw i gospodarek świata w wyniku rozwoju technologii, transportu, komunikacji i międzynarodowej współpracy. Obejmuje m.in. swobodny przepływ ludzi, towarów, informacji, kapitału i usług."},{"heading":"Globalizacja w turystyce","bullets":["Zwiększenie dostępności podróży (tanie loty, internetowe biura podróży)","Rozszerzenie oferty turystycznej na cały świat (egzotyka, nowe kierunki)","Wzrost liczby podróży międzynarodowych (turystyka masowa i indywidualna)","Standaryzacja stylów życia i oczekiwań turystów (np. all inclusive)","Rozwój globalnych marek (TUI, Booking) i rezerwacji online"]},{"heading":"Globalizacja w hotelarstwie","bullets":["Powstawanie sieci hotelowych działających globalnie (Marriott, Hilton)","Standaryzacja usług i wyposażenia hoteli na całym świecie","Wzrost konkurencji i dostępu do informacji (portale z recenzjami)","Automatyzacja usług (check-in online)"]},{"heading":"Globalizacja w rekreacji","bullets":["Wymiana form rekreacyjnych między krajami (joga, fitness, sporty ekstremalne)","Rozwój globalnych wydarzeń sportowo-rekreacyjnych (maratony, festiwale)","Nowe technologie rekreacyjne dostępne globalnie (aplikacje terenowe, fitness)","Wzrost znaczenia zdrowego stylu życia"]}],"questions":[{"type":"abcd","q":"Który przykład najlepiej ilustruje globalizację w hotelarstwie?","options":["Lokalna gospoda serwująca tylko dania regionalne","Powstawanie globalnych sieci hotelowych jak Marriott czy Hilton","Spadek liczby podróży międzynarodowych","Zanik standaryzacji usług hotelowych"],"correct":1,"explain":"Globalizacja w hotelarstwie objawia się m.in. powstawaniem sieci hotelowych działających w wielu krajach (Marriott, Hilton)."},{"type":"tf","q":"Globalizacja w turystyce zwiększa dostępność podróży dzięki tanim lotom i internetowym biurom podróży.","correct":true,"explain":"To jeden z głównych przejawów globalizacji w turystyce wymienionych w materiale."},{"type":"flash","front":"Wymień przejawy globalizacji w rekreacji.","back":"Wymiana form rekreacyjnych między krajami (joga, fitness), rozwój globalnych wydarzeń sportowo-rekreacyjnych, globalnie dostępne technologie rekreacyjne oraz wzrost znaczenia zdrowego stylu życia."}]},{"id":"rynek-turystyczny-elementy","wiki":[{"heading":"Pojęcie rynku turystycznego","body":"Rynek turystyczny to system, w którym współpracują ze sobą firmy oferujące usługi turystyczne (biura podróży, hotele, linie lotnicze) z turystami będącymi ich konsumentami. Jego celem jest wymiana dóbr i usług związanych z podróżowaniem, wypoczynkiem i rekreacją."},{"heading":"Popyt turystyczny","body":"Popyt turystyczny to chęć i możliwość ludzi do zakupu usług turystycznych.","bullets":["Dochody ludności (im wyższe, tym większy popyt)","Czas wolny (urlopy, ferie, wakacje)","Moda i trendy (podróże egzotyczne, city break)","Czynniki psychologiczne i społeczne (potrzeba odpoczynku, prestiż)","Sytuacja polityczna i bezpieczeństwo"]},{"heading":"Podaż turystyczna","body":"Podaż turystyczna to wszystkie dobra i usługi oferowane turystom: miejsca noclegowe, transport, usługi gastronomiczne, atrakcje turystyczne, usługi organizacyjne.","bullets":["Sezonowość (większa podaż w sezonie letnim)","Zróżnicowanie jakościowe i cenowe","Ograniczona elastyczność (trudno szybko zwiększyć liczbę miejsc w hotelu czy samolocie)"]},{"heading":"Cena usług turystycznych","body":"Cena to wartość, jaką turysta płaci za usługę. Wpływ na nią mają: relacja popytu i podaży, sezon turystyczny (szczyt sezonu = drożej), standard i jakość usług, lokalizacja oraz polityka cenowa organizatora (last minute, first minute, promocje)."}],"questions":[{"type":"abcd","q":"Który czynnik NIE należy do czynników wpływających na popyt turystyczny?","options":["Dochody ludności","Czas wolny","Sezonowość podaży miejsc noclegowych","Moda i trendy"],"correct":2,"explain":"Sezonowość jest cechą podaży turystycznej, a nie czynnikiem popytu. Popyt zależy m.in. od dochodów, czasu wolnego oraz mody i trendów."},{"type":"tf","q":"Podaż turystyczna charakteryzuje się bardzo dużą elastycznością, bo usługi można natychmiast dostosować do popytu.","correct":false,"explain":"Przeciwnie — podaż turystyczna jest mało elastyczna w krótkim czasie; liczby miejsc w hotelu czy samolocie nie da się szybko zwiększyć."},{"type":"flash","front":"Wymień trzy podstawowe elementy rynku turystycznego.","back":"Popyt turystyczny, podaż turystyczna oraz cena usług turystycznych."}]},{"id":"ekonomiczne-znaczenie-turystyki","wiki":[{"heading":"Rola w gospodarce","body":"Turystyka i rekreacja odgrywają ważną rolę w gospodarce, wpływając na różne sektory i poziomy życia społeczno-gospodarczego."},{"heading":"Główne funkcje ekonomiczne","bullets":["Źródło dochodów dla gospodarki (usługi, podatki) - np. Hiszpania, Tajlandia","Tworzenie miejsc pracy, w tym sezonowych i okazjonalnych","Wspieranie lokalnych społeczności (rzemiosło, rolnictwo, agroturystyka)","Pobudzanie inwestycji i modernizacja infrastruktury (drogi, lotniska, dworce)","Zróżnicowanie gospodarki - alternatywa dla przemysłu lub rolnictwa","Poprawa bilansu płatniczego dzięki wpływom z turystyki zagranicznej","Rozwój rekreacji jako sektora usług (siłownie, spa, aquaparki)"]},{"heading":"Wpływ na bilans płatniczy","body":"Wpływy z turystyki zagranicznej poprawiają saldo eksportu usług - turyści zostawiają pieniądze w odwiedzanym kraju, a turyści krajowi wspierają rodzimy rynek usług."}],"questions":[{"type":"abcd","q":"W jaki sposób turystyka zagraniczna wpływa na bilans płatniczy państwa?","options":["Poprawia saldo eksportu usług, bo turyści zostawiają pieniądze w kraju","Pogarsza saldo, bo turyści wywożą pieniądze za granicę","Nie ma żadnego wpływu na bilans płatniczy","Zwiększa wyłącznie import towarów"],"correct":0,"explain":"Wpływy z turystyki zagranicznej poprawiają saldo eksportu usług, ponieważ turyści wydają pieniądze w odwiedzanym kraju."},{"type":"tf","q":"Turystyka może być alternatywą dla przemysłu lub rolnictwa, zwłaszcza w regionach górskich i nadmorskich.","correct":true,"explain":"Turystyka różnicuje gospodarkę i pomaga regionom uniezależnić się od jednego sektora."},{"type":"flash","front":"Podaj główne funkcje ekonomiczne turystyki i rekreacji.","back":"Źródło dochodów, tworzenie miejsc pracy, wspieranie lokalnych społeczności, pobudzanie inwestycji, zróżnicowanie gospodarki, poprawa bilansu płatniczego oraz rozwój rekreacji jako sektora usług."}]},{"id":"wirtualna-rzeczywistosc-turystyka","wiki":[{"heading":"Czym jest VR","body":"Wirtualna rzeczywistość (VR) to technologia, która pozwala użytkownikowi przenieść się do wygenerowanego świata - odwzorowującego rzeczywistość lub całkowicie fikcyjnego. Dzięki goglom VR, kontrolerom ruchu i sensorom użytkownik może oglądać, poruszać się i wchodzić w interakcje z tym światem w sposób realistyczny."},{"heading":"VR w turystyce","bullets":["Wirtualne wycieczki po atrakcjach (muzea, miasta, zabytki)","Wirtualna prezentacja hoteli i kurortów przed rezerwacją (spacery po pokojach)","Reklama i marketing turystyczny regionów i państw (np. Visit Dubai VR)"]},{"heading":"VR w rekreacji","bullets":["Wirtualny trening i ćwiczenia (FitXR, Supernatural - boks, taniec, joga)","Symulatory sportowe (narty, wspinaczka, golf, pływanie)","Gry i zabawy rekreacyjne w centrach VR (strzelnica, escape room, wyścigi)"]}],"questions":[{"type":"abcd","q":"Który z poniższych to przykład wykorzystania VR w turystyce?","options":["Drukowanie papierowych folderów reklamowych","Wirtualny spacer po pokojach hotelu przed rezerwacją","Tradycyjna wycieczka autokarowa","Telefoniczna rezerwacja noclegu"],"correct":1,"explain":"Hotele i biura podróży udostępniają wirtualne spacery po pokojach i kurortach przed rezerwacją - to typowe zastosowanie VR w turystyce."},{"type":"tf","q":"VR umożliwia użytkownikowi interakcję z wygenerowanym światem dzięki goglom, kontrolerom ruchu i sensorom.","correct":true,"explain":"To podstawowa charakterystyka technologii VR opisana w materiale."},{"type":"flash","front":"Podaj trzy zastosowania VR w turystyce.","back":"Wirtualne wycieczki po atrakcjach (muzea, zabytki), wirtualna prezentacja hoteli i kurortów przed rezerwacją oraz reklama i marketing turystyczny regionów (np. Visit Dubai VR)."}]},{"id":"szlaki-turystyczne","wiki":[{"heading":"Pojęcie i rodzaje","body":"Szlaki turystyczne to wyznaczone w terenie trasy prowadzące przez ciekawe miejsca przyrodnicze, historyczne lub kulturowe. Są oznaczone specjalnymi symbolami (kolorami, znakami) i służą bezpiecznemu oraz atrakcyjnemu poruszaniu się po danym obszarze.","bullets":["Piesze (górskie, nizinne)","Rowerowe","Konne","Kajakowe","Narciarskie","Tematyczne (szlak zamków gotyckich, szlak papieski)"]},{"heading":"Dlaczego są specyficznym produktem krajoznawczym","bullets":["Łączą walory przyrodnicze, kulturowe i edukacyjne, pozwalając aktywnie poznawać region","Są produktem otwartym - nie wymagają zakupu, często bezpłatne i samodzielne","Tworzą spójną, zorganizowaną ofertę turystyczną (aplikacje, przewodniki)","Pobudzają rozwój lokalnych usług (noclegi, gastronomia, informacja turystyczna)","Mają znaczenie edukacyjne i proekologiczne, często prowadzą przez obszary chronione"]}],"questions":[{"type":"abcd","q":"Dlaczego szlak turystyczny uznaje się za \"produkt otwarty\"?","options":["Bo zawsze wymaga wykupienia biletu wstępu","Bo można z niego korzystać tylko z przewodnikiem","Bo jest dostępny wyłącznie sezonowo","Bo nie wymaga zakupu i często można korzystać z niego samodzielnie i bezpłatnie"],"correct":3,"explain":"Szlak jest produktem otwartym, ponieważ nie wymaga zakupu - turyści korzystają z niego samodzielnie, bez przewodnika i często bezpłatnie."},{"type":"tf","q":"Szlaki turystyczne mogą mieć charakter tematyczny, np. szlak zamków gotyckich czy szlak papieski.","correct":true,"explain":"Szlaki tematyczne to jeden z rodzajów szlaków wymienionych w materiale."},{"type":"flash","front":"Wymień rodzaje szlaków turystycznych.","back":"Piesze (górskie, nizinne), rowerowe, konne, kajakowe, narciarskie oraz tematyczne (np. szlak zamków gotyckich, szlak papieski)."}]},{"id":"walory-krajobrazowe-unesco","wiki":[{"heading":"Pojęcie i podział walorów","body":"Walory krajobrazowe (krajoznawcze) to cechy środowiska przyrodniczego i kulturowego decydujące o atrakcyjności obszaru. Dzieli się je na walory przyrodnicze (ukształtowanie terenu, szata roślinna, świat zwierząt, wody, zjawiska geologiczne) oraz walory kulturowe/antropogeniczne (zabytki architektury, układy urbanistyczne, obiekty przemysłowe, miejsca historyczne, krajobrazy kulturowe)."},{"heading":"Walory przyrodnicze Polski","bullets":["Krajobrazy nadmorskie - wybrzeże Bałtyku, ruchome wydmy, klify, mierzeje","Krajobrazy pojezierne - Pojezierze Mazurskie i Pomorskie, jeziora polodowcowe, moreny","Krajobrazy nizinne - równiny, doliny rzeczne (Wisła, Biebrza), bagna i torfowiska","Krajobrazy wyżynne - lessowe wąwozy, ostańce wapienne, jaskinie (Wyżyna Krakowsko-Częstochowska)","Krajobrazy górskie - Tatry, Bieszczady, Karkonosze, duże deniwelacje i piętrowość"]},{"heading":"Obiekty UNESCO w Polsce","body":"Polska posiada 17 obiektów na Liście Światowego Dziedzictwa UNESCO: 15 kulturowych i 2 przyrodnicze.","bullets":["Kulturowe m.in.: Historyczne Centrum Krakowa, kopalnie soli w Wieliczce i Bochni, Auschwitz-Birkenau, Stare Miasto w Warszawie i Zamościu, Zamek w Malborku, Toruń, Kalwaria Zebrzydowska, Kościoły Pokoju, Hala Stulecia, Tarnowskie Góry, Krzemionki","Przyrodnicze: Puszcza Białowieska (ostoja żubra) oraz pierwotne i stare lasy bukowe Karpat"]},{"heading":"Rezerwaty biosfery UNESCO","body":"W ramach programu \"Czlowiek i Biosfera\" (MAB) Polska posiada 11 rezerwatów biosfery łączących ochronę przyrody ze zrównoważonym rozwojem, m.in. Białowieża, Babia Góra, Tatry, Karkonosze, Słowiński, Bory Tucholskie, Roztocze, Karpaty Wschodnie, Kampinos."}],"questions":[{"type":"abcd","q":"Ile obiektów przyrodniczych z Polski znajduje się na Liście Światowego Dziedzictwa UNESCO?","options":["15 obiektów","11 obiektów","2 obiekty (Puszcza Białowieska oraz lasy bukowe Karpat)","17 obiektów"],"correct":2,"explain":"Z 17 polskich obiektów UNESCO 15 jest kulturowych, a tylko 2 przyrodnicze: Puszcza Białowieska oraz pierwotne i stare lasy bukowe Karpat."},{"type":"tf","q":"Rezerwaty biosfery UNESCO funkcjonują w ramach konwencji ramsarskiej i służą wyłącznie ochronie obszarów wodno-błotnych.","correct":false,"explain":"Rezerwaty biosfery działają w ramach programu „Człowiek i Biosfera” (MAB) i łączą ochronę przyrody ze zrównoważonym rozwojem; konwencja ramsarska dotyczy odrębnie obszarów wodno-błotnych."},{"type":"flash","front":"Na jakie dwie główne grupy dzielimy walory krajobrazowe Polski?","back":"Na walory przyrodnicze (ukształtowanie terenu, szata roślinna, świat zwierząt, wody, zjawiska geologiczne) oraz walory kulturowe/antropogeniczne (zabytki, układy urbanistyczne, obiekty przemysłowe, miejsca historyczne, krajobrazy kulturowe)."}]},{"id":"przyrodnicze-walory-polski","wiki":[{"heading":"Pojęcie walorów przyrodniczych","body":"Walory przyrodnicze to naturalne elementy środowiska będące przedmiotem zainteresowania turysty, powstałe niezależnie od działań człowieka. Obejmują klimat, ukształtowanie terenu, wody, bogactwa naturalne, rośliny i świat zwierząt."},{"heading":"Parki narodowe i góry","bullets":["W Polsce są 23 parki narodowe","Białowieski PN - ostatni naturalny las nizinny w UE, UNESCO, chroni żubra","Tatrzański PN - najwyższe góry, doliny i jeziora polodowcowe (Morskie Oko)","Biebrzański PN - największy PN, rzeka Biebrza, bagna i torfowiska","Karpaty (Tatry z Rysami, Bieszczady) i Sudety (Śnieżka, Góry Stołowe)"]},{"heading":"Wody i pojezierza","bullets":["Pojezierze Mazurskie (Śniardwy, Mamry) i Pomorskie","Wybrzeże Bałtyku ok. 510 km - Słowiński PN (ruchome wydmy), Mierzeja Helska","Rzeki: Wisła (najdłuższa, korytarz ekologiczny), Dunajec (przełom w Pieninach)"]},{"heading":"Lasy, formacje skalne i bioróżnorodność","bullets":["Puszcze: Białowieska, Kampinoska, Augustowska","Formacje skalne i jaskinie: Wyżyna Krakowsko-Częstochowska, Jaskinia Niedźwiedzia","Bagna i mokradła: Bagna Biebrzańskie, Poleski PN","Bioróżnorodność: żubry, wilki, rysie, niedźwiedzie brunatne, ponad 400 gatunków ptaków"]}],"questions":[{"type":"abcd","q":"Ile parków narodowych znajduje się w Polsce?","options":["11","23","17","40"],"correct":1,"explain":"W Polsce znajdują się 23 parki narodowe chroniące unikalne ekosystemy i krajobrazy."},{"type":"tf","q":"Tatrzański Park Narodowy jest największym parkiem narodowym w Polsce.","correct":false,"explain":"Największy jest Biebrzański Park Narodowy (rozległe bagna i torfowiska będące siedliskiem wielu ptaków), a nie Tatrzański."},{"type":"flash","front":"Z czego znany jest Słowiński Park Narodowy?","back":"Z ruchomych wydm, które przemieszczają się pod wpływem wiatru; leży na wybrzeżu Bałtyku."}]},{"id":"style-historyczne-zabytki","wiki":[{"heading":"Architektura przedromańska, romańska i gotyk","body":"Najstarsze zabytki na Ostrowie Tumskim wiążą się z chrystianizacją i Piastami: Palatium Mieszka I i kaplica Dobrawy (styl przedromański, surowość, łupany kamień - opus emplectum) oraz przedromańska i romańska bazylika w podziemiach katedry (masywność, monumentalizm). Gotyk (XIII-XVI w.) reprezentuje ceglana katedra na Ostrowie Tumskim - łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste, wąskie okna - oraz Psałteria (schodkowy szczyt z blendami) i Zamek Królewski na Wzgórzu Przemysła."},{"heading":"Renesans i barok","bullets":["Renesans (XVI w.) - Ratusz Jana Baptysty Quadro z loggią arkadową i attyką, Akademia Lubrańskiego, Pałac Górków","Cechy renesansu: harmonia, symetria, horyzontalizm, proporcje antyczne","Barok (XVII-XVIII w.) - Fara Poznańska (Jezuici, pseudokorynckie kolumny, freski Dankwarta), kościół św. Antoniego","Cechy baroku: dynamizm, teatralność, iluzjonizm, theatrum sacrum"]},{"heading":"Klasycyzm, rokoko i historyzm","bullets":["Klasycyzm (XVIII w.) - Odwach (portyk toskański) i Pałac Działyńskich (tympanon)","Rokoko - detale rzeźbiarskie, motyw muszli (rocaille), lekkość, złocenia","Historyzm (XIX-XX w.) w Dzielnicy Cesarskiej - Zamek Cesarski (neoromanizm), Teatr Wielki (neoklasycyzm), Collegium Minus (neorenesans), Złota Kaplica (neobizantynizm)"]},{"heading":"Modernizm i postmodernizm","body":"Modernizm reprezentuje Okrąglak (Marek Leykam, 1948-1954) - walec z betonowych prefabrykatów, zasada \"forma wynika z funkcji\". Postmodernizm/dekonstruktywizm to Brama Poznania ICHB (2014) - betonowy sześcian \"przecięty\" przeszkloną szczeliną kadrującą widok na gotycką katedrę, dialog współczesności z historią."}],"questions":[{"type":"abcd","q":"W jakim stylu architekt Jan Baptysta Quadro przebudował poznański Ratusz?","options":["Gotyk","Barok","Renesans","Klasycyzm"],"correct":2,"explain":"Ratusz uchodzi za jedno z najwspanialszych dzieł renesansu na północ od Alp; Quadro dodał trójkondygnacyjną loggię arkadową i attykę."},{"type":"tf","q":"Zamek Cesarski w Poznaniu zbudowano w stylu gotyckim, wzorując się na średniowiecznych katedrach.","correct":false,"explain":"Zamek Cesarski (proj. Franz Schwechten, 1910) powstał w stylu neoromańskim, by nawiązać do tradycji cesarskiej i legitymizować pruskie panowanie — nie w gotyku."},{"type":"flash","front":"Jakie cechy stylu gotyckiego widać w katedrze na Ostrowie Tumskim?","back":"Czerwona cegła (gotyk ceglany), strzeliste łuki ostre, sklepienia krzyżowo-żebrowe i gwiaździste oraz wysokie, wąskie okna z witrażami."}]},{"id":"planowanie-przestrzenne","wiki":[{"heading":"Istota i cele","body":"System planowania przestrzennego to zespół narzędzi prawnych, instytucjonalnych i organizacyjnych służących zrównoważonemu kształtowaniu przestrzeni. Głównym celem jest ochrona ładu przestrzennego i zrównoważonego rozwoju. Podstawą prawną jest ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym."},{"heading":"Struktura hierarchiczna (trójstopniowa)","bullets":["Poziom krajowy - dokument strategiczny (osie rozwoju, sieć osadnicza, korytarze transportowe), nie jest aktem prawa miejscowego","Poziom regionalny - Plan zagospodarowania przestrzennego województwa (PZPW), uchwala sejmik, nie wiąże właścicieli nieruchomości","Poziom lokalny (gminny) - kluczowy, tu zapadają decyzje wiążące dla obywatela","Zasada hierarchicznej zgodności - dokumenty niższego szczebla nie mogą być sprzeczne z wyższymi"]},{"heading":"Akty na poziomie gminy (po reformie 2023)","bullets":["Plan Ogólny Gminy - akt prawa miejscowego, obowiązkowy, dzieli gminę na strefy planistyczne (zastąpił dawne Studium)","Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) - akt prawa miejscowego, fakultatywny, podstawa pozwoleń na budowę","Zintegrowany Plan Inwestycyjny (ZPI) - szczególna forma MPZP w ramach partnerstwa publiczno-prywatnego","Gmina ma władztwo planistyczne - autonomiczne prawo kształtowania polityki przestrzennej"]},{"heading":"Dualizm systemu i problemy","body":"Gdy nie ma MPZP, inwestor występuje o decyzję o Warunkach Zabudowy (WZ) opartą na zasadzie dobrego sąsiedztwa. Nadużywanie decyzji WZ prowadziło do rozlewania się miast (urban sprawl) i chaosu przestrzennego. Główne problemy: niski stopień pokrycia kraju planami (ok. 30-35%), koszty finansowe gmin, chaos przestrzenny i konflikty funkcji."}],"questions":[{"type":"abcd","q":"Na jakiej podstawie inwestor może budować, gdy na danym terenie nie ma uchwalonego MPZP?","options":["Na podstawie Planu zagospodarowania przestrzennego województwa","Na podstawie decyzji o Warunkach Zabudowy (WZ) i zasady dobrego sąsiedztwa","Na podstawie koncepcji rozwoju kraju","Bez żadnego dokumentu administracyjnego"],"correct":1,"explain":"W braku MPZP stosuje się ścieżkę decyzyjną - decyzję o Warunkach Zabudowy opartą na zasadzie dobrego sąsiedztwa (analiza urbanistyczna)."},{"type":"tf","q":"Władztwo planistyczne oznacza, że to wojewoda (administracja rządowa) decyduje o przeznaczeniu gruntów w gminie.","correct":false,"explain":"Władztwo planistyczne przysługuje samorządowi gminnemu — to gmina, nie wojewoda, autonomicznie decyduje o polityce przestrzennej na swoim obszarze."},{"type":"flash","front":"Jakie trzy akty planistyczne funkcjonują na poziomie gminy po reformie z 2023 r.?","back":"Plan Ogólny Gminy (zastąpił Studium), Miejscowy Plan Zagospodarowania Przestrzennego (MPZP) oraz Zintegrowany Plan Inwestycyjny (ZPI)."}]},{"id":"zagospodarowanie-turystyczne-formy","wiki":[{"heading":"Pojęcie","body":"Zagospodarowanie turystyczne to ogół obiektów i urządzeń służących obsłudze ruchu turystycznego, dostosowany do potrzeb różnych form turystyki. Infrastruktura i usługi różnią się zakresem, funkcją oraz lokalizacją."},{"heading":"Formy turystyki i ich zaplecze","bullets":["Turystyka kulturowa - muzea, galerie, zabytki, trasy tematyczne, przewodnicy miejscy","Turystyka miejska - baza noclegowa, restauracje, kluby, komunikacja miejska, obiekty rozrywki","Turystyka biznesowa - centra kongresowe, sale konferencyjne, hotele średniej i wysokiej klasy","Turystyka religijna - obiekty sakralne, domy pielgrzyma, punkty obsługi, parkingi","Agroturystyka - pokoje gościnne, domy wiejskie, warsztaty, produkty regionalne","Turystyka przyrodnicza - ścieżki edukacyjne, wieże widokowe, tablice, ograniczona baza (kempingi, schroniska)","Turystyka aktywna i przygodowa - oznakowanie szlaków, punkty ratunkowe, wypożyczalnie sprzętu, specjalistyczni przewodnicy"]},{"heading":"Infrastruktura wspólna","body":"Zagospodarowanie obejmuje również infrastrukturę wspólną: bazę noclegową, gastronomiczną, sanitarną, transportową oraz punkty informacyjne. Dobrze rozwinięte zaplecze zwiększa atrakcyjność regionu i sprzyja zrównoważonemu rozwojowi turystyki."}],"questions":[{"type":"abcd","q":"Jakie zaplecze jest charakterystyczne dla turystyki biznesowej?","options":["Ścieżki edukacyjne i wieże widokowe","Domy pielgrzyma i obiekty sakralne","Centra kongresowe, sale konferencyjne i hotele średniej oraz wysokiej klasy","Pokoje gościnne w gospodarstwach rolnych"],"correct":2,"explain":"Turystyka biznesowa wymaga infrastruktury konferencyjnej (hale, sale, centra kongresowe) oraz hoteli średniej i wysokiej klasy."},{"type":"tf","q":"Turystyka przyrodnicza wymaga m.in. tworzenia ścieżek edukacyjnych, punktów obserwacyjnych i ograniczonej bazy noclegowej jak kempingi czy schroniska.","correct":true,"explain":"Turystyka przyrodnicza odbywa się na obszarach chronionych i wymaga infrastruktury ochrony przyrody oraz ograniczonej bazy noclegowej."},{"type":"flash","front":"Co obejmuje infrastruktura wspólna w zagospodarowaniu turystycznym?","back":"Bazę noclegową, gastronomiczną, sanitarną, transportową oraz punkty informacyjne - wspólne dla różnych form turystyki."}]},{"id":"pilot-wycieczek","wiki":[{"body":"Pilot wycieczek to osoba, która w imieniu organizatora nadzoruje realizację programu imprezy turystycznej i sprawuje opiekę nad uczestnikami. Marszałek województwa ma prawo kontrolować pilotów wycieczek."},{"heading":"Obowiązki pilota","bullets":["Działa na podstawie pisemnego zlecenia organizatora; musi znać język kraju docelowego.","Czuwa nad realizacją świadczeń — sprawdza jakość usług (nocleg, wyżywienie, transport) i ich zgodność z umową.","Sprawuje opiekę nad turystami, zapewnia pomoc medyczną i reaguje na problemy (zgubione dokumenty, konflikty z prawem).","Przekazuje informacje o trasie, krajach i atrakcjach oraz tłumaczy rozmowy z obsługą.","Pełni obowiązki handlowe (interesy organizatora, faktury) i obywatelskie (szacunek dla lokalnych przepisów i zwyczajów)."]},{"heading":"Prawa pilota","bullets":["Reprezentuje organizatora — kontaktuje się z kontrahentami i koordynuje program.","Podejmuje decyzje organizacyjne związane z przebiegiem imprezy.","Wydaje uczestnikom polecenia organizacyjne."]},{"body":"Uwaga: w niektórych krajach (np. Francja, Włochy) pilot nie może oprowadzać po obiektach bez lokalnej licencji przewodnika. Częsty jest też dylemat pilota: opieka nad uczestnikami czy realizacja programu (stan wyższej konieczności)."}],"questions":[{"type":"abcd","q":"Kto ma prawo kontrolować pilotów wycieczek?","options":["Minister sportu","Izba Turystyki","Prezydent miasta","Marszałek województwa"],"correct":3,"explain":"Zgodnie z materiałem, prawo kontroli pilotów wycieczek ma marszałek województwa."},{"type":"tf","q":"W niektórych krajach (np. Francja, Włochy) pilot nie może oprowadzać turystów bez lokalnej licencji.","correct":true,"explain":"W części krajów oprowadzanie po obiektach wymaga lokalnej licencji przewodnika — pilot nie może jej zastąpić."},{"type":"flash","front":"Na czym polega dylemat pilota „opieka czy program\"?","back":"W sytuacji wyższej konieczności pilot musi zdecydować, czy realizować zaplanowany program, czy zająć się opieką nad uczestnikiem — opieka i bezpieczeństwo mają pierwszeństwo."}]},{"id":"programowanie-imprez-turystycznych","wiki":[{"body":"Programowanie imprezy turystycznej to proces planowania kompleksowej oferty odpowiadającej potrzebom rynku i konkretnej grupy docelowej. Kluczowe jest dopasowanie oferty do specyfiki klientów (rodziny z dziećmi, seniorzy, młodzież, VIP)."},{"heading":"1. Analiza destynacji","bullets":["Rozpoznanie atrakcji (przyrodniczych, kulturowych, rozrywkowych).","Ocena infrastruktury (baza noclegowa, gastronomiczna, transportowa) i lokalnych usługodawców.","Sprawdzenie, czy miejsce spełnia wymagania grupy docelowej."]},{"heading":"2. Współpraca z usługodawcami","body":"Touroperator ustala ceny, terminy i standardy. Dwie formy zakupu usług:","bullets":["Allotment — rezerwacja usług z możliwością zwrotu do wyznaczonego terminu (lepszy dla indywidualnych i seniorów).","Czarter — wynajęcie całej usługi na własne ryzyko (sprawdza się przy młodzieży i grupach szkolnych)."]},{"heading":"3. Program i kalkulacja ceny","bullets":["Ustala się trasę/miejsce, terminy, standard usług, atrakcje, transport i cenę.","Program dopasowany do grupy: seniorzy — krótsze trasy; młodzież — intensywny program; VIP — usługi premium.","Kalkulacja: koszty stałe + koszty zmienne + marża + prowizje; w turystyce obowiązuje VAT od marży."]}],"questions":[{"type":"abcd","q":"Która forma zakupu usług pozwala zwrócić niewykorzystane miejsca do określonego terminu?","options":["Czarter","Allotment","Leasing","Franczyza"],"correct":1,"explain":"Allotment to rezerwacja z możliwością zwrotu do wyznaczonego terminu; czarter to wynajem na własne ryzyko."},{"type":"abcd","q":"Które koszty imprezy są niezależne od liczby uczestników?","options":["Koszty stałe","Koszty zmienne","Prowizje agentów","Bilety wstępu"],"correct":0,"explain":"Koszty stałe (np. wynagrodzenie pilota, rezerwacje) nie zależą od liczby uczestników; nocleg czy bilety to koszty zmienne."},{"type":"tf","q":"Czarter sprawdza się szczególnie przy małych, niepewnych grupach indywidualnych.","correct":false,"explain":"Czarter (całość usługi na własne ryzyko) opłaca się przy dużych, pewnych grupach, np. szkolnych — a nie przy małych grupach indywidualnych."},{"type":"flash","front":"Jaki system VAT obowiązuje w turystyce przy imprezach?","back":"System VAT od marży — podatek nalicza się od marży touroperatora, a nie od całej wartości imprezy."}]},{"id":"uczestnicy-turystyki-przygodowej","wiki":[{"heading":"Poziomy przygody i oczekiwania","body":"Wyróżnia się cztery poziomy przygody: nieszczęście, przygodę ekstremalną, przygodę i zabawę. Modelowo poziom wyzwania musi być dostosowany do poziomu uczestników, a uczestnicy powinni mieć wyrobione oczekiwania, które w efekcie aktywności mogą zostać spełnione lub osiągnięte. Uczestnik musi widzieć szansę na osiągnięcie sukcesu, dzięki czemu towarzyszy mu optymizm."},{"heading":"Motywacja i subiektywność","body":"Ludzi do uprawiania turystyki przygodowej skłaniają emocje wynikające z przekraczania strefy komfortu. Mogą one wynikać z szoku kulturowego lub z wykonywania czynności wymagających znacznego wysiłku fizycznego, wywołujących poczucie ryzyka (rzeczywistego lub domniemanego) lub zagrożenia fizycznego. Zaawansowanych specjalistów od masowych uczestników odróżnia poziom umiejętności oraz odległość i dostępność miejsca uprawiania turystyki, dlatego turystyka przygodowa ma charakter subiektywny."},{"heading":"Wyróżniki uczestników","bullets":["postawa akceptacji elementu ryzyka w doznaniach turystycznych","zdolność do ponoszenia zwiększonego poziomu wysiłku fizycznego podczas wypraw","potrzeba posiadania określonych umiejętności i nastawienia psychicznego dla powodzenia wyprawy"]}],"questions":[{"type":"abcd","q":"Ile poziomów przygody wyróżnia się w charakterystyce uczestników turystyki przygodowej?","options":["Dwa","Cztery","Trzy","Pięć"],"correct":1,"explain":"Wyróżnia się cztery poziomy: nieszczęście, przygodę ekstremalną, przygodę i zabawę."},{"type":"tf","q":"Turystyka przygodowa ma dla jej uczestników charakter subiektywny.","correct":true,"explain":"O subiektywności decyduje m.in. indywidualny poziom umiejętności oraz odległość i dostępność miejsca uprawiania turystyki."},{"type":"flash","front":"Wymień wyróżniki uczestników turystyki przygodowej.","back":"Akceptacja elementu ryzyka, zdolność do zwiększonego wysiłku fizycznego oraz potrzeba posiadania określonych umiejętności i nastawienia psychicznego dla powodzenia wyprawy."}]},{"id":"etapy-zarzadzania-projektami-turystycznymi","wiki":[{"heading":"Pięć etapów projektu","body":"Zarządzanie projektami turystycznymi składa się z pięciu głównych etapów. Każdy ma własne wyzwania i wymagania, które należy uwzględnić dla skutecznego ukończenia projektu.","bullets":["Inicjacja: określenie celu i zakresu projektu, zdefiniowanie zespołu i głównych zadań, wstępna analiza możliwości oraz ustalenie ram wyjazdu","Planowanie: szczegółowy plan z harmonogramem, budżetem, zasobami i procesami, określenie ryzyka i strategii jego zarządzania oraz przygotowanie informacji dla interesariuszy","Realizacja: wykonanie zaplanowanych zadań, monitorowanie postępów, reagowanie na zmiany i problemy, zapewnienie świadczeń i sprzętu","Monitorowanie: porównywanie postępów z planem, kontrola ryzyka, budżetu, harmonogramu i jakości oraz poziomu zadowolenia klienta","Zamknięcie: podsumowanie wyników, ocena projektu, dokumentacja, rozliczenie finansowe, raport końcowy i wdrożenie wniosków na przyszłość"]},{"heading":"Specyfika turystyki","body":"Ważnym elementem jest zrozumienie specyfiki turystyki i dostosowanie procesu zarządzania do konkretnego typu projektu. Może to obejmować analizę rynku, określenie grupy docelowej, marketing i promocję oraz współpracę z lokalnymi dostawcami i partnerami."}],"questions":[{"type":"abcd","q":"Który etap zarządzania projektem turystycznym obejmuje opracowanie harmonogramu, budżetu i strategii zarządzania ryzykiem?","options":["Inicjacja","Zamknięcie","Realizacja","Planowanie"],"correct":3,"explain":"Na etapie planowania opracowuje się szczegółowy plan z harmonogramem, budżetem, zasobami oraz strategią zarządzania ryzykiem."},{"type":"abcd","q":"Na którym etapie projektu sporządza się raport końcowy i przeprowadza rozliczenie finansowe?","options":["Zamknięcie","Realizacja","Monitorowanie","Inicjacja"],"correct":0,"explain":"Zamknięcie obejmuje podsumowanie wyników, ocenę, dokumentację, rozliczenie finansowe i raport końcowy."},{"type":"tf","q":"Zarządzanie projektami turystycznymi składa się z trzech głównych etapów.","correct":false,"explain":"Etapów jest pięć: inicjacja, planowanie, realizacja, monitorowanie i kontrola oraz zamknięcie."},{"type":"flash","front":"Wymień pięć etapów zarządzania projektami turystycznymi.","back":"Inicjacja, planowanie, realizacja, monitorowanie i kontrola oraz zamknięcie."}]},{"id":"fotografia-dokumentalna","wiki":[{"heading":"Czym jest fotografia dokumentalna","body":"To rodzaj fotografii, którego głównym celem jest uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania. Często jest używana do dokumentowania wydarzeń, miejsc, kultur lub sytuacji społecznych, politycznych i ludzkich. Obejmuje wszystkie zdjęcia próbujące wiernie przedstawić świat."},{"heading":"Rola i odróżnienie od fotoreportażu","body":"Zdjęcia dokumentalne, od wojennych panoram po zbliżenia ludzi na ulicy, mogą informować odbiorców o ukrytych zakamarkach współczesnego życia, a nawet stać się częścią danych historycznych. W przeciwieństwie do fotoreportażu, który ogranicza się do pojedynczej wiadomości lub wydarzenia, obrazy dokumentalne wykorzystywane są zbiorowo, aby naświetlić głębszy problem."}],"questions":[{"type":"abcd","q":"Co najlepiej odróżnia fotografię dokumentalną od fotoreportażu?","options":["Fotografia dokumentalna wymaga pozowania modeli","Fotoreportaż zawsze dotyczy danych historycznych","Obrazy dokumentalne wykorzystywane są zbiorowo, by naświetlić głębszy problem, a fotoreportaż ogranicza się do pojedynczej wiadomości lub wydarzenia","Fotografia dokumentalna dotyczy wyłącznie wydarzeń wojennych"],"correct":2,"explain":"Fotoreportaż ogranicza się do pojedynczej wiadomości lub wydarzenia, a obrazy dokumentalne wykorzystywane są zbiorowo, aby naświetlić głębszy problem."},{"type":"tf","q":"Głównym celem fotografii dokumentalnej jest uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania.","correct":true,"explain":"Fotografia dokumentalna obejmuje zdjęcia próbujące wiernie przedstawić świat."},{"type":"flash","front":"Jaki jest główny cel fotografii dokumentalnej?","back":"Uchwycenie prawdziwych i naturalnych momentów, bez zmian ani pozowania, w celu wiernego przedstawienia świata oraz dokumentowania wydarzeń, miejsc, kultur i sytuacji społecznych."}]},{"id":"fotografia-w-social-mediach","wiki":[{"heading":"Wpływ fotografii na social media","body":"Fotografia jest kluczowym elementem mediów społecznościowych. Profesjonalnie wykonane zdjęcia przyciągają uwagę, zwiększają zaangażowanie i wspierają sprzedaż. To nie tylko estetyka, ale także strategia komunikacji pozwalająca wyróżnić się na tle konkurencji.","bullets":["budowanie wizerunku marki i zaufania","zwiększanie zaangażowania (polubienia, komentarze, udostępnienia)","wspomaganie sprzedaży poprzez fotografię produktową","wyróżnianie się na tle konkurencji"]},{"heading":"Jak wykorzystać fotografię","bullets":["dostosowanie do platformy (np. Instagram - format kwadratowy, Facebook - pionowy lub poziomy)","regularność i spójność stylu oraz estetyki","kreowanie historii marki i produktu","wykorzystanie różnych formatów: zdjęcia, krótkie filmy, reelsy, story"]},{"heading":"Dodatkowe wskazówki","bullets":["dbanie o wyraźne i ostre zdjęcia (czyszczenie obiektywu, dobre oświetlenie)","pilnowanie praw autorskich do publikowanych zdjęć","eksperymentowanie z różnymi stylami i formatami"]}],"questions":[{"type":"abcd","q":"Który format zdjęć jest wskazany dla Instagrama według zasady dostosowania do platformy?","options":["Panoramiczny 21:9","Wyłącznie pionowy","Wyłącznie poziomy","Kwadratowy"],"correct":3,"explain":"Instagram wymaga zdjęć w kwadratowym formacie, a Facebook w pionowym lub poziomym."},{"type":"tf","q":"Fotografia w social media to wyłącznie kwestia estetyki, bez znaczenia strategicznego.","correct":false,"explain":"To nie tylko estetyka, ale także strategia komunikacji pozwalająca wyróżnić się na tle konkurencji."},{"type":"flash","front":"Jak fotografia wpływa na social media?","back":"Buduje wizerunek marki i zaufanie, zwiększa zaangażowanie, wspomaga sprzedaż oraz pomaga wyróżnić się na tle konkurencji."}]},{"id":"kompetencje-miedzykulturowe-outdoor","wiki":[{"heading":"Trzon kompetencji kulturowych","bullets":["Skills (umiejętności) - komunikowanie się, współpraca, elastyczność, radzenie sobie w sytuacjach stresowych, aktywne słuchanie i krytyczne myślenie","Attitude (postawa) - świadomość różnic, odwaga, pozytywne nastawienie i otwartość","Knowledge (wiedza) - wiedza kulturowa, przygotowanie na szok kulturowy oraz wiedza z turystyki, survivalu i planowania"]},{"heading":"Znaczenie w projektach outdoorowych","body":"Kompetencje obejmują rozumienie różnic kulturowych, akceptację i szacunek dla innych kultur oraz umiejętność komunikowania się i współpracy z osobami z różnych środowisk. Pozwalają na skuteczną współpracę przez budowanie zaufania, podnoszą bezpieczeństwo i komfort dzięki lepszej adaptacji, rozwijają kompetencje uczestników i kształtują właściwą relację z innym."},{"heading":"Odpowiedzialne podróżowanie","body":"Kompetencje prowadzą do odpowiedzialnego podróżowania z otwartymi oczami: ludzie pamiętają, że ich obecność odciska piętno na odwiedzanych miejscach, wydają pieniądze wspierając lokalne walory, cenią dziedzictwo przyrodnicze i kulturowe, szanują lokalne zwyczaje i tradycje oraz wspierają tych, którzy dbają o dane miejsca."}],"questions":[{"type":"abcd","q":"Który element NIE należy do trzonu kompetencji kulturowych (skills, attitude, knowledge)?","options":["Skills - umiejętności","Attitude - postawa","Budget - budżet","Knowledge - wiedza"],"correct":2,"explain":"Trzon kompetencji kulturowych stanowią skills (umiejętności), attitude (postawa) i knowledge (wiedza); budżet nie wchodzi w jego skład."},{"type":"tf","q":"Komponent \"knowledge\" obejmuje m.in. przygotowanie na szok kulturowy oraz wiedzę z survivalu i planowania.","correct":true,"explain":"Knowledge to wiedza kulturowa, przygotowanie na szok kulturowy oraz wiedza z dziedzin potrzebnych w podróży: turystyki, survivalu i planowania."},{"type":"flash","front":"Co stanowi trzon kompetencji międzykulturowych?","back":"Skills (umiejętności), attitude (postawa) i knowledge (wiedza)."}]},{"id":"kwalifikacje-pilotow-przewodnikow-trampingowych","wiki":[{"heading":"Podstawowe wymogi","body":"Podstawowe wymogi to ukończenie 18 lat, niekaralność oraz wykształcenie średnie. Przewodnik powinien posiadać wiedzę o regionie i atrakcjach, a pilot doświadczenie w organizacji i zarządzaniu wycieczkami. Obowiązki i kompetencje określa ustawa o usługach hotelarskich oraz usługach pilotów wycieczek i przewodników turystycznych z 2023 roku."},{"heading":"Grupy kompetencji","bullets":["kompetencje społeczne - elokwentność, cierpliwość, komunikatywność, empatia i elastyczność","kompetencje osobiste - cierpliwość, punktualność, dokładność, znajomość dobrych manier, optymizm","kompetencje menedżerskie i przywódcze - charyzma, pewność siebie, delegowanie uprawnień, umiejętność pracy w grupie","kompetencje zawodowe - językowe, fachowa wiedza, sporządzanie pism, pierwsza pomoc","kompetencje formalno-prawne pilota - zakres uprawnień i pełnomocnictwo do podejmowania decyzji"]},{"heading":"Specyfika trampingu","body":"W turystyce trampingowej przewodnik i pilot muszą znać teren, trasę, zagrożenia i zasady bezpieczeństwa oraz posiadać umiejętności praktyczne (obsługa sprzętu, pierwsza pomoc, planowanie). Tramping odbywa się jak najmniejszym kosztem i wymaga adaptacji pilota do otoczenia i grupy, odporności na zmienne warunki pogodowe oraz nastawienia na kontakt z lokalną ludnością i autentyczność. Treść przekazuje się przez poznawanie i doświadczanie."}],"questions":[{"type":"abcd","q":"Który z poniższych jest podstawowym wymogiem dla pilotów i przewodników turystyki trampingowej?","options":["Ukończenie 16 lat","Co najmniej 10 lat doświadczenia w terenie","Wykształcenie wyższe kierunkowe","Ukończenie 18 lat, niekaralność oraz wykształcenie średnie"],"correct":3,"explain":"Podstawowe wymogi to ukończenie 18 lat, niekaralność oraz wykształcenie średnie."},{"type":"tf","q":"Obowiązki i kompetencje pilotów oraz przewodników określa ustawa o usługach hotelarskich oraz usługach pilotów wycieczek i przewodników turystycznych z 2023 roku.","correct":true,"explain":"To właśnie ta ustawa pozostaje podstawą określającą obowiązki i kompetencje pilotów i przewodników."},{"type":"flash","front":"Wymień grupy kompetencji pilotów i przewodników turystyki trampingowej.","back":"Kompetencje społeczne, osobiste, menedżerskie i przywódcze, zawodowe oraz formalno-prawne pilota."}]},{"id":"ocena-tras-grupy-odbiorcow","wiki":[{"heading":"Metody jakościowe i kwestionariuszowe","bullets":["Szkocki formularz oceny atrakcji (Scottish Tourist Board) - obserwacja uczestnicząca, ocena sześciu części atrakcji (wstęp, wejście, prezentacja tematyki, gastronomia, sklep, toalety) na skali 0-10","Testy zróżnicowania semantycznego - budowanie profili semantycznych przez wybór par skrajnych cech (np. ładny - brzydki, bezpieczny - niebezpieczny)","Analiza ASEB/SWOT - rozwinięcie analizy SWOT o poziomy hierarchii wymagań, skupione na potrzebach, motywach, wrażeniach i satysfakcji zwiedzających","Kwestionariusz SERVQUAL - pomiar różnicy między oczekiwaniami klienta a percepcją usługi; do atrakcji przystosował go M. Nowacki"]},{"heading":"Metody analityczne","bullets":["Metoda bonitacji punktowej - przypisanie cechom wartości liczbowych według skali, których suma jest oceną","Metoda modelowa - badanie złożonych systemów przez tworzenie ich modeli, symulacja i przewidywanie zachowań","Metoda wielowymiarowej analizy porównawczej - porządkowanie jednorodnego zbioru obiektów lub cech według ustalonego kryterium, do badania zjawisk niemierzalnych bezpośrednio"]}],"questions":[{"type":"abcd","q":"Na czym opiera się założenie kwestionariusza SERVQUAL?","options":["Na liczbie odwiedzin atrakcji w sezonie","Na pomiarze długości i przewyższeń trasy","Na różnicy między oczekiwaniami klienta wobec usługi a jej percepcją","Na obserwacji uczestniczącej na skali 0-10"],"correct":2,"explain":"SERVQUAL zakłada, że satysfakcja z jakości usługi jest różnicą między oczekiwaniami klienta wobec niej a jej percepcją."},{"type":"tf","q":"Szkocki formularz oceny atrakcji ocenia sześć głównych części atrakcji na skali od 1 do 5.","correct":false,"explain":"Formularz Scottish Tourist Board stosuje jedenastostopniową skalę od 0 do 10, a nie skalę 1-5."},{"type":"flash","front":"Czym jest analiza ASEB/SWOT?","back":"Rozwinięcie tradycyjnej analizy SWOT o dodatkowy wymiar poziomów hierarchii wymagań, skupione na potrzebach, motywach, wrażeniach i satysfakcji zwiedzających."}]},{"id":"ocena-tras-formy-przygodowe","wiki":[{"heading":"Ocena atrakcyjności tras","body":"Najbardziej rozpowszechnione są próby wartościowania przez listy rankingowe. W naukach geograficznych stosuje się analizy rozmieszczenia tras, a w marketingu i badaniach behawioralnych ocenia się jakość i odbiór szlaku. Wykorzystuje się skalę Likerta, Szkocki Kwestionariusz Atrakcji, Kwestionariusz Australijski, testy wiedzy, quizy, ankiety i schematy obserwacji, a coraz częściej kioski multimedialne oraz rejestrację zachowań za pomocą fotografii i nagrań."},{"heading":"Ocena trudności tras","body":"Należy korzystać z map, sprawdzać opis trasy, przebieg, długość i przewyższenia (np. w aplikacjach takich jak viaferrata.org), a także ustalić warunki pogodowe i możliwe trudności."},{"heading":"Wystandaryzowane skale trudności","bullets":["Skala UIAA (rzymska III-IX) oraz skala ferrat A-F dla tras wspinaczkowych","Skala singletrail (S0-S5) dla tras rowerowych","Skala SAC Szwajcarskiego Klubu Alpinistycznego (T1-T6) dla szlaków górskich","Oznaczenia kolorystyczne tras narciarskich (niebieski - łatwe, czarny - ekstremalne)","Skala szlaków kajakowych: nizinne (ZW: ZWA, ZWB, ZWC) i górskie (WW I do WW VI)"]}],"questions":[{"type":"abcd","q":"Która skala służy do oceny trudności tras rowerowych?","options":["Skala UIAA","Skala WW I do WW VI","Skala SAC (T1-T6)","Skala singletrail (S0-S5)"],"correct":3,"explain":"Skala singletrail to system klasyfikacji trudności tras rowerowych obejmujący 6 poziomów od S0 do S5."},{"type":"abcd","q":"Jakim kolorem oznacza się ekstremalne trasy narciarskie?","options":["Czarnym","Zielonym","Czerwonym","Niebieskim"],"correct":0,"explain":"Trasy łatwe oznacza się kolorem niebieskim, a trasy ekstremalne kolorem czarnym."},{"type":"tf","q":"Skala SAC Szwajcarskiego Klubu Alpinistycznego wykorzystuje oznaczenia od T1 do T10.","correct":false,"explain":"Skala SAC obejmuje sześć stopni — od T1 (bardzo łatwe) do T6 (najtrudniejsze szlaki alpejskie), nie sięga T10."},{"type":"flash","front":"Jak klasyfikuje się trudność szlaków kajakowych?","back":"Szlaki nizinne ocenia się w skali ZW (ZWA, ZWB, ZWC), a górskie w skali WW (od WW I do WW VI)."}]},{"id":"miekkie-formy-aktywnosci-terenowej","wiki":[{"heading":"Definicja miękkich form","body":"Miękkie formy aktywności turystyki przygodowej charakteryzują się niskim stopniem ryzyka i są dostępne dla osób bez specjalnych umiejętności czy przygotowania. W przeciwieństwie do twardej turystyki przygodowej, wymagającej zaawansowanych umiejętności i wiążącej się z większym ryzykiem, koncentrują się na przeżyciu przygody w bezpieczny i relatywnie łatwy sposób."},{"heading":"Przykłady miękkich form","bullets":["Bieg na orientację (BnO) - bieg wyznaczoną trasą z mapą i kompasem do punktów kontrolnych w określonej kolejności, łączący wysiłek fizyczny i intelektualny","Safari - podróż do dzikich obszarów w celu obserwacji zwierząt w naturalnym środowisku, np. Wielkiej Piątki: lwów, słoni, nosorożców, lampartów i bawołów","Nurkowanie - przebywanie pod wodą ze sprzętem lub na zatrzymanym oddechu (freediving); odmiany: snorkeling, freediving, płetwonurkowanie, wrakowe, jaskiniowe","Narciarstwo - przemieszczanie się na nartach; formy: klasyczne, biegi, skitouring, freeskiing, alpejskie","Snowboard - jazda na desce po stoku, rozwijająca równowagę, siłę mięśni i koordynację","Surfing - jazda na desce po fali morskiej; rodzaje: longboarding, shortboarding, na dużych falach, w rurkach"]}],"questions":[{"type":"abcd","q":"Co charakteryzuje miękkie formy aktywności turystyki przygodowej?","options":["Wysoki stopień ryzyka i konieczność zaawansowanych umiejętności","Obowiązkowy udział instruktora z licencją","Wyłącznie aktywności wysokogórskie","Niski stopień ryzyka i dostępność dla osób bez specjalnego przygotowania"],"correct":3,"explain":"Miękkie formy charakteryzują się niskim stopniem ryzyka i są dostępne dla osób bez specjalnych umiejętności czy przygotowania."},{"type":"abcd","q":"Które zwierzęta tworzą tzw. Wielką Piątkę, będącą pożądanym celem safari?","options":["Słonie, nosorożce, krokodyle, lwy i goryle","Lwy, żyrafy, zebry, hieny i gepardy","Lwy, słonie, nosorożce, lamparty i bawoły","Lamparty, tygrysy, lwy, niedźwiedzie i wilki"],"correct":2,"explain":"Wielką Piątkę tworzą lwy, słonie, nosorożce, lamparty i bawoły."},{"type":"tf","q":"Bieg na orientację wymaga zarówno sprawności fizycznej, jak i zdolności intelektualnych.","correct":true,"explain":"BnO łączy wysiłek fizyczny (bieganie, pokonywanie przeszkód) ze zdolnościami intelektualnymi (czytanie mapy, decyzje nawigacyjne)."},{"type":"flash","front":"Wymień przykłady miękkich form aktywności terenowej.","back":"Bieg na orientację, safari, nurkowanie, narciarstwo, snowboard i surfing."}]},{"id":"obszary-turystyki-przygodowej-azja","wiki":[{"heading":"Obszary górskie i pustynne","bullets":["Himalaje (Nepal i Tybet) - najwyższe pasmo świata, trekking, wspinaczka wysokogórska i narciarstwo ekstremalne","Masyw Karakorum (Pakistan i Chiny) - trekking, wspinaczka i narciarstwo ekstremalne w regionie K2, przebiega tędy najwyżej położona autostrada świata","Pustynia Gobi (Chiny i Mongolia) - turystyka offroadowa i rajdy quadowe, bezpieczeństwo zapewniają wieże sygnałowe GPS","Jordania i jej pustynie (Petra) - imprezy sportowe, jazda tradycyjnym jeepem dzięki formacjom skalnym i antycznym zabudowaniom","Wulkany archipelagu Malajskiego - wyprawy trekkingowe i wspinaczkowe na styku płyt tektonicznych"]},{"heading":"Obszary wodne i przyrodnicze","bullets":["Zatoka Halong (Wietnam) - setki wysepek, kajakarstwo, żeglarstwo i fotografia przygodowa","Taman Negara (Malezja) - jeden z najstarszych lasów deszczowych, kładki 45 m nad ziemią, ekoturystyka","Tajlandia, zatoki Phuket i Phang Nga - kajakarstwo i żeglarstwo","Indonezja, Raja Ampat - nurkowanie i żeglarstwo","Wietnam, delta Mekongu i Mai Chau - trasy rowerowe przez pola ryżowe","Japonia - trekking, backpacking, narciarstwo (Furano, Hokkaido) i formy wodne na południu"]}],"questions":[{"type":"abcd","q":"Która forma turystyki przygodowej jest najbardziej charakterystyczna dla pustyni Gobi?","options":["Turystyka offroadowa i rajdy quadowe","Nurkowanie i żeglarstwo","Wspinaczka wysokogórska","Kajakarstwo"],"correct":0,"explain":"Na pustyni Gobi uprawia się przede wszystkim formy turystyki offroadowej i rajdy quadowe, a bezpieczeństwo zapewniają wieże sygnałowe GPS."},{"type":"tf","q":"Raja Ampat w Indonezji to obszar pustynny, sprzyjający przede wszystkim wspinaczce i trekkingowi wysokogórskiemu.","correct":false,"explain":"Raja Ampat to morski archipelag sprzyjający wodnym formom turystyki — głównie nurkowaniu i żeglarstwu, a nie wspinaczce na pustyni."},{"type":"flash","front":"Jakie aktywności oferują Himalaje (Nepal i Tybet)?","back":"Trekking, wspinaczkę wysokogórską i narciarstwo ekstremalne - to najwyższe pasmo górskie świata."}]},{"id":"obszary-turystyki-przygodowej-europa","wiki":[{"heading":"Obszary górskie","bullets":["Tatry (Polska i Słowacja) - wspinaczka turystyczna, wyprawy wysokogórskie, via ferraty, trekking i narciarstwo, ratownictwo TOPR","Alpy (Francja, Szwajcaria, Włochy) - trekking, wspinaczka i narciarstwo, kolej zębatkowa z Zermatt na Gornergrat, ratownicy Air Zermatt, schroniska w Chamonix","Fiordy Norwegii - wyprawy trekkingowe i żeglarskie wśród stromych skarp oraz trasy narciarskie","Północna Szkocja - trekking, tramping, backpacking, bieg na orientację, wyprawy rowerowe, obserwacja wielorybów i wspinaczka na klifach","Islandia - trekking, tramping, backpacking, biegi i wyprawy quadowe przez pola lawowe"]},{"heading":"Obszary wodne i wybrzeża","bullets":["Francja, rzeka Dordogne - kajakarstwo łączone z turystyką kulturową","Szwecja, region Dalarna - kajakarstwo po jeziorach, wędkarstwo sportowe, bieg na orientację","Polska, Wielkie Jeziora Mazurskie - żeglarstwo z rozbudowaną infrastrukturą, windsurfing, kitesurfing, obserwacja fauny i flory","Grecja, Cyklady - żeglarstwo uwarunkowane kulturowo oraz formy związane z plażami i wyspami","Hiszpania, Wyspy Kanaryjskie - trekking, tramping, backpacking i nurkowanie w ciepłej, przejrzystej wodzie","Chorwacja, wybrzeże Dalmacji - nurkowanie, żeglarstwo i trekking"]}],"questions":[{"type":"abcd","q":"Która grupa ratownicza działa w polskich Tatrach jako udogodnienie dla turystów?","options":["Air Zermatt","WOPR","GOPR Beskidy","TOPR"],"correct":3,"explain":"W Tatrach działa TOPR, a Air Zermatt to ratownicy z regionu Matterhornu w Alpach."},{"type":"tf","q":"Polskie Wielkie Jeziora Mazurskie oferują dobre warunki do żeglarstwa wraz z rozbudowaną infrastrukturą.","correct":true,"explain":"Mazury to obszar żeglarski z rozbudowaną infrastrukturą, gdzie uprawia się także windsurfing i kitesurfing."},{"type":"flash","front":"Jakie aktywności umożliwia francuska rzeka Dordogne?","back":"Kajakarstwo łączone z turystyką kulturową - można płynąć rzeką, zatrzymując się, by spróbować lokalnej kuchni i zobaczyć sielskie miasteczka."}]},{"id":"kreatywne-myslenie-definicja-branze","wiki":[{"heading":"Definicja","body":"Kreatywne myslenie to trwala postawa czlowieka powodujaca podejmowanie dzialan przynoszacych wartosciowe nowosci. To dzialanie, ktorego celem jest zmiana stanu koniecznosci w stan wyboru. Jest to proces umyslowy prowadzacy do generowania nowych i oryginalnych idei, rozwiazan lub koncepcji, ktore sa uzyteczne i przydatne."},{"heading":"Istota","body":"Innymi slowy, jest to zdolnosc do myslenia nieszablonowego, wykraczajacego poza tradycyjne schematy myslenia."},{"heading":"Branze, w ktorych jest atutem","bullets":["filmografia","teatr","marketing","grafika komputerowa","edukacja","przewodnictwo i pilotaz","animatorka","projektowanie gier","fotografia"]}],"questions":[{"type":"abcd","q":"Czym jest kreatywne myslenie wedlug definicji?","options":["Zdolnoscia do szybkiego liczenia w pamieci","Umiejetnoscia wiernego odtwarzania znanych schematow","Procesem umyslowym prowadzacym do generowania nowych i oryginalnych idei, ktore sa uzyteczne i przydatne","Postawa unikania jakichkolwiek zmian"],"correct":2,"explain":"To proces umyslowy prowadzacy do generowania nowych i oryginalnych idei, rozwiazan lub koncepcji, ktore sa uzyteczne i przydatne."},{"type":"tf","q":"Kreatywne myslenie zmienia stan koniecznosci w stan wyboru.","correct":true,"explain":"Wprost wynika z definicji: celem dzialania kreatywnego jest zmiana stanu koniecznosci w stan wyboru."},{"type":"flash","front":"Wymien przynajmniej piec branz, w ktorych kreatywne myslenie jest duzym atutem.","back":"M.in.: filmografia, teatr, marketing, grafika komputerowa, edukacja, przewodnictwo i pilotaz, animatorka, projektowanie gier, fotografia."}]},{"id":"techniki-kreatywnego-myslenia","wiki":[{"heading":"Techniki dyskusyjne i grupowe","bullets":["Uproszczona debata oksfordzka - sformalizowana dyskusja, w ktorej dwie druzyny toczą spor wokol postawionej tezy; jedna strona udowadnia jej prawdziwosc, druga ja obala","Odwrocona burza mozgow - zasady klasycznej burzy mozgow stosowane do wyroznienia jak najwiekszej liczby wad obiektu analizy, by je nastepnie wyeliminowac","Metoda 635 - rodzaj brainwritingu: 6 uczestnikow wymysla 3 pomysly w 5 minut, zapisujac je na formularzu przekazywanym osobie po prawej","Dyskusja piramidowa - przechodzenie od pracy indywidualnej, przez pary, czworki, osemki, do wspolnego stanowiska zespolu"]},{"heading":"Metody analizy z wielu perspektyw","bullets":["Technika 6 kapeluszy De Bono - mylenie lateralne; wcielanie sie w 6 rol (bialy - dane, czerwony - emocje, czarny - zagrozenia, zolty - korzysci, zielony - nowe pomysly, niebieski - zarzadzanie procesem)","Metoda 3 krzesel Disneya - analiza z trzech perspektyw: marzyciel, realista i krytyk","Drzewko decyzyjne (mind mapping) - graficzna technika wspomagania decyzji; korzen i galezie prowadzace do kolejnych wierzcholkow, ulatwia strukturyzowanie pomyslow"]},{"heading":"Techniki modyfikacji i analizy przyczyn","bullets":["SCAMPER - akronim siedmiu dzialan: Substitute (zastapic), Combine (polaczyc), Adapt (dostosowac), Modify (zmodyfikowac), Put to another use (zastosowac inaczej), Eliminate (usunac), Reverse (odwrocic)","Diagram Ishikawy (rybia osc) - analiza przyczynowo-skutkowa; 5 skladowych: ludzie, metody, maszyny, materialy, zarzadzanie"]}],"questions":[{"type":"abcd","q":"Na czym polega metoda 635?","options":["Szesciu uczestnikow wymysla po trzy pomysly w ciagu pieciu minut, zapisujac je na przekazywanych formularzach","Trzy osoby debatuja przez szesc rund po piec minut","Szesc kapeluszy zmienia sie co trzy minuty piec razy","Trzech ekspertow ocenia szesc projektow w piec dni"],"correct":0,"explain":"Nazwa wynika z zasad: 6 uczestnikow, 3 pomysly, 5 minut - to rodzaj brainwritingu, w ktorym pomysly nie sa wypowiadane na glos."},{"type":"abcd","q":"Co oznacza litera \"S\" w technice SCAMPER?","options":["Separate - rozdzielic","Simplify - uproscic","Standardize - ujednolicic","Substitute - zastapic"],"correct":3,"explain":"SCAMPER to: Substitute, Combine, Adapt, Modify, Put to another use, Eliminate, Reverse. \"S\" oznacza Substitute (zastapic)."},{"type":"tf","q":"W metodzie 3 krzesel Disneya wystepuja role: marzyciel, inwestor i sprzedawca.","correct":false,"explain":"Trzy role w metodzie Disneya to marzyciel, realista i krytyk — nie inwestor czy sprzedawca."},{"type":"flash","front":"Jakie sa kolory i role kapeluszy w technice 6 kapeluszy De Bono?","back":"Bialy - dane i informacje; czerwony - intuicja i emocje; czarny - zagrozenia; zolty - korzysci; zielony - nowe pomysly; niebieski - zarzadzanie procesem myslowym."}]},{"id":"cwiczenia-pobudzajace-kreatywnosc","wiki":[{"heading":"Trzydziesci kolek","body":"Cwiczenie mozna wykonac indywidualnie lub w grupach. Na szablonie znajduje sie trzydziesci kolek. W jak najkrotszym czasie nalezy narysowac w kazdym cos innego, trzymajac sie jednego tematu, np. \"jesien\" lub \"wakacje\"."},{"heading":"Ciag skojarzeniowy logiczny","body":"Nalezy wybrac dwa rzeczowniki i stworzyc ciag skojarzen, ktory logicznie prowadzi od jednego do drugiego, np.: kloda - drzewo - las - jezioro - wakacje - kolonie - nastolatki - pryszcz."},{"heading":"Opowiesc logiczna","body":"Polega na wymysleniu sensacyjnego naglowka (np. \"Co by bylo, gdyby czlowiek polecial na Marsa\") oraz absurdalnego zakonczenia (np. \"i wlasnie dlatego psy nie jedza czekolady\"), a nastepnie zbudowaniu sensownej opowiesci laczacej naglowek z zakonczeniem."}],"questions":[{"type":"abcd","q":"Na czym polega cwiczenie \"ciag skojarzeniowy logiczny\"?","options":["Na stworzeniu ciagu skojarzen logicznie prowadzacego od jednego wybranego rzeczownika do drugiego","Na narysowaniu rzeczy w trzydziestu kolkach na jeden temat","Na napisaniu opowiesci laczacej naglowek z zakonczeniem","Na ocenie pomyslu z trzech punktow widzenia"],"correct":0,"explain":"Wybiera sie dwa rzeczowniki i buduje ciag skojarzen logicznie prowadzacy od jednego do drugiego, np. kloda - drzewo - las."},{"type":"tf","q":"Cwiczenie \"trzydziesci kolek\" mozna wykonywac zarowno indywidualnie, jak i w grupach.","correct":true,"explain":"W opisie cwiczenia wprost zaznaczono, ze mozna je wykonac zarowno indywidualnie, jak i w grupach."},{"type":"flash","front":"Na czym polega cwiczenie \"opowiesc logiczna\"?","back":"Na wymysleniu sensacyjnego naglowka i absurdalnego zakonczenia, a nastepnie zbudowaniu sensownej opowiesci laczacej jedno z drugim."}]},{"id":"tramping-backpacking-hiking","wiki":[{"heading":"Tramping","body":"Tramping oznacza niezalezne i tanie organizowanie wypraw w bliskim kontakcie z natura, lokalnymi kulturami i mieszkancami. Slowo pochodzi od angielskiego \"to tramp\" - wedrowac, wloczyc sie; termin zaczeto uzywac w Nowej Zelandii i Australii na poczatku XX wieku.","bullets":["Podrozowanie w niewielkich grupach, zazwyczaj do 12 osob","Organizacja noclegow i przejazdow przez biuro, opcje przystepne cenowo","Rozne srodki transportu: pociagi, autobusy, taksowki, jeepy, lodzie, promy, riksze","Noclegi w hotelach 3-gwiazdkowych, motelach, czasem jurtach, namiotach lub domach mieszkancow","Trwa zazwyczaj dluzej niz tydzien; duza elastycznosc i spontanicznosc"]},{"heading":"Backpacking","body":"Forma turystyki oznaczajaca aktywnosc podroznicza na danym obszarze bez nadmiernego wydawania pieniedzy, czesto pieszo, z rzeczami w plecaku. Wymaga umiejetnosci poslugiwania sie sprzetem oraz przygotowania fizycznego i psychicznego. Backpackersi czesto okreslaja sie mianem antyturystow, podrozuja samotnie lub w malych grupach. Polska wersja backpackingu jest tramping - pojecie wprowadzone do opracowan turystycznych w 1975 roku przez Bogdana Opowicza. Roznica: tramping zazwyczaj realizowany jest w grupach i ma z gory opracowany zarys lub cel.","bullets":["Turysta sam organizuje wyjazd, nie kupuje gotowego pakietu uslug","Stoi w opozycji do turystyki masowej","Szansa na realizacje idei turystyki zrownowazonej","Zagrozenia: \"efekt gapowicza\", pobiezne poznanie kultury, pogardliwe podejscie do innych turystow"]},{"heading":"Hiking","body":"Piesza wedrowka w terenie naturalnym, zazwyczaj poza miastem, na wyznaczonych szlakach, trwajaca zazwyczaj jeden dzien. Najczesciej forma rekreacji i przyjemnego spedzania czasu na swiezym powietrzu.","bullets":["Krotkie, zazwyczaj jednodniowe wyprawy w lasach, gorach, parkach krajobrazowych, terenach wiejskich","Nie wymaga specjalnego przygotowania fizycznego ani dlugotrwalego treningu","Zazwyczaj bez noclegow w terenie; dostepny dla wszystkich bez wzgledu na wiek","Roznica wobec trekkingu: trekking ma wyzszy prog wejscia, odbywa sie na wymagajacych terenach i trwa kilka dni"]}],"questions":[{"type":"abcd","q":"Czym rozni sie tramping od backpackingu?","options":["Tramping odbywa sie wylacznie samotnie i bez planu","Tramping jest zawsze drozszy od turystyki masowej","Tramping zazwyczaj realizowany jest w grupach i ma z gory opracowany zarys lub cel","Tramping nie wymaga zadnego transportu"],"correct":2,"explain":"Tramping (polska wersja backpackingu) rozni sie tym, ze wyjazd realizowany jest w grupach oraz ma z gory opracowany zarys lub cel."},{"type":"abcd","q":"Ile osob liczy zazwyczaj grupa trampingowa?","options":["Co najmniej 30 osob","Do 50 osob","Dokladnie 6 osob","Do 12 osob"],"correct":3,"explain":"Tramping to podrozowanie w niewielkich grupach, zazwyczaj do 12 osob."},{"type":"tf","q":"Hiking to zazwyczaj wielotygodniowa, wymagajaca wyprawa, ktora wymaga dlugotrwalego treningu i specjalistycznego sprzetu.","correct":false,"explain":"To raczej opis dlugich wypraw/trekkingu; hiking to krotkie, zwykle jednodniowe wedrowki na wyznaczonych szlakach, bez specjalnego przygotowania."},{"type":"flash","front":"Skad pochodzi slowo \"tramping\" i kto wprowadzil pojecie \"tramping\" do polskich opracowan turystycznych?","back":"Slowo pochodzi od angielskiego \"to tramp\" (wedrowac, wloczyc sie); termin zaczeto uzywac w Nowej Zelandii i Australii na poczatku XX wieku. Do polskich opracowan turystycznych pojecie wprowadzil Bogdan Opowicz w 1975 roku."}]},{"id":"prawne-aspekty-projektow-outdoorowych","wiki":[{"body":"Projekty outdoorowe w turystyce i rekreacji (np. trasy rowerowe, sciezki edukacyjne, wieze widokowe, miejsca piknikowe, silownie plenerowe, wypozyczalnie sprzetu wodnego) sa popularne, ale wymagaja spelnienia wielu prawnych obowiazkow ze wzgledu na lokalizacje (czesto w srodowisku naturalnym) i funkcje publiczna. Dla otwartych obiektow zalecane jest opracowanie wewnetrznego regulaminu korzystania lub posiadanie odpowiednich atestow."},{"heading":"Kluczowe dokumenty i podstawy prawne","bullets":["Pozwolenia administracyjne i planowanie przestrzenne - zgodnosc z miejscowym planem zagospodarowania przestrzennego lub decyzja o warunkach zabudowy (Ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym)","Prawo budowlane - pozwolenie na budowe (wieze widokowe, budynki zaplecza), zgloszenie budowy (wiaty, mala architektura) lub zwolnienie (np. oznakowanie szlakow) (Ustawa z 7 lipca 1994 r. - Prawo budowlane)","Ochrona srodowiska i przyrody oraz wycinka drzew - lokalizacja w terenach chronionych lub lasach panstwowych wymaga zgod, np. Regionalnej Dyrekcji Ochrony Srodowiska (Ustawa z 16 kwietnia 2004 r. o ochronie przyrody)","Prawo wlasnosci i dostepnosc terenu - prawo do dysponowania nieruchomoscia: wlasnosc, dzierzawa, uzyczenie (Kodeks cywilny)","Bezpieczenstwo - wymogi bezpieczenstwa konstrukcyjnego, przeciwpozarowego i sanitarnego (Prawo budowlane)","Zgloszenia wydarzen outdoorowych - splywy, rajdy, pikniki masowe wymagaja zgloszenia do gminy lub organow porzadkowych (Ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r.)"]}],"questions":[{"type":"abcd","q":"Ktora ustawa stanowi podstawe prawna ochrony srodowiska i przyrody przy projektach outdoorowych?","options":["Ustawa z 16 kwietnia 2004 r. o ochronie przyrody","Ustawa z 7 lipca 1994 r. - Prawo budowlane","Ustawa z 27 marca 2003 r. o planowaniu i zagospodarowaniu przestrzennym","Ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r."],"correct":0,"explain":"Ochrona srodowiska i przyrody oraz wycinka drzew opieraja sie na Ustawie z 16 kwietnia 2004 r. o ochronie przyrody."},{"type":"tf","q":"Organizacja masowego spływu lub rajdu moze wymagac zgloszenia do gminy lub organow porzadkowych na podstawie ustawy o bezpieczenstwie imprez masowych.","correct":true,"explain":"Zgloszenia wydarzen outdoorowych (splyw, rajd, piknik masowy) wymagaja zgloszenia do gminy lub organow porzadkowych - podstawa prawna to ustawa o bezpieczenstwie imprez masowych z 20 marca 2009 r."},{"type":"flash","front":"Jaki dokument reguluje prawo do dysponowania nieruchomoscia (wlasnosc, dzierzawa, uzyczenie) przy projekcie outdoorowym?","back":"Kodeks cywilny - reguluje prawo do dysponowania nieruchomoscia na cele budowlane (wlasnosc, dzierzawa, uzyczenie), m.in. poprzez umowy cywilnoprawne."}]},{"id":"rodzaje-turystyki-trekkingowej","wiki":[{"heading":"Podzial wg pory roku","bullets":["Trekking letni - mniej ubran i sprzetu z uwagi na wyzsza temperature, lzejszy ekwipunek; konieczna ochrona przed sloncem (kremy, czapki)","Trekking zimowy - wymaga wiekszych umiejetnosci, odziezy warstwowej, specjalistycznego sprzetu (raki, czekany); wiaze sie z ryzykiem lawinowym i mrozem"]},{"heading":"Podzial wg miejsca (m.in. wg P. Rozyckiego)","bullets":["Klasyczny (gorski) - forma posrednia miedzy wspinaczka a turystyka piesza, wymaga przygotowania psychofizycznego, czesto trwa kilka dni","Pustynny - skrajne temperatury, monotonia krajobrazu, burze piaskowe; dla doswiadczonych trekkerow, np. Wadi Rum w Jordanii","Tropikalny - gęste lasy i dzungle, klimat rownikowy, wilgoc; zagrozenia: burze, ulewy, owady i choroby zakazne (malaria)","Lodowcowy - niebezpieczny teren w strefach polarnych i wysokich gorach; ryzyko poslizgniecia i wpadniecia w szczeline, np. Chamonix w Alpach","Polarny - ekstremalnie niskie temperatury, arktyczne tundry; cel: biegun, zorza polarna; np. Spitsbergen, polnocna Skandynawia","Rzeczny (rafting) - na rwacych rzekach, na pontonach lub tratwach; ryzyko: prady wodne, sliski teren, duze predkosci; np. Lena na Syberii","Bagienny - krotka wyprawa przez podmokly teren z kijkami i przewodnikiem; trudnosci: brak solidnego podloza, osuwiska, komary; np. Biebrza, Amazonka","Wulkaniczny - po wygaslych (podobny do klasycznego) lub aktywnych wulkanach (czesto po zmroku); ryzyko: toksyczne gazy, erupcja, np. Teide na Teneryfie"]}],"questions":[{"type":"abcd","q":"Ktory rodzaj trekkingu znany jest rowniez jako rafting?","options":["Pustynny","Bagienny","Lodowcowy","Rzeczny"],"correct":3,"explain":"Trekking rzeczny znany jest rowniez jako rafting - uprawiany na rwacych rzekach na pontonach lub tratwach, np. na syberyjskiej Lenie."},{"type":"abcd","q":"Jakie glowne zagrozenie zdrowotne wiaze sie z trekkingiem tropikalnym?","options":["Ryzyko lawinowe i odmrozenia","Owady i przenoszone przez nie choroby zakazne, np. malaria","Burze piaskowe i odwodnienie","Toksyczne gazy wulkaniczne"],"correct":1,"explain":"W trekkingu tropikalnym niebezpieczenstwo stanowia zwierzeta, szczegolnie owady i przenoszone przez nie choroby zakazne, np. malaria."},{"type":"tf","q":"Trekking zimowy wymaga specjalistycznego sprzetu, takiego jak raki i czekany, oraz wiaze sie z ryzykiem lawinowym.","correct":true,"explain":"Trekking zimowy wymaga odziezy warstwowej i specjalistycznego sprzetu (raki, czekany), a takze wiaze sie z ryzykiem lawinowym i mrozem."},{"type":"flash","front":"Wymien rodzaje trekkingu wedlug podzialu ze wzgledu na miejsce wyprawy.","back":"Klasyczny (gorski), pustynny, tropikalny, lodowcowy, polarny, rzeczny (rafting), bagienny i wulkaniczny."}]},{"id":"roznice-konflikty-kulturowe","wiki":[{"body":"Roznice kulturowe sa powszechne i stanowia zarowno zrodlo bogactwa, jak i potencjalnych konfliktow. Wzrost migracji, globalizacja i wieksza swiadomosc innych kultur prowadza do wiekszej ekspozycji na roznice, ale takze do napiec. Konflikty moga wynikac ze zderzenia kultur, np. podroze w celu zobaczenia \"dzikiego\", spotkanie kultur religijnych, zderzenie codzienne czy zderzenie stereotypowe."},{"heading":"Zjawiska prowadzace do konfliktow","bullets":["Etnocentryzm - przekonanie, ze wlasne etno zajmuje centralne, uprzywilejowane miejsce i ocenia innych przez pryzmat wlasnych przekonan","Ludzkie zoo (kanibalizm turystyczny) - traktowanie przedstawicieli innej kultury przedmiotowo, jak atrakcje","Zle pojmowana autentycznosc - turysta nie dopuszcza odstepstw od swojego obrazu tubylca","Stereotypy - uproszczony, emocjonalny i czesto falszywy obraz osoby lub grupy","Uprzedzenie - negatywne nastawienie emocjonalne oparte na stereotypie","Ksenofobia - lek przed poznawaniem nowych, nieznanych osob","Dyskryminacja - skutek uprzedzen, odrzucenie osoby lub grupy","Rasizm - odrzucenie ze wzgledu na kolor skory; Eksterminacja - likwidacja grupy narodowosciowej"]},{"heading":"Zasada DIE i domeny konfliktow","body":"Dla unikania konfliktow wazna jest zasada DIE: Description (opis - to co widze), Interpretation (interpretacja - to co mysle), Evaluation (ewaluacja - to co oceniam). W modelu blednym pomijamy opis i przechodzimy od razu do oceny.","bullets":["Trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia","Spory o terytorium: np. pakistansko-indyjski o Kaszmir, japonsko-rosyjski o Kuryle, argentynsko-brytyjski o Falklandy/Malwiny","Spory o jezyk: np. Flamandowie w Belgii, Katalonczycy w Hiszpanii","Konflikty religijne: miedzy religiami swiatowymi i w ramach odlamow (np. katolicy/protestanci w Irlandii Polnocnej)"]}],"questions":[{"type":"abcd","q":"Co opisuje zasada DIE wspierajaca komunikacje miedzykulturowa?","options":["Opis sytuacji, interpretacje i ewaluacje (description, interpretation, evaluation)","Dialog, integracje i edukacje","Decyzje, implementacje i ewaluacje","Dyskryminacje, izolacje i eksterminacje"],"correct":0,"explain":"Zasada DIE sklada sie z opisu sytuacji (description), interpretacji (interpretation) i ewaluacji (evaluation). Pominiecie opisu prowadzi do konfliktu."},{"type":"abcd","q":"Ktore sa trzy zasadnicze domeny konfliktow kulturowych?","options":["Wiek, plec i wyksztalcenie","Ekonomia, technologia i ekologia","Terytorium, jezyk i religia","Sport, sztuka i nauka"],"correct":2,"explain":"Wyrozniamy trzy zasadnicze domeny konfliktow kulturowych: terytorium, jezyk i religia."},{"type":"tf","q":"Ksenofilia to lek przed poznawaniem nowych, nieznanych osob, ktory objawia sie izolacja i niecheicia.","correct":false,"explain":"Taki lek to ksenofobia; ksenofilia oznacza przeciwnie — sympatie i upodobanie do tego, co obce i nieznane."},{"type":"flash","front":"Czym jest etnocentryzm?","back":"Postawa i przekonanie, ze wlasne etno (spoleczenstwo) zajmuje centralne, uprzywilejowane miejsce w swiecie, a innych ocenia sie przez pryzmat wlasnych przekonan."}]},{"id":"ryzyka-projektow-turystycznych","wiki":[{"heading":"Definicja i zarzadzanie ryzykiem","body":"Ryzyko to mozliwosc wystapienia zdarzenia, ktore wplynie negatywnie na cele projektu. Celem zarzadzania ryzykiem jest identyfikacja zagrozen, przygotowanie sie do nich (profilaktyka, reakcja) i minimalizacja wplywu/skutkow.","bullets":["Ustanowienie polityk, procedur, systemow i standardow oraz opracowanie dokumentacji (podreczniki, instrukcje, broszury)","Wdrozenie zasad, procedur i standardow (szkolenia, cwiczenia kontrolne, audyty, przeglady)","Identyfikacja ryzyk (jakie, ocena, wplyw, skutki), profilaktyka, scenariusze postepowania i monitorowanie","Zasadnicze techniki: eliminacja, redukcja, transfer lub akceptacja"]},{"heading":"Rodzaje ryzyk","bullets":["Ekonomiczne - inflacja, spadek wartosci walut, zmiany stop procentowych, ogolna sytuacja ekonomiczna","Srodowiskowe - kleski zywiolowe, zmiany klimatu, zanieczyszczenie, ochrona przyrody","Geopolityczne - konflikty, napiecia polityczne, zmiany w polityce migracyjnej","Spoleczne - bezpieczenstwo turystow, zmiany w zachowaniach konsumenckich, zmiany demograficzne, konflikt kulturowy","Technologiczne - cyberataki, awarie systemow informacyjnych, rozwoj nowych technologii","Specyficzne dla turystyki - sezonowosc, konkurencja, zmiany przepisow, jakosc uslug, marketing, bezpieczenstwo i zdrowie turystow, skutki turystyki masowej","Zwiazane z lokalizacja - warunki naturalne, dostepnosc infrastruktury, poziom rozwoju spoleczno-gospodarczego, lokalne tradycje i kultura"]}],"questions":[{"type":"abcd","q":"Ktore z ponizszych to zasadnicze techniki zarzadzania ryzykiem?","options":["Eliminacja, redukcja, transfer lub akceptacja","Inflacja, deflacja, stagnacja i recesja","Identyfikacja, marketing, sprzedaz i serwis","Opis, interpretacja, ewaluacja i ocena"],"correct":0,"explain":"Zasadnicze techniki zarzadzania ryzykiem to eliminacja, redukcja, transfer lub akceptacja."},{"type":"abcd","q":"Do ktorej kategorii ryzyk zalicza sie cyberataki i awarie systemow informacyjnych?","options":["Ekonomicznych","Technologicznych","Srodowiskowych","Geopolitycznych"],"correct":1,"explain":"Ryzyka technologiczne sa zwiazane z cyberatakami, awariami systemow informacyjnych oraz rozwojem nowych technologii i ich wplywem na turystyke."},{"type":"tf","q":"Ryzyko definiuje sie jako zdarzenie, ktore na pewno wystapi i zawsze pozytywnie wplynie na cele projektu.","correct":false,"explain":"Ryzyko to mozliwosc (niepewnosc) wystapienia zdarzenia wplywajacego negatywnie na cele projektu, a nie zdarzenie pewne i korzystne."},{"type":"flash","front":"Wymien glowne rodzaje ryzyk w projektach turystycznych.","back":"Ekonomiczne, srodowiskowe, geopolityczne, spoleczne, technologiczne, specyficzne dla turystyki oraz zwiazane z konkretna lokalizacja."}]},{"id":"turystyka-przygodowa-niepelnosprawnosc","wiki":[{"heading":"Stopnie i kategorie niepelnosprawnosci","body":"W Polsce jest 3 miliony osob z prawnie potwierdzona niepelnosprawnoscia. Ustala sie trzy stopnie: znaczny (niezdolnosc do zatrudnienia lub praca w zakladzie chronionym, wymagana stala/dlugotrwala opieka), umiarkowany (praca na przystosowanym stanowisku, czesciowa/okresowa pomoc) i lekki (zdolnosc do zatrudnienia bez potrzeby pomocy).","bullets":["upoSledzeni umyslowo","glusi","niewidomi","niedostosowani spolecznie","przewlekle chorzy somatycznie, nerwowo, psychicznie","osoby z uszkodzeniem narzadu ruchu","osoby z glebszymi zaburzeniami mowy"]},{"heading":"Znaczenie i cele","body":"Turystyka osob z niepelnosprawnoscia to zamierzona, celowa, dobrana do potrzeb aktywnosc fizyczna zwiazana z aktywnoscia krajoznawcza. Glownymi celami sa zmniejszenie skutkow ograniczenia aktywnosci fizycznej oraz zapelnienie czasu wolnego.","bullets":["Wplywa na rozwoj osobowosci, wspomaga i przyspiesza rehabilitacje","Podnosi samopoczucie, sprawnosc i wydolnosc fizyczna oraz przystosowanie spoleczne","Pozwala przezwyciezyc leki i kompleksy, zapobiega wtornym zmianom po zabiegach","Aktywnosc powinna byc: bezpieczna (dostosowana obciazeniowo), zaadaptowana (uwzgledniajaca ograniczenia) i efektywna (rozwijajaca mozliwosci)"]},{"heading":"Czynniki przy programowaniu i metodyka","body":"Programujac aktywnosc nalezy pamietac m.in. o: funkcjach ruchowych i czuciowych, ukladzie sercowo-naczyniowym, termoregulacji, ukladzie oddechowym i wydalniczo-moczowym, autonomicznej dysrefleksji, spastycznosci, stosowanych lekach, osteoporozie oraz koordynacji.","bullets":["Wzbudzanie motywacji i entuzjazmu poprzez stymulacje zdolnosci, zainteresowan i ambicji","Indywidualne traktowanie kazdego cwiczacego i znajomosc jego problemow","Metody nauczania: slowne, kinestetyczne (angazowanie aktywnosci miesniowej, kojarzenie wzrokowo-ruchowe) i wzrokowe (pokaz bezposredni lub multimedialny)"]}],"questions":[{"type":"abcd","q":"Ile stopni niepelnosprawnosci ustala sie w Polsce?","options":["Cztery stopnie","Dwa: ciezki i lekki","Trzy: znaczny, umiarkowany i lekki","Piec stopni"],"correct":2,"explain":"Ustala sie trzy stopnie niepelnosprawnosci: znaczny, umiarkowany i lekki."},{"type":"abcd","q":"Jakie trzy cechy powinna miec aktywnosc turystyczna programowana dla osob z niepelnosprawnoscia?","options":["Bezpieczna, zaadaptowana i efektywna","Tania, krotka i masowa","Spontaniczna, indywidualna i ryzykowna","Sezonowa, lokalna i komercyjna"],"correct":0,"explain":"Aktywnosc powinna byc bezpieczna (dostosowana obciazeniowo), zaadaptowana (uwzgledniajaca ograniczenia uczestnikow) i efektywna (rozwijajaca ich mozliwosci)."},{"type":"tf","q":"Uczestnictwo osob z niepelnosprawnoscia w turystyce wspomaga i przyspiesza proces rehabilitacji.","correct":true,"explain":"Wsrod efektow uczestnictwa wymienia sie wspomaganie i przyspieszanie procesu rehabilitacji oraz podnoszenie sprawnosci i przystosowania spolecznego."},{"type":"flash","front":"Jakie metody nauczania wyroznia sie w pracy z osobami z niepelnosprawnoscia w turystyce?","back":"Metody slowne, kinestetyczne (angazowanie aktywnosci miesniowej, np. kojarzenie wzrokowo-ruchowe) oraz wzrokowe (pokaz bezposredni lub posredni za pomoca srodkow multimedialnych)."}]},{"id":"turystyka-przygodowa-dzieci","wiki":[{"heading":"Podstawa prawna","body":"Organizację wypoczynku dla dzieci i młodzieży określają przepisy ustawy z dnia 7 września 1991 r. o systemie oświaty oraz Rozporządzenie Ministra Edukacji Narodowej z dnia 30 czerwca 2016 r. w sprawie wypoczynku dzieci i młodzieży.","bullets":["termin złożenia zgłoszenia wypoczynku oraz przekazania karty wypoczynku","liczba uczestników w grupie pod opieką jednego wychowawcy","obowiązki kierownika i wychowawcy wypoczynku, w tym prowadzenie dziennika zajęć","program kursów na kierownika albo wychowawcę wypoczynku, wzór karty kwalifikacyjnej i zaświadczenia"]},{"heading":"Limity liczebności grup i terminy zgłoszeń","bullets":["liczba uczestników pod opieką jednego wychowawcy nie może przekraczać 20 osób","dla grupy z dziećmi do 10. roku życia (lub grupy mieszanej z takimi dziećmi) limit wynosi 15 osób","dopuszcza się udział nie więcej niż 2 uczestników niepełnosprawnych lub przewlekle chorych w grupie jednego wychowawcy","zgłoszenie wypoczynku składa się nie później niż na 21 dni przed terminem rozpoczęcia, a dla półkolonii lub wypoczynku za granicą — nie później niż na 14 dni"]},{"heading":"Obowiązki kierownika i wychowawcy","body":"Kierownik kieruje wypoczynkiem, opracowuje plan pracy i rozkład dnia, przydziela zadania kadrze i kontroluje ich wykonanie, zapewnia opiekę od przejęcia dzieci od rodziców do przekazania ich z powrotem oraz nadzoruje bezpieczne i higieniczne warunki. Wychowawca zapoznaje się z kartami kwalifikacyjnymi uczestników, informuje kierownika o ich specjalnych potrzebach, prowadzi dziennik zajęć, opracowuje plan pracy grupy i realizuje program zgodnie z rozkładem dnia."},{"heading":"Cele i formy turystyki przygodowej dzieci","body":"Realizowane cele dzieli się na poznawczo-kształtujące, wychowawcze oraz rekreacyjno-zdrowotne (m.in. wypoczynkowe, restytucyjne, zabawowe, kondycyjne).","bullets":["wycieczki: lekcje (spacery), programowo-dydaktyczne, krajobrazowe, turystyczno-krajoznawcze","turystyka kwalifikowana: piesza, rowerowa, żeglarska, narciarska, motorowa, kajakowa","imprezy turystyki kwalifikowanej: rajd, spływ, rejs, zlot, złaz, biwak, kolonie, imprezy na orientację, obozy wędrowne i stałe","szkoły: zielona, biała/zimowa, ekologiczna"]}],"questions":[{"type":"abcd","q":"Ilu uczestników może maksymalnie pozostawać pod opieką jednego wychowawcy w grupie mieszanej z dziećmi do 10. roku życia?","options":["10 osób","25 osób","20 osób","15 osób"],"correct":3,"explain":"Standardowy limit to 20 osób, ale dla grup z dziećmi do 10. roku życia oraz grup mieszanych z takimi dziećmi limit wynosi 15 osób."},{"type":"tf","q":"Do obowiązków wychowawcy wypoczynku należy prowadzenie dziennika zajęć realizowanych podczas wypoczynku.","correct":true,"explain":"Rozporządzenie nakłada na wychowawcę obowiązek prowadzenia dziennika zajęć, którego wzór określa załącznik nr 5."},{"type":"flash","front":"Jakie akty prawne regulują organizację wypoczynku dzieci i młodzieży?","back":"Ustawa z 7 września 1991 r. o systemie oświaty oraz Rozporządzenie MEN z 30 czerwca 2016 r. w sprawie wypoczynku dzieci i młodzieży."},{"type":"flash","front":"Wymień trzy grupy celów turystyki przygodowej dzieci i młodzieży.","back":"Cele poznawczo-kształtujące, wychowawcze oraz rekreacyjno-zdrowotne."}]},{"id":"typologia-form-aktywnosci-terenowej","wiki":[{"heading":"Podział według poziomu ryzyka","body":"Na podstawie poziomu ryzyka wyróżniono formy twarde i miękkie aktywności terenowej. Formy miękkie uprawiają osoby zainteresowane przeżyciem przygody o niewielkim stopniu ryzyka. Formy twarde charakteryzują się wysokim poziomem ryzyka — np. ryzykiem poważnych obrażeń ciała, a nawet śmierci. Odczucie ryzyka jest jednak pojęciem subiektywnym."},{"heading":"Formy miękkie i twarde","bullets":["miękkie: backpacking, birdwatching, camping, kajakarstwo, wędkarstwo, trekking, bieg na orientację, safari, nurkowanie","twarde: speleologia, wspinaczka skałkowa, wspinaczka lodowa, trekking w niebezpiecznym terenie, spadochroniarstwo, paralotniarstwo"]},{"heading":"Inne typologie","bullets":["według skali: formy małej skali (elementy ekoturystyki), średniej skali (elementy sportowe), dużej skali (cechy turystyki masowej)","według przestrzeni realizacji: w powietrzu (loty balonem), na wodzie (windsurfing), na lądzie (wyprawy rowerowe)"]}],"questions":[{"type":"abcd","q":"Która z wymienionych aktywności należy do form twardych aktywności terenowej?","options":["Birdwatching","Camping","Wspinaczka lodowa","Wędkarstwo"],"correct":2,"explain":"Wspinaczka lodowa charakteryzuje się wysokim poziomem ryzyka, więc zaliczana jest do form twardych; pozostałe to formy miękkie."},{"type":"tf","q":"Odczucie ryzyka w aktywności terenowej jest pojęciem obiektywnym, jednakowym dla wszystkich uczestników.","correct":false,"explain":"Odczucie ryzyka jest pojęciem subiektywnym i różni się w zależności od uczestnika."},{"type":"flash","front":"Według jakiego kryterium dzieli się aktywności terenowe na twarde i miękkie?","back":"Według poziomu ryzyka — formy miękkie mają niewielki stopień ryzyka, twarde wysoki (zagrożenie poważnymi obrażeniami, a nawet śmiercią)."}]},{"id":"wyprawy-trampingowe-zasady-organizacji","wiki":[{"heading":"Baza informacji i kontakty lokalne","body":"Podstawą organizacji wypraw trampingowych jest zgromadzenie dużej bazy informacji o miejscu podróży — zarówno o atrakcjach turystycznych, jak i o warunkach panujących w przestrzeni (bezpieczeństwo, pogoda, opłaty). Organizator musi nawiązać kontakty z lokalnymi przedsiębiorcami, aby zorganizować nocleg, transport lub inne usługi."},{"heading":"Program i informacje praktyczne","body":"Program wycieczki powinien być elastyczny i dopasowany do możliwości grupy, która się zgłosi; należy zaznaczyć wymagany poziom sprawności fizycznej i zastrzec sobie prawo do zmian w sytuacjach nieprzewidzianych. Przygotowuje się informacje praktyczne o charakterze wyprawy, przelotach, zakwaterowaniu, transporcie, klimacie, wyżywieniu, ubezpieczeniu, przepisach rezygnacji i kosztach (w tym dodatkowych). Analizuje się dystans i przewyższenia trasy, by oszacować czas potrzebny na pokonanie szlaku, oraz weryfikuje zagrożenia i np. wymagane szczepionki."},{"heading":"Specyfika trampingu i rola pilota","body":"W trampingu dąży się do ograniczenia kosztów — korzysta się z noclegów o niższym standardzie, a wyprawy projektuje dla mniejszych grup. Ważny jest aspekt kulturowy: prawdziwy kontakt uczestników ze społecznością i miejscem. Najważniejszym ogniwem jest rola pilota wyprawy — musi być elastyczny i sprawny w kontaktach międzyludzkich, jest pośrednikiem między turystami, biurem a lokalną społecznością. Tramping wymaga otwartości na dialog międzykulturowy oraz znoszenia trudów podróży, a grupa często wspólnie decyduje o organizacji wyżywienia i mniej istotnych punktów programu."}],"questions":[{"type":"abcd","q":"Co jest podstawą organizacji wyprawy trampingowej?","options":["Wykupienie noclegów o najwyższym standardzie","Ograniczenie kontaktu z lokalną społecznością","Zaplanowanie sztywnego, niezmiennego programu","Zgromadzenie dużej bazy informacji o miejscu podróży"],"correct":3,"explain":"Podstawą jest zgromadzenie dużej bazy informacji o miejscu — o atrakcjach oraz o warunkach (bezpieczeństwo, pogoda, opłaty)."},{"type":"tf","q":"W trampingu dąży się do ograniczenia kosztów, dlatego korzysta się z noclegów o niższym standardzie.","correct":true,"explain":"Tramping nastawiony jest na ograniczenie kosztów — stąd tańsze noclegi i mniejsze grupy."},{"type":"flash","front":"Jaka jest rola pilota w wyprawie trampingowej?","back":"Pilot to najważniejsze ogniwo wyprawy — elastyczny pośrednik między turystami, biurem a lokalną społecznością, dobrze odnajdujący się w kontaktach międzyludzkich."}]},{"id":"wyprawy-trekkingowe-przygotowanie-sprzet","wiki":[{"heading":"Przygotowanie do trekkingu","body":"Najlepiej zacząć od zdobycia wiedzy merytorycznej o miejscu docelowym (inaczej przygotujemy się na trekking po Saharze, a inaczej na Kilimandżaro). Konieczne jest przygotowanie fizyczne i psychiczne organizmu. W początkowych fazach prowadzi się trening kondycyjny (bieganie wytrzymałościowe, marszobiegi, interwały), zaleca się podstawowe badania (morfologia krwi, badanie moczu, EKG serca), a także ćwiczenia siłowe na duże partie mięśniowe (plecy, brzuch, nogi), ćwiczenia oddechowe i rozciągające. Ważna jest odpowiednia dieta (białko, tłuszcze, węglowodany, witaminy i minerały) oraz równowaga wodno-elektrolitowa. Zdrowie psychiczne buduje się przez stawianie sobie celów i rozwój cech wolicjonalnych."},{"heading":"Zasady organizacji","bullets":["analiza dystansu i przewyższenia — oszacowanie czasu potrzebnego na pokonanie szlaku","powiadomienie osoby bliskiej o celu wyprawy i planowanych ścieżkach","dostosowanie ekwipunku do rodzaju wyprawy (inny zimą, inny latem) — dobór obuwia, plecaka, odzieży","weryfikacja zagrożeń na trasie i poza nią oraz wymaganych szczepionek","dostosowanie kijów trekkingowych do wysokości ciała","dwukrotne sprawdzenie prognoz pogody (na tydzień przed i potwierdzenie dzień przed wylotem)","uwzględnienie kondycji, wieku i poziomu zaawansowania uczestników"]},{"heading":"Niezbędny sprzęt","bullets":["wodoodporny plecak ze stelażem o dużej pojemności; kurtka i spodnie z membraną; odzież termiczna szybkoschnąca","bukłak z wodą (z filtrem lub tabletkami uzdatniającymi), termos, karimata, śpiwór dobrany do miejsca","okulary przeciwsłoneczne, kremy z filtrem, latarka zwykła i czołowa, nóż wielofunkcyjny, ciepłe nakrycie głowy","składane, regulowane kije trekkingowe, mapa i kompas, apteczka, lornetka","buty za kostkę z membraną o sztywnej podeszwie (rozchodzone przed wyjazdem), skarpetki trekkingowe","batony energetyczne i żele, namiot, worki na śmieci, ręcznik szybkoschnący"]}],"questions":[{"type":"abcd","q":"Które z poniższych badań zaleca się wykonać przed trekkingiem, aby wykluczyć przeciwwskazania ze strony układu krążenia?","options":["Tylko pomiar wzrostu i wagi","EKG serca","Badanie wzroku","Test sprawności fizycznej Coopera"],"correct":1,"explain":"Zaleca się podstawowe badania: morfologię krwi, badanie moczu oraz EKG serca, by upewnić się, że nie ma przeciwwskazań związanych z niewydolnością układu krążenia."},{"type":"tf","q":"Nowe buty trekkingowe najlepiej założyć po raz pierwszy dopiero na szlaku, bez wcześniejszego rozchodzenia.","correct":false,"explain":"Buty za kostkę należy rozchodzić przed wyjazdem — zakładanie nowych dopiero na szlaku grozi otarciami i kontuzjami."},{"type":"flash","front":"Dlaczego prognozę pogody przed trekkingiem sprawdza się dwukrotnie?","back":"Sprawdza się ją na tydzień poprzedzający i na tydzień planowanego wyjścia, a następnie potwierdza dzień przed wylotem — to dwukrotna weryfikacja zwiększająca bezpieczeństwo."}]},{"id":"zagospodarowanie-kajaki-zeglarstwo-nurkowanie","wiki":[{"heading":"Kajakarstwo","body":"Dla wszystkich typów kluczowa jest dostępność akwenów wodnych i odpowiednie zaplecze. Warunki dla kajakarstwa zmieniają się co sezon, a brak infrastruktury może zniechęcić turystów — ważne, by szlaki zachowały naturalność.","bullets":["dostępność i oznakowanie szlaków wodnych dla bezpieczeństwa","miejsca wodowania i wyciągania kajaków","biwaki i pola namiotowe przy trasach wraz z informacją o nich","wypożyczalnie sprzętu i parkingi; spławność rzeki (odpowiednia głębokość i szerokość)","przykłady: Krutynia, Czarna Hańcza, Dordogne we Francji, Abel Tasman National Park w Nowej Zelandii"]},{"heading":"Żeglarstwo","body":"Wymagania infrastrukturalne dla żeglarstwa są bardzo wysokie i kosztowne.","bullets":["porty i przystanie żeglarskie, serwis techniczny i tankowanie","miejsca do cumowania i slipy; szkoły żeglarskie i kapitanaty portów oraz wypożyczalnie sprzętu","punkty gastronomiczne (rejsy trwają kilka dni) oraz informacje pogodowe","przykłady: Wielkie Jeziora Mazurskie, Cyklady (Santorini, Mykonos), Brytyjskie Wyspy Dziewicze na Karaibach"]},{"heading":"Nurkowanie i planowanie przestrzenne","body":"Nurkowanie wymaga specyficznej infrastruktury. Planując przestrzennie dla środowiska naturalnego, należy unikać konfliktów użytkowania przestrzeni, utrzymywać zgodność z planami zagospodarowania i dążyć do zrównoważonego rozwoju. Wyzwaniami pozostają kwestie ekonomiczne, sezonowość, zagrożenia środowiskowe oraz balans między komercjalizacją a ochroną.","bullets":["bazy nurkowe z wypożyczalniami sprzętu; dostęp do łodzi nurkowych z odpowiednią burtą","zaplecze ratunkowe i dekompresyjne; punkty szkoleniowe i certyfikacyjne (PADI, CMAS)","przykłady: Morze Czerwone (Sharm El Sheikh), Wyspy Kanaryjskie (Lanzarote, Teneryfa), Blue Hole na Malcie"]}],"questions":[{"type":"abcd","q":"Które organizacje wymieniono jako wystawiające certyfikaty w nurkowaniu?","options":["IATA i UNWTO","PADI i CMAS","PZŻ i ISO","FIFA i UEFA"],"correct":1,"explain":"W zagospodarowaniu dla nurkowania wymieniono punkty szkoleniowe i certyfikacyjne PADI oraz CMAS."},{"type":"tf","q":"Wymagania infrastrukturalne dla żeglarstwa są minimalne i tanie.","correct":false,"explain":"Przeciwnie — żeglarstwo wymaga portów, slipów, serwisu, szkół, kapitanatów i gastronomii, więc infrastruktura jest bardzo wysoka i kosztowna."},{"type":"flash","front":"Co decyduje o spławności rzeki dla kajakarstwa?","back":"Odpowiednia głębokość i szerokość rzeki — tak, aby dało się nią płynąć."}]},{"id":"zagospodarowanie-turystyka-rowerowa","wiki":[{"heading":"Potrzebna infrastruktura","bullets":["miejsca postoju rowerów (bezpieczne pozostawienie roweru) oraz wypożyczalnie dostarczające jednolity sprzęt grupom","miejsca obsługi technicznej: serwisy, sklepy z narzędziami, punkty na szlakach (np. do dopompowania kół)","miejsca odpoczynku z właściwym oznakowaniem oraz oznakowane szlaki rowerowe z tabliczkami edukacyjnymi","bazy noclegowe i gastronomiczne przy dłuższych wyprawach","informacje o pogodzie i atrakcjach regionu, ścieżki i wydzielone pasy dla rowerów oraz oświetlenie szlaków na zmrok"]},{"heading":"Ścieżka a szlak; MTB i downhill","body":"Nie każda ścieżka rowerowa to szlak rowerowy i nie każdy szlak to ścieżka — ścieżka to droga przeznaczona dla komunikacji. W przypadku jazdy MTB oraz downhill potrzebne są dodatkowo miejsca wypożyczenia sprzętu, specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe. Przykłady zagospodarowania: Nadwarciański Szlak Rowerowy w Polsce, Cape Epic w RPA, Mai Chau w Wietnamie, Alpe-Adria (Włochy, Austria)."},{"heading":"Rola w zrównoważonym rozwoju","body":"Turystyka rowerowa sprzyja zrównoważonemu rozwojowi — ogranicza negatywny wpływ na środowisko, a tablice przy szlakach podnoszą świadomość ekologiczną i umożliwiają współpracę z lokalnymi społecznościami. Dobrze zaprojektowana infrastruktura podnosi bezpieczeństwo i komfort podróży, promuje walory przestrzeni, zachęca do aktywności fizycznej oraz zwiększa ochronę środowiska."}],"questions":[{"type":"abcd","q":"Co jest potrzebne w turystyce rowerowej obejmującej jazdę MTB oraz downhill, czego zwykle nie wymaga zwykła turystyka rowerowa?","options":["Tylko oznakowane miejsca odpoczynku","Wyłącznie bazy gastronomiczne","Specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe","Jedynie informacje o pogodzie"],"correct":2,"explain":"Dla MTB i downhill potrzebne są dodatkowo miejsca wypożyczenia sprzętu, specjalne trasy z zabezpieczeniami, zabezpieczenie medyczne oraz wyciągi linowe."},{"type":"tf","q":"Każda ścieżka rowerowa jest jednocześnie szlakiem rowerowym.","correct":false,"explain":"Nie każda ścieżka rowerowa to szlak rowerowy i odwrotnie — ścieżka to droga przeznaczona dla komunikacji."},{"type":"flash","front":"W jaki sposób turystyka rowerowa sprzyja zrównoważonemu rozwojowi?","back":"Ogranicza negatywny wpływ na środowisko, tablice przy szlakach podnoszą świadomość ekologiczną, a sama turystyka umożliwia współpracę z lokalnymi społecznościami."}]},{"id":"fotografia-przygodowa-zasady-techniki","wiki":[{"heading":"Czym jest fotografia przygodowa","body":"Fotografia przygodowa skupia się na zdjęciach plenerowych — oszałamiających krajobrazach i zapierających dech sytuacjach — oraz na uchwyceniu sportów ekstremalnych (narciarstwo, wspinaczka górska, kajakarstwo). Kluczowe elementy to dobra kompozycja, świadome użycie światła, wybór odpowiednich ustawień aparatu oraz praktyka i cierpliwość."},{"heading":"Zasady dobrej fotografii","bullets":["zasada trójpodziału — podział kadru na trzy części i umieszczenie elementów na liniach podziału","linie wiodące — prowadzenie wzroku widza ku głównemu obiektowi","ramy — kadrowanie obiektu naturalnymi elementami; zrównoważenie kompozycji","światło naturalne (wschód i zachód słońca) oraz dbałość o kontrast i cień dla głębi i emocji","tryb manualny i kontrola ekspozycji, dobór ISO (unikanie szumu), czasu naświetlania i przysłony (głębia ostrości)"]},{"heading":"Techniki fotografii przygodowej","bullets":["panoramowanie — ruch aparatem do uchwycenia ruchu i dynamiki","długie naświetlanie — efekt rozmycia i zamrażania światła (np. w nocy)","HDR — uchwycenie większego zakresu tonalnego i szczegółów","zamrażanie ruchu — krótki czas naświetlania lub lampa błyskowa","malowanie światłem — kreatywne, artystyczne efekty nocne"]}],"questions":[{"type":"abcd","q":"Na czym polega zasada trójpodziału w fotografii przygodowej?","options":["Na ustawieniu aparatu na trzy różne wartości ISO","Na podziale kadru na trzy równe części i umieszczeniu głównych elementów na liniach podziału","Na wykonaniu trzech zdjęć tego samego ujęcia","Na użyciu trzech źródeł światła jednocześnie"],"correct":1,"explain":"Zasada trójpodziału polega na podziale kadru na trzy równe części (poziomo i pionowo) i umieszczeniu głównych elementów na liniach przecięcia, co daje dynamiczniejszą kompozycję."},{"type":"tf","q":"Technika HDR służy do uchwycenia większego zakresu tonalnego i szczegółów w zdjęciach.","correct":true,"explain":"HDR (High Dynamic Range) pozwala uchwycić szerszy zakres tonalny i więcej szczegółów."},{"type":"flash","front":"Jak ustawienie przysłony wpływa na głębię ostrości?","back":"Szersza przysłona daje mniejszą głębię ostrości, a mniejsza przysłona — większą głębię ostrości."}]}]$awfjson$::jsonb)
  as x(id text, wiki jsonb, questions jsonb)
where t.id = x.id;
